CREATE FUNCTION public.get_tenant_data(p_tenant_slug text) RETURNS TABLE(id uuid, name text, domain text, logo_url text)
    LANGUAGE sql STABLE
    SET search_path TO 'public'
    AS $$
  SELECT id, name, domain, logo_url
  FROM tenants
  WHERE domain = p_tenant_slug
  LIMIT 1;
$$;


