20260217165238	{"-- Establece zona horaria por defecto para la base de datos\r\nalter database postgres\r\nset timezone to 'America/Bogota'","-- (Opcional pero recomendado) \r\n-- Asegura que nuevas conexiones también usen esta zona\r\nalter role authenticated\r\nset timezone to 'America/Bogota'","alter role anon\r\nset timezone to 'America/Bogota'","alter role service_role\r\nset timezone to 'America/Bogota'","--WARNING, ESTE CODIGO DEBE DE IR EN MIGRACIONES MANUALES"}	latam_configuration
20260219004844	{"-- ===============================\r\n-- Tabla: service_users\r\n-- ===============================\r\n\r\n\r\n\r\nCREATE table public.service_users (\r\n  id uuid primary key default gen_random_uuid(),\r\n\r\n  -- Relación con el usuario de Supabase Auth\r\n  auth_user_id uuid not null unique references auth.users(id) on delete cascade,\r\n\r\n  full_name text,\r\n\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now()\r\n\r\n)","COMMENT ON TABLE public.service_users IS 'Version del schema v1'","-- ==========================================\r\n-- Indexes\r\n-- ==========================================\r\n\r\n-- Aunque el UNIQUE ya crea un índice,\r\n-- lo dejamos explícito si quieres claridad arquitectónica\r\n-- (no es estrictamente necesario)\r\n-- create unique index service_users_auth_user_id_idx\r\n--   on public.service_users (auth_user_id);\r\n\r\n\r\n\r\n-- ==========================================\r\n-- GRANTS\r\n-- ==========================================\r\n\r\n\r\n\r\n-- Permiso para role authenticated\r\ngrant select, insert, update, delete\r\non table public.service_users\r\nto authenticated","-- Permiso para el service role\r\ngrant select, insert, update, delete\r\non table public.service_users\r\nto service_role"}	CREATE_table-grant_service_users
20260219004954	{"-- ==========================================\r\n-- Tabla: tenants\r\n-- ==========================================\r\n\r\n\r\n\r\ncreate table public.tenants (\r\n  id uuid primary key default gen_random_uuid(),\r\n\r\n  name text not null,\r\n  domain text not null unique,\r\n  slug text not null unique,\r\n\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now(),\r\n\r\n  -- Reglas estructurales\r\n  constraint tenants_name_length_check check (char_length(name) >= 2),\r\n  constraint tenants_slug_format_check check (slug ~ '^[a-z0-9-]+$')\r\n)","-- ==========================================\r\n-- Comentarios (documentación viva)\r\n-- ==========================================\r\n\r\n-- ==========================================\r\n-- VERSION DE LA TABLA CON SUS INDEX, GRANTS Y POLICIES\r\nCOMMENT ON TABLE public.tenants IS 'Version del schema v1'","-- ==========================================\r\n\r\ncomment on table public.tenants is 'Tenant root entity for multi-tenant isolation. Represents an organization/customer.'","comment on column public.tenants.domain is 'Primary custom domain for the tenant (must be unique).'","comment on column public.tenants.slug is 'URL-safe identifier used for subdomain or routing. Lowercase, alphanumeric and hyphens only.'","-- ==========================================\r\n-- Índices adicionales\r\n-- ==========================================\r\n\r\n-- UNIQUE ya crea índices, pero si planeas búsquedas frecuentes por created_at:\r\ncreate index tenants_created_at_idx on public.tenants (created_at)","-- ==========================================\r\n-- Seguridad estructural (GRANTS)\r\n-- ==========================================\r\n\r\ngrant select on table public.tenants to authenticated","grant all on table public.tenants to service_role"}	CREATE_table-grant_tenants
20260219005033	{"-- ==========================================\r\n-- Tabla: tenant_permissions\r\n-- ==========================================\r\n\r\ncreate table public.tenant_permissions (\r\n  id uuid primary key default gen_random_uuid(),\r\n\r\n  tenant_id uuid not null references public.tenants(id) on delete cascade,\r\n  service_user_id uuid not null references public.service_users(id) on delete cascade,\r\n\r\n  role text not null default 'member' check (role in ('owner','admin','member')),\r\n\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now(),\r\n\r\nconstraint tenant_permissions_unique_pair unique (tenant_id, service_user_id)\r\n)","-- ==========================================\r\n-- Comentarios\r\n-- ==========================================\r\n\r\nCOMMENT ON TABLE public.tenant_permissions IS 'Version del schema v1'","comment on table public.tenant_permissions is 'Maps service_users to tenants with role-based permissions.'","comment on column public.tenant_permissions.role is 'Role of the user inside the tenant context.'","-- ==========================================\r\n-- Índices estratégicos\r\n-- ==========================================\r\n\r\ncreate index tenant_permissions_tenant_id_idx on public.tenant_permissions (tenant_id)","create index tenant_permissions_service_user_id_idx on public.tenant_permissions (service_user_id)","-- ==========================================\r\n-- GRANTS\r\n-- ==========================================\r\n\r\ngrant select on table public.tenant_permissions to authenticated","grant all on table public.tenant_permissions to service_role"}	CREATE_table-grant_tenant-permissions
20260219005106	{"-- ==========================================\r\n-- RLS\r\n-- ==========================================\r\nalter table public.service_users enable row level security","create policy \\"Users can read their own service_user\\"\r\non public.service_users\r\nfor select\r\nto authenticated\r\nusing (auth_user_id = auth.uid())","create policy \\"Users can insert their own service_user\\"\r\non public.service_users\r\nfor insert\r\nto authenticated\r\nwith check (auth_user_id = auth.uid())","create policy \\"Users can update their own service_user\\"\r\non public.service_users\r\nfor update\r\nto authenticated\r\nusing (auth_user_id = auth.uid())\r\nwith check (auth_user_id = auth.uid())","create policy \\"Users can delete their own service_user\\"\r\non public.service_users\r\nfor delete\r\nto authenticated\r\nusing (auth_user_id = auth.uid())"}	CREATE_policies_service-users
20260219005138	{"-- ==========================================\r\n-- RLS\r\n-- ==========================================\r\n\r\nalter table public.tenants enable row level security","-- Nota:\r\n-- Esta tabla normalmente NO debería permitir a usuarios crear tenants libremente.\r\n-- Normalmente esto lo hace el backend con service_role.\r\n-- Aquí asumimos que solo lectura pública es permitida.\r\n\r\n\r\n--Entonces ¿qué está comprobando exactamente el EXISTS? El EXISTS pregunta:\r\n--¿Hay al menos una fila en tenant_permissions\r\n--que:\r\n--pertenezca a este tenant\r\n--y cuyo service_user esté asociado al usuario autenticado?\r\n\r\n\r\ncreate policy \\"Acceso total verificado: JWT + Base de Datos\\"\r\non public.tenants\r\nfor select\r\nto authenticated\r\nusing (\r\n  -- 1. Verificación rápida por JWT (Filtro de primera línea)\r\n  ((auth.jwt() -> 'app_metadata' -> 'tenants') ? slug::text)\r\n  \r\n  AND -- AMBAS deben cumplirse\r\n  \r\n  -- 2. Verificación en tiempo real en la DB (Verdad absoluta)\r\n  exists (\r\n    select 1 \r\n    from public.tenant_permissions tp\r\n    inner join public.service_users su on tp.service_user_id = su.id\r\n    where tp.tenant_id = public.tenants.id\r\n    and su.auth_user_id = auth.uid()\r\n  )\r\n)"}	CREATE_policies_tenants
20260219005203	{"-- ==========================================\r\n-- RLS\r\n-- ==========================================\r\n\r\nalter table public.tenant_permissions enable row level security","-- Usuarios pueden ver sus propias membresías\r\ncreate policy \\"Users can read their tenant memberships\\"\r\non public.tenant_permissions\r\nfor select\r\nto authenticated\r\nusing (\r\n  service_user_id in (\r\n    select id\r\n    from public.service_users\r\n    where auth_user_id = auth.uid()\r\n  )\r\n)","-- Solo el backend (service_role) debería crear/editar permisos"}	CREATE_policies_tenant_permissions
20260219005332	{"create or replace function public.get_tenant_name(p_tenant_slug text)\r\nreturns text\r\nlanguage sql\r\nSET search_path = public\r\nas $$\r\n  select name\r\n  from tenants\r\n  where slug = p_tenant_slug\r\n  limit 1;\r\n$$"}	CREATE_function_get-tenant-name
20260219005408	{"create or replace function public.set_updated_at()\r\nreturns trigger\r\nlanguage plpgsql\r\nset search_path = public\r\nas $$\r\nbegin\r\n  new.updated_at = now();\r\n  return new;\r\nend;\r\n$$"}	CREATE_function_set-updated-at
20260219005532	{"-- Trigger para updated_at (reusas tu misma función)\r\ncreate trigger set_service_users_updated_at\r\nbefore update on public.service_users\r\nfor each row\r\nexecute function public.set_updated_at()","--Trigger updated_at (nombre ajustado a la tabla)\r\ncreate trigger set_tenant_permissions_updated_at\r\nbefore update on public.tenant_permissions\r\nfor each row\r\nexecute function public.set_updated_at()","--Y este es el trigger como tal que lo que hace es hacer la operacion de la funcion por cada fila que se le evidencie el update\r\ncreate trigger set_tenants_updated_at\r\nbefore update on public.tenants\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_triggers_SU_TP_T
20260226024702	{"create or replace function public.get_tenant_domain(p_tenant_slug text)\r\nreturns text\r\nlanguage sql\r\nSET search_path = public\r\nas $$\r\n  select domain\r\n  from tenants\r\n  where domain = p_tenant_slug\r\n  limit 1;\r\n$$"}	CREATE_function_get_tenant_domain
20260304202215	{"-- ==========================================\r\n-- Tabla: tickets\r\n-- ==========================================\r\n\r\ncreate table public.tickets (\r\n  id uuid primary key default gen_random_uuid(),\r\n  \r\n  -- Relación con el tenant (Obligatorio para aislamiento)\r\n  tenant_id uuid not null references public.tenants(id) on delete cascade,\r\n  \r\n  -- Autor del ticket (Relacionado con tu tabla de perfiles públicos)\r\n  created_by uuid not null references public.service_users(id),\r\n  \r\n  -- Datos del ticket\r\n  title text not null check (char_length(title) > 0),\r\n  description text,\r\n  status text not null default 'open' check (status in ('open', 'in_progress', 'done', 'cancelled', 'information_missing')),\r\n  \r\n  -- Auditoría\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now()\r\n)","-- ==========================================\r\n-- Comentarios (Schema v1)\r\n-- ==========================================\r\n\r\ncomment on table public.tickets is 'Versión del schema v1. Almacena los tickets de soporte por tenant.'","comment on column public.tickets.status is 'Estado actual del ticket: open, in_progress, done, cancelled.'","comment on column public.tickets.tenant_id is 'ID del tenant al que pertenece el ticket para aislamiento multi-tenant.'","-- ==========================================\r\n-- Índices estratégicos\r\n-- ==========================================\r\n\r\n-- Índice para búsquedas rápidas por tenant (vital para el rendimiento)\r\ncreate index tickets_tenant_id_idx on public.tickets (tenant_id)","-- Índice para filtrar por creador\r\ncreate index tickets_created_by_idx on public.tickets (created_by)","-- Índice para filtros de estado\r\ncreate index tickets_status_idx on public.tickets (status)","-- ==========================================\r\n-- GRANTS\r\n-- ==========================================\r\n\r\ngrant select, insert, update on table public.tickets to authenticated","grant all on table public.tickets to service_role","-- ==========================================\r\n-- RLS (Row Level Security)\r\n-- ==========================================\r\n\r\nalter table public.tickets enable row level security","-- POLÍTICA: Los usuarios solo pueden ver tickets de los tenants a los que pertenecen\r\ncreate policy \\"Users can see tickets from their tenants\\"\r\non public.tickets\r\nfor select\r\nto authenticated\r\nusing (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)","-- POLÍTICA: Los usuarios pueden crear tickets en los tenants donde son miembros\r\ncreate policy \\"Users can create tickets in their tenants\\"\r\non public.tickets\r\nfor insert\r\nto authenticated\r\nwith check (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)","/* Esto hace lo mismo que el check de arriba\r\nwith check (\r\n  exists (\r\n    select 1 \r\n    from public.tenant_permissions tp\r\n    join public.service_users su on tp.service_user_id = su.id\r\n    where tp.tenant_id = public.tickets.tenant_id -- Vinculamos el ticket con el permiso\r\n    and su.auth_user_id = auth.uid()             -- Vinculamos el permiso con el usuario\r\n  )\r\n);\r\n*/\r\n\r\n\r\n-- POLÍTICA: Solo el autor (o un admin) puede actualizar el ticket\r\n-- (Aquí puedes simplificarlo o hacerlo más complejo según tus roles)\r\ncreate policy \\"Authors can update their own tickets\\"\r\non public.tickets\r\nfor update\r\nto authenticated\r\nusing (\r\n  created_by in (\r\n    select id from public.service_users where auth_user_id = auth.uid()\r\n  )\r\n)\r\nwith check (\r\n  created_by in (\r\n    select id from public.service_users where auth_user_id = auth.uid()\r\n  )\r\n)"}	CREATE_table-grant-policies_tickets
20260304202343	{"create trigger set_tickets_updated_at\r\nbefore update on public.tickets\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_updated-date_tickets
20260305153709	{"create or replace function public.set_created_by_table_tickets()\r\nreturns trigger\r\nlanguage plpgsql\r\nset search_path = public\r\nas $$\r\nbegin\r\n  -- Buscamos al usuario interno basándonos en la sesión de Supabase\r\n  -- Aqui lo que se esta diciendo es seleccionar el id que resulta del from e \r\n  -- inyectarlo en el field created_by que es a donde esta dirigida la info que atrapa el trigger\r\n  SELECT id INTO NEW.created_by\r\n  FROM public.service_users\r\n  WHERE auth_user_id = auth.uid();\r\n  -- Opcional: Si el usuario no existe en service_users, bloqueamos el insert\r\n  IF NEW.created_by IS NULL THEN\r\n    RAISE EXCEPTION 'No se encontró un perfil de servicio para el usuario actual.';\r\n  END IF;\r\n  RETURN NEW;\r\nend;\r\n$$"}	CREATE_function_set-created-by_table_tickets
20260305153758	{"CREATE TRIGGER tr_set_author\r\nBEFORE INSERT ON public.tickets\r\nFOR EACH ROW EXECUTE FUNCTION public.set_created_by_table_tickets()"}	CREATE_trigger_set-created-by_table_tickets
20260305175343	{"-- 1. Agregar la columna como NOT NULL desde el inicio\r\n-- (Al estar vacía la tabla, no habrá conflictos)\r\nALTER TABLE public.tickets \r\nADD COLUMN ticket_number bigint NOT NULL","-- 2. Crear la restricción de unicidad compuesta\r\n-- Garantiza que cada tenant tenga su propia secuencia (1, 2, 3...)\r\nALTER TABLE public.tickets \r\nADD CONSTRAINT unique_ticket_number_per_tenant \r\nUNIQUE (tenant_id, ticket_number)","-- 3. Crear el índice para búsquedas rápidas (ej: /tenant/tickets/1)\r\nCREATE INDEX tickets_ticket_number_idx ON public.tickets (ticket_number)","-- 4. Comentario para la base de datos\r\nCOMMENT ON COLUMN public.tickets.ticket_number IS 'Número secuencial humano (1, 2, 3...) por cada tenant.'"}	ALTER_table_tickets_add_column_ticketNumber
20260305182313	{"-- 1. La lógica del Trigger\r\nCREATE OR REPLACE FUNCTION public.set_next_ticket_number()\r\nRETURNS TRIGGER AS $$\r\nBEGIN\r\n    SELECT COALESCE(MAX(ticket_number), 0) + 1 \r\n    INTO NEW.ticket_number\r\n    FROM public.tickets\r\n    WHERE tenant_id = NEW.tenant_id;\r\n    RETURN NEW;\r\nEND;\r\n$$ LANGUAGE plpgsql"}	CREATE_function_set-next-ticket-number
20260305183316	{"CREATE TRIGGER tr_set_ticket_number\r\nBEFORE INSERT ON public.tickets\r\nFOR EACH ROW\r\nEXECUTE FUNCTION public.set_next_ticket_number()"}	CREATE_trigger_set-ticket-number_table_tickets
20260306010838	{"DROP POLICY \\"Users can read their own service_user\\" ON public.service_users"}	DROP_policy_table_service-users
20260306010914	{"create policy \\"Users can read service_users from their same tenants\\"\r\non public.service_users\r\nfor select\r\nto authenticated\r\nusing (\r\n  id in (\r\n    select service_user_id \r\n    from public.tenant_permissions\r\n    where tenant_id in (\r\n      select tenant_id \r\n      from public.tenant_permissions\r\n      where service_user_id = (select id from public.service_users where auth_user_id = auth.uid())\r\n    )\r\n  )\r\n)"}	CREATE_policy_table_service-users
