20260306011954	{"create policy \\"Users can read service_users from their same tenants\\"\r\non public.service_users\r\nfor select\r\nto authenticated\r\nusing (\r\n  auth_user_id = auth.uid()\r\n  OR\r\n  id in (\r\n    select service_user_id \r\n    from public.tenant_permissions\r\n    where tenant_id in (\r\n      select tenant_id \r\n      from public.tenant_permissions\r\n      where service_user_id = (select id from public.service_users where auth_user_id = auth.uid())\r\n    )\r\n  )\r\n)"}	CREATE_policy_table_service-users-improved
20260306014103	{"DROP POLICY \\"Users can read service_users from their same tenants\\" ON public.service_users"}	DROP_policy_table_service-users
20260306014200	{"create policy \\"Users can read their own service_user\\"\r\non public.service_users\r\nfor select\r\nto authenticated\r\nusing (auth_user_id = auth.uid())"}	CREATE_policy_table_service-users-oldone
20260308202308	{"-- ==========================================================\r\n-- Migración: Agregar política de borrado para tickets\r\n-- ==========================================================\r\n\r\n-- 2. Creamos la política definitiva\r\ncreate policy \\"Users can delete own tickets\\"\r\non public.tickets\r\nfor delete\r\nto authenticated\r\nusing (\r\n  exists (\r\n    select 1 \r\n    from public.service_users su\r\n    join public.tenant_permissions tp on tp.service_user_id = su.id\r\n    where su.auth_user_id = auth.uid()\r\n    and public.tickets.created_by = su.id\r\n    and public.tickets.tenant_id = tp.tenant_id\r\n  )\r\n)"}	CREATE_policy_table_tickets_deletePolicy
20260308205528	{"-- ==========================================================\r\n-- ==========================================================\r\n-- Migración: Actualizar tabla service_users\r\n-- ==========================================================\r\n\r\n-- 1. Agregar columnas nuevas\r\nALTER TABLE public.service_users \r\nADD COLUMN IF NOT EXISTS is_available BOOLEAN NOT NULL DEFAULT TRUE,\r\nADD COLUMN IF NOT EXISTS job_title TEXT","-- 2. Agregar comentarios\r\nCOMMENT ON COLUMN public.service_users.is_available IS 'Indica si el usuario está disponible (vacaciones, enfermedad, etc.)'","COMMENT ON COLUMN public.service_users.job_title IS 'Título profesional o cargo del usuario dentro del equipo'","-- 3. Crear índices para rendimiento\r\n-- Índice para búsqueda de disponibilidad\r\nCREATE INDEX IF NOT EXISTS service_users_is_available_idx ON public.service_users (is_available)","-- 4. Preparar búsqueda por texto (Búsqueda de nombre)\r\n-- Habilitar extensión para coincidencias parciales (trigramas)\r\nCREATE EXTENSION IF NOT EXISTS pg_trgm","-- Índice GIN para búsquedas eficientes en full_name\r\nCREATE INDEX IF NOT EXISTS service_users_full_name_trgm_idx \r\nON public.service_users USING gin (full_name gin_trgm_ops)"}	ALTER_table_service-users_add_is-avaliable-job-title_column
20260308222544	{"create or replace function public.get_service_users_with_tenant(target_tenant_id uuid)\r\nreturns setof public.service_users\r\nSET search_path = public\r\nlanguage plpgsql\r\nsecurity definer -- Importante: la función se ejecuta con privilegios de la DB, no del usuario directo\r\nas $$\r\nbegin\r\n  -- 1. Comprobamos si el usuario que llama a la función tiene permisos en ese tenant\r\n  if not exists (\r\n    select 1\r\n    from public.tenant_permissions tp\r\n    join public.service_users su on tp.service_user_id = su.id\r\n    where tp.tenant_id = target_tenant_id\r\n    and su.auth_user_id = auth.uid()\r\n  ) then\r\n    raise exception 'Acceso denegado: no perteneces a este tenant.';\r\n  end if;\r\n\r\n  -- 2. Si pasó la comprobación, devolvemos los usuarios\r\n  return query\r\n  select su.*\r\n  from public.service_users su\r\n  join public.tenant_permissions tp on su.id = tp.service_user_id\r\n  where tp.tenant_id = target_tenant_id;\r\nend;\r\n$$"}	CREATE_function_get_service_users_with_tenant
20260308234433	{"-- ==========================================================\r\n-- Migración: Agregar campos de asignación a tickets\r\n-- ==========================================================\r\n\r\n-- 1. Agregar las columnas si no existen\r\nALTER TABLE public.tickets \r\nADD COLUMN IF NOT EXISTS assignee uuid REFERENCES public.service_users(id) ON DELETE SET NULL,\r\nADD COLUMN IF NOT EXISTS assignee_name text","-- 2. Crear índice para el asignado (Optimización de consultas)\r\n-- Es muy común filtrar tickets por \\"quién tiene asignado este ticket\\"\r\nCREATE INDEX IF NOT EXISTS tickets_assignee_idx ON public.tickets (assignee)","-- 3. Comentarios para documentar los nuevos campos\r\nCOMMENT ON COLUMN public.tickets.assignee IS 'ID del usuario asignado al ticket (relacionado con service_users).'","COMMENT ON COLUMN public.tickets.assignee_name IS 'Nombre del usuario asignado (campo informativo para evitar joins constantes).'"}	ALTER_table_tickets_add-columns_assignee_asigneename
20260309153832	{"create or replace function public.set_ticket_assignee_name()\r\nreturns trigger\r\nlanguage plpgsql\r\nSECURITY DEFINER\r\nset search_path = public\r\nas $$\r\nbegin\r\n-- 1. Si no hay asignado, limpiamos el nombre\r\n    IF (NEW.assignee IS NULL) THEN\r\n        NEW.assignee_name := NULL;\r\n        \r\n        -- 2. Si hay un asignado, intentamos buscar su nombre validando que pertenezca al tenant\r\n    ELSE NEW.assignee_name = (\r\n        SELECT full_name FROM service_users WHERE id = NEW.assignee AND EXISTS (\r\n            SELECT 1 FROM tenant_permissions p WHERE\r\n            p.tenant_id = NEW.tenant_id AND p.service_user_id=NEW.assignee\r\n        )\r\n    );\r\n\r\n-- 3. Si no encontramos un usuario válido para ese tenant, invalidamos la asignación\r\n    IF (NEW.assignee_name IS NULL) THEN\r\n    NEW.assignee := NULL;\r\n    END IF;\r\n\r\n    END IF;\r\n    RETURN NEW;\r\nend;\r\n$$"}	CREATE_function_set_ticket_assignee_name
20260309154152	{"-- Asegurar que el trigger no se duplique\r\n\r\n-- Crear el trigger\r\nCREATE TRIGGER trg_set_ticket_assignee_name\r\nBEFORE INSERT OR UPDATE OF assignee ON public.tickets\r\nFOR EACH ROW\r\nEXECUTE FUNCTION public.set_ticket_assignee_name()"}	CREATE_trigger_set_ticket_assignee_name
20260310015821	{"-- ==========================================\r\n-- Tabla: comments\r\n-- ==========================================\r\n\r\ncreate table public.comments (\r\n  id uuid primary key default gen_random_uuid(),\r\n  \r\n  -- Relaciones\r\n  ticket_id uuid not null references public.tickets(id) on delete cascade,\r\n  tenant_id uuid not null references public.tenants(id) on delete cascade,\r\n  created_by uuid not null references public.service_users(id),\r\n  \r\n  -- Datos del comentario\r\n  comment_text text not null check (char_length(comment_text) > 0),\r\n  \r\n  -- Caché del autor (Desnormalización para evitar JOINs constantes en el front)\r\n  author_name text not null,\r\n  \r\n  -- Auditoría\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now()\r\n)","-- ==========================================\r\n-- Índices para rendimiento (crucial para RLS y carga de listas)\r\n-- ==========================================\r\n\r\n-- Índice para filtrar comentarios por ticket (la consulta principal: \\"ver comentarios del ticket X\\")\r\ncreate index comments_ticket_id_idx on public.comments (ticket_id)","-- Índice para el RLS (búsquedas por tenant)\r\ncreate index comments_tenant_id_idx on public.comments (tenant_id)","-- ==========================================\r\n-- GRANTS\r\n-- ==========================================\r\n\r\ngrant select, insert, update on table public.comments to authenticated","grant all on table public.comments to service_role"}	CREATE_table_comments
20260310020351	{"-- ==========================================\r\n-- RLS (Row Level Security)\r\n-- ==========================================\r\n\r\nalter table public.comments enable row level security","-- POLÍTICA: Solo los miembros del tenant pueden ver los comentarios\r\ncreate policy \\"Users can see comments from their tenants\\"\r\non public.comments\r\nfor select\r\nto authenticated\r\nusing (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)","-- POLÍTICA: Solo miembros del tenant pueden insertar comentarios en tickets de ese tenant\r\ncreate policy \\"Users can insert comments in their tenants\\"\r\non public.comments\r\nfor insert\r\nto authenticated\r\nwith check (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)"}	CREATE_policy_table_comments
20260310024207	{"-- 1. Función específica para comentarios\r\ncreate or replace function public.set_comment_author_name()\r\nreturns trigger\r\nlanguage plpgsql\r\nSECURITY DEFINER\r\nset search_path = public\r\nas $$\r\nbegin\r\n\r\n    -- Como created_by es NOT NULL, siempre tendrá un valor.\r\n    -- Pero si quieres una validación de seguridad extra:\r\n    IF (NEW.created_by IS NULL) THEN\r\n        RAISE EXCEPTION 'Un comentario debe tener un autor.';\r\n    END IF;\r\n\r\n\r\n    -- Buscamos el nombre del usuario basado en su ID (created_by)\r\n    -- No necesitamos validar el tenant aquí, porque ya lo haces en el RLS\r\n    SELECT full_name \r\n    INTO NEW.author_name\r\n    FROM public.service_users \r\n    WHERE id = NEW.created_by;\r\n    \r\n    -- Si por alguna razón el usuario no existe, lanzamos un error o ponemos 'Unknown'\r\n    IF NOT FOUND THEN\r\n        NEW.author_name := 'Usuario desconocido';\r\n    END IF;\r\n\r\n    RETURN NEW;\r\nend;\r\n$$"}	CREATE_function_set_comment_author_name
20260310024302	{"CREATE TRIGGER trg_comments_autoset_author_name\r\nBEFORE INSERT ON public.comments\r\nFOR EACH ROW\r\nEXECUTE FUNCTION public.set_comment_author_name()"}	CREATE_trigger_trg_comments_autoset_author_name
20260310031603	{"create trigger set_comments_updated_at\r\nbefore update on public.comments\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_trg_comments_autoset_author_name2
20260310032848	{"create or replace function public.set_created_by_value()\r\nreturns trigger\r\nlanguage plpgsql\r\nSECURITY DEFINER\r\nset search_path = public\r\nas $$\r\nbegin\r\n  -- Buscamos el ID en service_users que coincide con el auth.uid() de la sesión\r\n  SELECT id INTO NEW.created_by\r\n  FROM public.service_users\r\n  WHERE auth_user_id = auth.uid();\r\n\r\n  -- Si no encontramos el usuario, abortamos la inserción\r\n  IF NOT FOUND THEN\r\n    RAISE EXCEPTION 'No se pudo vincular el usuario actual con un registro en service_users';\r\n  END IF;\r\n\r\n  RETURN NEW;\r\nend;\r\n$$"}	CREATE_function_set_created_by_value-table_comments
20260310032951	{"CREATE TRIGGER tr_comments_autoset_created_by\r\nBEFORE INSERT ON public.comments\r\nFOR EACH ROW\r\nEXECUTE FUNCTION public.set_created_by_value()"}	CREATE_trigger_tr_comments_autoset_created_by-table_comments
20260310155226	{"create or replace function public.derive_tenant_from_ticket()\r\nreturns trigger\r\nlanguage plpgsql\r\nsecurity definer -- Usamos security definer para asegurar acceso a la tabla tickets\r\nset search_path = public\r\nas $$\r\nBEGIN\r\n    -- Obtenemos el tenant_id del ticket relacionado\r\n    NEW.tenant_id := (\r\n        SELECT t.tenant_id \r\n        FROM public.tickets t \r\n        WHERE t.id = NEW.ticket_id\r\n    );\r\n\r\n    -- Validación de seguridad\r\n    IF NEW.tenant_id IS NULL THEN\r\n        RAISE EXCEPTION 'No se pudo encontrar el ticket relacionado o el ticket no tiene un tenant asignado.';\r\n    END IF;\r\n\r\n    RETURN NEW;\r\nEND;\r\n$$"}	CREATE_function_derive_tenant_from_ticket
20260310155316	{"CREATE TRIGGER tr_comments_derive_tenant\r\nBEFORE INSERT ON public.comments\r\nFOR EACH ROW\r\nEXECUTE FUNCTION public.derive_tenant_from_ticket()"}	CREATE_trigger_tr_comments_derive_tenant
20260310185233	{"-- 1. Asegúrate de que la tabla esté en la publicación de realtime\r\n-- Si ya existe la publicación, simplemente añade la tabla\r\nALTER PUBLICATION supabase_realtime ADD TABLE public.comments","-- 2. (Opcional) Si quieres escuchar solo eventos específicos (INSERT, UPDATE, DELETE)\r\n-- Por defecto añade todos, pero puedes ser selectivo:\r\n-- ALTER PUBLICATION supabase_realtime SET TABLE public.comments"}	CREATE_realTime_table_comments
20260311164739	{"INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\r\nVALUES (\r\n  'tickets-attachments', \r\n  'tickets-attachments', \r\n  false, \r\n  5242880, -- Límite de 5MB en bytes\r\n  ARRAY['image/jpeg', 'image/png', 'application/pdf'] -- Tipos permitidos\r\n)\r\nON CONFLICT (id) DO UPDATE \r\nSET \r\n  file_size_limit = EXCLUDED.file_size_limit,\r\n  allowed_mime_types = EXCLUDED.allowed_mime_types","-- 2. Crear política para permitir que usuarios autenticados suban archivos\r\ncreate policy \\"Authenticated users can upload files\\"\r\non storage.objects\r\nfor insert\r\nto authenticated\r\nwith check (\r\n  bucket_id = 'tickets-attachments'\r\n  and (auth.uid() is not null) -- Validación básica\r\n)","-- 3. Crear política para que solo el propietario pueda leer su archivo\r\ncreate policy \\"Users can read their own files\\"\r\non storage.objects\r\nfor select\r\nto authenticated\r\nusing (\r\n  bucket_id = 'tickets-attachments'\r\n  and auth.uid() = owner\r\n)"}	CREATE_bucket_tickets-attachemnts_with_RLS
20260311174953	\N	CREATE_policy_bucket_tickets-attachments
20260311175023	{"CREATE POLICY \\"Aislar_tenants_en_storage\\"\r\nON storage.objects\r\nFOR ALL -- Aplica para SELECT, INSERT, UPDATE y DELETE\r\nTO authenticated\r\nUSING (\r\n  bucket_id = 'tickets-attachments'\r\n  AND (storage.foldername(name))[1]::uuid IN (\r\n    SELECT tp.tenant_id \r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE su.auth_user_id = auth.uid()\r\n  )\r\n)\r\nWITH CHECK (\r\n  bucket_id = 'tickets-attachments'\r\n  AND (storage.foldername(name))[1]::uuid IN (\r\n    SELECT tp.tenant_id \r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE su.auth_user_id = auth.uid()\r\n  )\r\n)"}	CREATE_policy_bucket_tickets-attachments2
20260414202255	{"CREATE TABLE IF NOT EXISTS public.order_signatures (\r\n    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    tenant_id               UUID NOT NULL,\r\n    entry_order_id          UUID NOT NULL,\r\n    -- Referencia a qué rol de firma de la plantilla corresponde\r\n    template_signature_id   UUID NOT NULL,\r\n    \r\n    -- El nombre de quien firmó (Snapshot por si el cliente cambia)\r\n    signer_name             TEXT NOT NULL,\r\n    -- URL del archivo en Supabase Storage\r\n    signature_url           TEXT NOT NULL,\r\n\r\n    \r\n    created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n\r\n    CONSTRAINT os_tenant_fkey FOREIGN KEY (tenant_id) REFERENCES public.tenants(id),\r\n    CONSTRAINT os_order_fkey FOREIGN KEY (entry_order_id) REFERENCES public.entry_orders(id) ON DELETE CASCADE\r\n)"}	CREATE_table_order_signatures
20260311180156	{"-- 2. Eliminamos políticas viejas por si acaso (para evitar conflictos tras un reset)\r\nDROP POLICY IF EXISTS \\"Authenticated users can upload files\\" ON storage.objects","DROP POLICY IF EXISTS \\"Users can read their own files\\" ON storage.objects","DROP POLICY IF EXISTS \\"Aislar_tenants_en_storage\\" ON storage.objects","-- 3. Creamos la ÚNICA política maestra\r\nCREATE POLICY \\"Aislar_tenants_en_storage\\"\r\nON storage.objects\r\nFOR ALL\r\nTO authenticated\r\nUSING (\r\n  bucket_id = 'tickets-attachments'\r\n  AND (storage.foldername(name))[1]::uuid IN (\r\n    SELECT tp.tenant_id \r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE su.auth_user_id = auth.uid()\r\n  )\r\n)\r\nWITH CHECK (\r\n  bucket_id = 'tickets-attachments'\r\n  AND (storage.foldername(name))[1]::uuid IN (\r\n    SELECT tp.tenant_id \r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE su.auth_user_id = auth.uid()\r\n  )\r\n)"}	CREATE_policy_bucket_tickets-attachments3
20260312164227	{"-- 1. Asegurarnos de que el bucket existe (usamos ON CONFLICT para que no falle si ya existe)\r\nINSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\r\nVALUES (\r\n  'comments-attachments', \r\n  'comments-attachments', \r\n  false, \r\n  5242880, -- Límite de 5MB en bytes\r\n  ARRAY['image/jpeg', 'image/png', 'application/pdf'] -- Tipos permitidos\r\n)\r\nON CONFLICT (id) DO UPDATE \r\nSET \r\n  file_size_limit = EXCLUDED.file_size_limit,\r\n  allowed_mime_types = EXCLUDED.allowed_mime_types"}	CREATE_bucket_comments_attachments
20260312165507	{"-- 3. Creamos la ÚNICA política maestra\r\nCREATE POLICY \\"Aislar_comments_en_storage\\"\r\nON storage.objects\r\nFOR ALL\r\nTO authenticated\r\nUSING (\r\n  bucket_id = 'comments-attachments'\r\n  AND (storage.foldername(name))[1]::uuid IN (\r\n    SELECT tp.tenant_id \r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE su.auth_user_id = auth.uid()\r\n  )\r\n)\r\nWITH CHECK (\r\n  bucket_id = 'comments-attachments'\r\n  AND (storage.foldername(name))[1]::uuid IN (\r\n    SELECT tp.tenant_id \r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE su.auth_user_id = auth.uid()\r\n  )\r\n)"}	CREATE_policy_bucket_comments-attachmments
20260312200310	{"create table public.comment_attachments (\r\n  id uuid primary key default gen_random_uuid(),\r\n  \r\n  -- Relaciones\r\n  comment_id uuid not null references public.comments(id) on delete cascade,\r\n  tenant_id uuid not null references public.tenants(id) on delete cascade,\r\n  \r\n  -- Datos\r\n  file_path text not null,\r\n  \r\n  -- Auditoría\r\n  created_at timestamptz not null default now(),\r\n  updated_at timestamptz not null default now()\r\n)","-- IMPORTANTÍSIMO: Índice para velocidad\r\ncreate index comment_attachments_tenant_id_idx on public.comment_attachments (tenant_id)","create index comment_attachments_comment_id_idx on public.comment_attachments (comment_id)","-- ==========================================\r\n-- Comentarios (Schema v1)\r\n-- ==========================================\r\n\r\ncomment on table public.comment_attachments is 'Ultima actualizacion del schema: Marzo 12 2026'","comment on column public.comment_attachments.tenant_id is 'ID del tenant al que pertenece el ticket para aislamiento multi-tenant.'","-- ==========================================\r\n-- GRANTS\r\n-- ==========================================\r\n\r\ngrant select, insert, update on table comment_attachments to authenticated","grant all on table comment_attachments to service_role"}	CREATE_table_comment-attachments
20260312200544	{"create trigger tr_set_comments_attachments_updated_at\r\nbefore update on public.comment_attachments\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_tr-set-comments-attachments-updated-at
20260312200809	{"-- ==========================================\r\n-- RLS (Row Level Security)\r\n-- ==========================================\r\n\r\nalter table public.comment_attachments enable row level security","-- Política: Solo miembros del tenant pueden ver sus archivos adjuntos\r\ncreate policy \\"Users can see attachments from their tenants\\"\r\non public.comment_attachments\r\nfor select\r\nto authenticated\r\nusing (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)"}	CREATE_policy_table_comment_attachments
20260312221047	{"-- POLÍTICA: Solo miembros que tengan su tenant puede borrar comentarios\r\ncreate policy \\"Users can delete comments from their tenats\\"\r\non public.comments\r\nfor delete\r\nto authenticated\r\nusing (\r\n\r\n  created_by = (\r\n    select id from public.service_users where auth_user_id = auth.uid()\r\n  )\r\n\r\n  OR\r\n\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)"}	CREATE_policy_table_comments_rlsDelete
