20260316184743	{"CREATE OR REPLACE FUNCTION public.get_tenant_data(p_tenant_slug text)\r\nRETURNS TABLE (\r\n  id uuid,\r\n  name text,\r\n  domain text\r\n) \r\nLANGUAGE sql\r\nSTABLE\r\nSET search_path = public\r\nAS $$\r\n  SELECT id, name, domain\r\n  FROM tenants\r\n  WHERE domain = p_tenant_slug\r\n  LIMIT 1;\r\n$$"}	CREATE_function_get_tenant_data
