20260402190303	{"-- 1. Eliminar la restricción actual\r\n-- El nombre por defecto que Postgres suele dar es 'tenant_permissions_role_check'\r\n-- Si le pusiste un nombre manual, usa ese.\r\nALTER TABLE public.tenant_permissions \r\nDROP CONSTRAINT IF EXISTS tenant_permissions_role_check","-- 2. (Opcional) Mapear los roles viejos a los nuevos si ya tienes datos\r\n-- Por ejemplo: 'owner' pasa a ser 'gerente', 'member' a 'directortecnico', etc.\r\nUPDATE public.tenant_permissions SET role = 'gerente' WHERE role = 'owner'","UPDATE public.tenant_permissions SET role = 'director_tecnico' WHERE role = 'admin'","UPDATE public.tenant_permissions SET role = 'recepcionista' WHERE role = 'member'","-- 3. Cambiar el valor por defecto de la columna (antes era 'member')\r\nALTER TABLE public.tenant_permissions \r\nALTER COLUMN role SET DEFAULT 'recepcionista'","-- 4. Añadir la nueva restricción con tus 4 roles\r\nALTER TABLE public.tenant_permissions \r\nADD CONSTRAINT tenant_permissions_role_check \r\nCHECK (role IN ('gerente', 'recepcionista', 'aux_administrativo', 'director_tecnico'))"}	ALTER_table_tenant_permissions
20260316203117	{"-- ==========================================\r\n-- Tabla: tickets (PARTICIONADA)\r\n-- ==========================================\r\n\r\nCREATE TABLE public.tickets (\r\n  id uuid NOT NULL DEFAULT gen_random_uuid(),\r\n\r\n  -- Identificador humano secuencial por tenant\r\n  ticket_number bigint NOT NULL, \r\n  \r\n  -- Relación con el tenant (Obligatorio para aislamiento y particionamiento)\r\n  tenant_id uuid NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE,\r\n  \r\n  -- Autor del ticket (Relacionado con tu tabla de perfiles públicos)\r\n  created_by uuid NOT NULL REFERENCES public.service_users(id),\r\n  assignee uuid REFERENCES public.service_users(id) ON DELETE SET NULL,\r\n  \r\n  -- Datos del ticket\r\n  title text NOT NULL CHECK (char_length(title) > 0),\r\n  description text,\r\n  status text NOT NULL DEFAULT 'open' CHECK (status IN ('open', 'in_progress', 'done', 'cancelled', 'information_missing')),\r\n  assignee_name text,\r\n  \r\n  -- Auditoría\r\n  created_at timestamptz NOT NULL DEFAULT now(),\r\n  updated_at timestamptz NOT NULL DEFAULT now(),\r\n\r\n  -- CONSTRAINT DE UNICIDAD Y PK: \r\n  -- En tablas particionadas, la columna de partición DEBE estar en la PK\r\n  PRIMARY KEY (id, tenant_id),\r\n  -- CONSTRAINT DE UNICIDAD: Evita duplicados de número dentro del mismo cliente\r\n  CONSTRAINT unique_ticket_number_per_tenant UNIQUE (tenant_id, ticket_number)\r\n) PARTITION BY LIST (tenant_id)","-- \r\n\r\n-- ==========================================\r\n-- Comentarios\r\n-- ==========================================\r\n\r\nCOMMENT ON TABLE public.tickets IS 'Esta es la v2, particionada por tenant_id'","COMMENT ON COLUMN public.tickets.status IS 'Estado actual del ticket: open, in_progress, done, cancelled.'","COMMENT ON COLUMN public.tickets.tenant_id IS 'ID del tenant al que pertenece el ticket para aislamiento multi-tenant.'","-- ==========================================\r\n-- Índices estratégicos\r\n-- ==========================================\r\n\r\n-- Nota: En tablas particionadas, estos índices se propagan automáticamente a las particiones hijas\r\n-- Índice para búsquedas rápidas por tenant (vital para el rendimiento)\r\nCREATE INDEX tickets_tenant_id_idx ON public.tickets (tenant_id)","-- Índice para filtrar por creador\r\nCREATE INDEX tickets_created_by_idx ON public.tickets (created_by)","-- Índice para filtros de estado\r\nCREATE INDEX tickets_status_idx ON public.tickets (status)","-- Indice para los filtros por assignee\r\nCREATE INDEX tickets_assignee_idx ON public.tickets (assignee)","-- Búsqueda ultra rápida por número (usado en URLs: /tenant/tickets/42)\r\nCREATE INDEX tickets_tenant_ticket_num_idx ON public.tickets (tenant_id, ticket_number)","-- ==========================================\r\n-- GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE ON TABLE public.tickets TO authenticated","GRANT ALL ON TABLE public.tickets TO service_role","ALTER TABLE public.comments \r\nADD CONSTRAINT fk_comments_to_tickets \r\nFOREIGN KEY (ticket_id, tenant_id) REFERENCES public.tickets (id, tenant_id) ON DELETE CASCADE"}	CREATE_table_tickets_with_partition
20260316204143	{"alter table public.tickets enable row level security","-- POLÍTICA: Los usuarios solo pueden ver tickets de los tenants a los que pertenecen\r\ncreate policy \\"Users can see tickets from their tenants\\"\r\non public.tickets\r\nfor select\r\nto authenticated\r\nusing (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)","-- POLÍTICA: Los usuarios pueden crear tickets en los tenants donde son miembros\r\ncreate policy \\"Users can create tickets in their tenants\\"\r\non public.tickets\r\nfor insert\r\nto authenticated\r\nwith check (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = auth.uid()\r\n    )\r\n  )\r\n)","/* Esto hace lo mismo que el check de arriba\r\nwith check (\r\n  exists (\r\n    select 1 \r\n    from public.tenant_permissions tp\r\n    join public.service_users su on tp.service_user_id = su.id\r\n    where tp.tenant_id = public.tickets.tenant_id -- Vinculamos el ticket con el permiso\r\n    and su.auth_user_id = auth.uid()             -- Vinculamos el permiso con el usuario\r\n  )\r\n);\r\n*/\r\n\r\n\r\n-- POLÍTICA: Solo el autor (o un admin) puede actualizar el ticket\r\n-- (Aquí puedes simplificarlo o hacerlo más complejo según tus roles)\r\ncreate policy \\"Authors can update their own tickets\\"\r\non public.tickets\r\nfor update\r\nto authenticated\r\nusing (\r\n  created_by in (\r\n    select id from public.service_users where auth_user_id = auth.uid()\r\n  )\r\n)\r\nwith check (\r\n  created_by in (\r\n    select id from public.service_users where auth_user_id = auth.uid()\r\n  )\r\n)","create policy \\"Users can delete own tickets\\"\r\non public.tickets\r\nfor delete\r\nto authenticated\r\nusing (\r\n  exists (\r\n    select 1 \r\n    from public.service_users su\r\n    join public.tenant_permissions tp on tp.service_user_id = su.id\r\n    where su.auth_user_id = auth.uid()\r\n    and public.tickets.created_by = su.id\r\n    and public.tickets.tenant_id = tp.tenant_id\r\n  )\r\n)"}	CREATE_policies_table_tickets_with_partitions
