20260318183946	{"-- 1. Eliminamos la función anterior para evitar conflictos de firmas\r\nDROP FUNCTION IF EXISTS public.get_service_users_with_tenant(uuid)","-- 2. Creamos la versión optimizada con ORDER BY\r\nCREATE OR REPLACE FUNCTION public.get_service_users_with_tenant(target_tenant_id uuid)\r\nRETURNS SETOF public.service_users\r\nSET search_path = public\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER -- Ejecuta con privilegios elevados para saltar RLS interno si es necesario\r\nAS $$\r\nBEGIN\r\n  -- Verificación de seguridad: ¿El usuario que consulta pertenece a este tenant?\r\n  IF NOT EXISTS (\r\n    SELECT 1\r\n    FROM public.tenant_permissions tp\r\n    JOIN public.service_users su ON tp.service_user_id = su.id\r\n    WHERE tp.tenant_id = target_tenant_id\r\n    AND su.auth_user_id = auth.uid()\r\n  ) THEN\r\n    RAISE EXCEPTION 'Acceso denegado: no tienes permisos en este tenant.';\r\n  END IF;\r\n\r\n  -- Retorno de los usuarios ordenados alfabéticamente\r\n  RETURN QUERY\r\n  SELECT su.*\r\n  FROM public.service_users su\r\n  INNER JOIN public.tenant_permissions tp ON su.id = tp.service_user_id\r\n  WHERE tp.tenant_id = target_tenant_id\r\n  ORDER BY su.full_name ASC; -- <--- Garantiza que no salten al actualizar\r\nEND;\r\n$$"}	ALTER_function_get_service_users_with_tenant
20260318215810	{"DROP POLICY IF EXISTS \\"Acceso total verificado: JWT + Base de Datos\\" ON public.tenants","create policy \\"Acceso total verificado: JWT + Base de Datos\\"\r\non public.tenants\r\nfor select\r\nto authenticated\r\nusing (\r\n  -- 1. Filtro de primera línea (JWT)\r\n  -- Buscamos el slug de la fila actual dentro del array de tenants del JWT\r\n  ((auth.jwt() -> 'app_metadata' -> 'tenants') ? tenants.slug)\r\n  \r\n  AND \r\n  \r\n  -- 2. Verdad absoluta (Base de Datos)\r\n  exists (\r\n    select 1 \r\n    from public.tenant_permissions tp\r\n    inner join public.service_users su on tp.service_user_id = su.id\r\n    where tp.tenant_id = tenants.id  -- Referencia a la fila evaluada\r\n    and su.auth_user_id = auth.uid() -- Filtro por el usuario actual\r\n  )\r\n)"}	ALTER_policy_table_tenants
