20260323160719	{"drop policy if exists \\"Acceso total verificado: JWT + Base de Datos\\" on public.tenants","create policy \\"Acceso total verificado: JWT + Base de Datos\\"\r\non public.tenants\r\nfor select\r\nto authenticated\r\nusing (\r\n  -- 1. Filtro de primera línea (JWT)\r\n  -- Buscamos el slug de la fila actual dentro del array de tenants del JWT\r\n  (((select auth.jwt()) -> 'app_metadata' -> 'tenants') ? tenants.slug)\r\n  \r\n  AND \r\n  \r\n  -- 2. Verdad absoluta (Base de Datos)\r\n  exists (\r\n    select 1 \r\n    from public.tenant_permissions tp\r\n    inner join public.service_users su on tp.service_user_id = su.id\r\n    where tp.tenant_id = tenants.id  -- Referencia a la fila evaluada\r\n    and su.auth_user_id = (select auth.uid()) -- Filtro por el usuario actual\r\n  )\r\n)"}	ALTER_policy_table_tenants
20260323161152	{"drop policy if exists \\"Users can see tickets from their tenants\\" on public.tickets","-- POLÍTICA: Los usuarios solo pueden ver tickets de los tenants a los que pertenecen\r\ncreate policy \\"Users can see tickets from their tenants\\"\r\non public.tickets\r\nfor select\r\nto authenticated\r\nusing (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = (select auth.uid())\r\n    )\r\n  )\r\n)","drop policy if exists \\"Users can create tickets in their tenants\\" on public.tickets","-- POLÍTICA: Los usuarios pueden crear tickets en los tenants donde son miembros\r\ncreate policy \\"Users can create tickets in their tenants\\"\r\non public.tickets\r\nfor insert\r\nto authenticated\r\nwith check (\r\n  tenant_id in (\r\n    select tenant_id \r\n    from public.tenant_permissions \r\n    where service_user_id in (\r\n      select id from public.service_users where auth_user_id = (select auth.uid())\r\n    )\r\n  )\r\n)","drop policy if exists \\"Authors can update their own tickets\\" on public.tickets","-- POLÍTICA: Solo el autor (o un admin) puede actualizar el ticket\r\n-- (Aquí puedes simplificarlo o hacerlo más complejo según tus roles)\r\ncreate policy \\"Authors can update their own tickets\\"\r\non public.tickets\r\nfor update\r\nto authenticated\r\nusing (\r\n  created_by in (\r\n    select id from public.service_users where auth_user_id = (select auth.uid())\r\n  )\r\n)\r\nwith check (\r\n  created_by in (\r\n    select id from public.service_users where auth_user_id = (select auth.uid())\r\n  )\r\n)","drop policy if exists \\"Users can delete own tickets\\" on public.tickets","create policy \\"Users can delete own tickets\\"\r\non public.tickets\r\nfor delete\r\nto authenticated\r\nusing (\r\n  exists (\r\n    select 1 \r\n    from public.service_users su\r\n    join public.tenant_permissions tp on tp.service_user_id = su.id\r\n    where su.auth_user_id = (select auth.uid())\r\n    and public.tickets.created_by = su.id\r\n    and public.tickets.tenant_id = tp.tenant_id\r\n  )\r\n)"}	ALTER_policy_table_tickets
