20260323162833	{"-- 1. Borramos el que tienes actualmente\r\ndrop index if exists public.comments_tenant_ticket_idx","-- 2. Lo creamos en el orden exacto de la FK\r\n-- Primero ticket_id, luego tenant_id\r\ncreate index comments_ticket_tenant_idx \r\non public.comments (ticket_id, tenant_id)"}	ALTER_index_table_comments_order
20260323175256	{"-- Función que borra sesiones antiguas\r\ncreate or replace function public.handle_single_session()\r\nreturns trigger as $$\r\nbegin\r\n  -- Borramos todas las sesiones del usuario EXCEPTO la que se acaba de crear\r\n  delete from auth.sessions\r\n  where user_id = new.user_id\r\n    and id != new.id;\r\n  return new;\r\nend;\r\n$$ language plpgsql security definer","-- Aplicamos el trigger a la tabla de sesiones de Supabase Auth\r\ncreate trigger on_auth_session_created\r\n  after insert on auth.sessions\r\n  for each row execute procedure public.handle_single_session()"}	CREATE_function_handle_single_session
20260323234916	{"-- 1. Eliminamos la versión anterior (especificando los argumentos para evitar conflictos)\r\nDROP FUNCTION IF EXISTS public.get_service_users_with_tenant(uuid)","-- 2. Creamos la nueva versión sin la validación interna de auth.uid()\r\nCREATE OR REPLACE FUNCTION public.get_service_users_with_tenant(target_tenant_id uuid)\r\nRETURNS SETOF public.service_users\r\nSET search_path = public\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER -- Ejecuta con privilegios de sistema, ideal para el Admin Client\r\nAS $$\r\nBEGIN\r\n  RETURN QUERY\r\n  SELECT DISTINCT su.*\r\n  FROM public.service_users su\r\n  JOIN public.tenant_permissions tp ON su.id = tp.service_user_id\r\n  WHERE tp.tenant_id = target_tenant_id\r\n  ORDER BY su.full_name ASC;\r\nEND;\r\n$$"}	ALTER_function_get_service_users_with_tenant
20260401170643	{"ALTER TABLE public.tickets DETACH PARTITION public.tickets_tenant_acme","ALTER TABLE public.tickets DETACH PARTITION public.tickets_tenant_globex","ALTER TABLE public.tickets DETACH PARTITION public.tickets_tenant_umbrella","DROP TABLE IF EXISTS public.tickets_tenant_acme","DROP TABLE IF EXISTS public.tickets_tenant_globex","DROP TABLE IF EXISTS public.tickets_tenant_umbrella"}	DROP_tables_partition_acme
20260402193458	{"-- ==========================================\r\n-- MIGRACIÓN: service_users v1.1 -> v1.2\r\n-- ==========================================\r\n\r\n-- 1. LIMPIEZA ABSOLUTA\r\n-- Borramos el índice viejo primero para que no dé errores\r\nDROP INDEX IF EXISTS service_users_is_available_idx","-- Borramos la columna que ya no usaremos\r\nALTER TABLE public.service_users \r\nDROP COLUMN IF EXISTS is_available,\r\nDROP COLUMN IF EXISTS job_title","-- 2. ADICIÓN DE NUEVAS COLUMNAS\r\n-- Nota: Primero las añadimos como NULL para no romper datos existentes\r\nALTER TABLE public.service_users \r\nADD COLUMN IF NOT EXISTS document_type TEXT NOT NULL DEFAULT 'cedula',\r\nADD COLUMN IF NOT EXISTS document_number TEXT,\r\nADD COLUMN IF NOT EXISTS is_active BOOLEAN NOT NULL DEFAULT true","-- 4. APLICAR RESTRICCIÓN NOT NULL\r\nALTER TABLE public.service_users ALTER COLUMN document_number SET NOT NULL","-- 5. Regla de tipos de documento\r\nALTER TABLE public.service_users\r\n    ADD CONSTRAINT service_users_document_type_check \r\n    CHECK (document_type IN ('cedula', 'cedula_extrangeria', 'pasaporte', 'nit', 'targeta_identidad'))","-- UNICIDAD COMPUESTA (La clave para evitar duplicados reales)\r\nALTER TABLE public.service_users\r\n    ADD CONSTRAINT service_users_document_unique \r\n    UNIQUE (document_type, document_number)","-- 6. ÍNDICES DE RENDIMIENTO\r\nCREATE INDEX IF NOT EXISTS service_users_document_number_idx ON public.service_users (document_number)","CREATE INDEX IF NOT EXISTS service_users_is_active_idx ON public.service_users (is_active)","-- 7. COMENTARIOS\r\nCOMMENT ON COLUMN public.service_users.document_number IS 'Número de identificación legal (Obligatorio)'","COMMENT ON COLUMN public.service_users.is_active IS 'Control maestro de acceso al sistema'"}	ALTER_table_service_users
20260402201330	{"-- 1. Función que sincroniza el estado activo con Auth Metadata\r\nCREATE OR REPLACE FUNCTION public.sync_user_active_status()\r\nRETURNS TRIGGER AS $$\r\nBEGIN\r\n  UPDATE auth.users\r\n  SET raw_app_metadata = raw_app_metadata || \r\n    jsonb_build_object('is_active', NEW.is_active)\r\n  WHERE id = NEW.auth_user_id;\r\n  RETURN NEW;\r\nEND;\r\n$$ LANGUAGE plpgsql SECURITY DEFINER"}	CREATE_function_sync_user_active_status
20260402202001	{"--Trigger que se dispara al actualizar is_active\r\n--Cambiamos el trigger para que escuche INSERT y UPDATE\r\nCREATE TRIGGER on_auth_user_created_or_updated\r\n  AFTER INSERT OR UPDATE OF is_active ON public.service_users\r\n  FOR EACH ROW\r\n  EXECUTE FUNCTION public.sync_user_active_status()"}	CREATE_trigger_table_service_users
20260402232240	{"-- Función que sincroniza el estado activo con Auth Metadata corregida\r\nCREATE OR REPLACE FUNCTION public.sync_user_active_status()\r\nRETURNS TRIGGER AS $$\r\nBEGIN\r\n  UPDATE auth.users\r\n  SET raw_app_metadata = \r\n    COALESCE(raw_app_metadata, '{}'::jsonb) || \r\n    jsonb_build_object('is_active', NEW.is_active)\r\n  WHERE id = NEW.auth_user_id;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$$ LANGUAGE plpgsql SECURITY DEFINER"}	ALTER_funcion_sync_user_active_status
20260402232413	{"-- Función que sincroniza el estado activo con Auth Metadata corregida\r\nCREATE OR REPLACE FUNCTION public.sync_user_active_status()\r\nRETURNS TRIGGER AS $$\r\nBEGIN\r\n  UPDATE auth.users\r\n  SET raw_app_meta_data = \r\n    COALESCE(raw_app_meta_data, '{}'::jsonb) || \r\n    jsonb_build_object('is_active', NEW.is_active)\r\n  WHERE id = NEW.auth_user_id;\r\n  \r\n  RETURN NEW;\r\nEND;\r\n$$ LANGUAGE plpgsql SECURITY DEFINER"}	ALTER_funcion_sync_user_active_status
20260413173655	{"-- ==========================================\r\n-- 1. TIPOS ENUM (Definiciones previas)\r\n-- ==========================================\r\nDO $$ \r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'vehicle_type_enum') THEN\r\n        CREATE TYPE vehicle_type_enum AS ENUM ('motocicleta', 'liviano', 'pesado', 'motocarro');\r\n    END IF;\r\nEND $$","-- ==========================================\r\n-- 2. TABLA: order_template (Plantilla Orden de Entrada)\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.order_template (\r\n    -- Identificadores\r\n    id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    tenant_id           UUID NOT NULL,\r\n    \r\n    -- Información de la Plantilla\r\n    template_name       TEXT NOT NULL,\r\n    version             INTEGER NOT NULL DEFAULT 1,\r\n    is_active           BOOLEAN NOT NULL DEFAULT true,\r\n    \r\n    -- Documentación Legal/SGC\r\n    document_date       DATE NOT NULL DEFAULT CURRENT_DATE,\r\n    document_code       TEXT NOT NULL,\r\n    logo_url            TEXT,\r\n    applies_to_vehicle  vehicle_type_enum NOT NULL,\r\n    base_contract_text  TEXT,\r\n\r\n    -- Auditoría\r\n    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    created_by          UUID,\r\n    deleted_at          TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 3. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\n-- Relación con el funcionario que crea la plantilla\r\nALTER TABLE public.order_template\r\n    ADD CONSTRAINT order_template_created_by_fkey \r\n    FOREIGN KEY (created_by) REFERENCES public.service_users(id) ON DELETE SET NULL","ALTER TABLE public.order_template \r\n    ADD CONSTRAINT order_template_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- ==========================================\r\n-- 4. CONSTRAINTS (Validaciones y Unicidad)\r\n-- ==========================================\r\n\r\n-- 1. Unicidad de Versión por Plantilla y Tenant\r\n-- Evita que un mismo CDA tenga dos \\"v1\\" de la misma plantilla\r\nALTER TABLE public.order_template\r\n    ADD CONSTRAINT order_template_name_version_tenant_key \r\n    UNIQUE (tenant_id, template_name, version)","-- 2. Validación de código de documento no vacío\r\nALTER TABLE public.order_template\r\n    ADD CONSTRAINT order_template_document_code_check \r\n    CHECK (char_length(document_code) > 0)","-- ==========================================\r\n-- 5. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\n-- Búsqueda rápida por Tenant (Esencial para Multi-tenant)\r\nCREATE INDEX IF NOT EXISTS order_template_tenant_id_idx \r\n    ON public.order_template USING btree (tenant_id)","-- Búsqueda por tipo de vehículo (Para filtrar en la recepción)\r\nCREATE INDEX IF NOT EXISTS order_template_vehicle_type_idx \r\n    ON public.order_template USING btree (applies_to_vehicle)","-- Búsqueda por estado activo y no borrado\r\nCREATE INDEX IF NOT EXISTS order_template_active_not_deleted_idx \r\n    ON public.order_template (is_active) \r\n    WHERE (deleted_at IS NULL)","-- Búsqueda difusa por nombre de plantilla\r\nCREATE INDEX IF NOT EXISTS order_template_name_trgm_idx \r\n    ON public.order_template USING gin (template_name gin_trgm_ops)","-- ==========================================\r\n-- 6. COMENTARIOS DE DOCUMENTACIÓN\r\n-- ==========================================\r\n\r\nCOMMENT ON TABLE public.order_template IS 'Configuración maestra de las plantillas de orden de entrada para el SGC. v1.0'","COMMENT ON COLUMN public.order_template.is_active IS 'Indica si la plantilla está disponible para nuevas órdenes.'","COMMENT ON COLUMN public.order_template.version IS 'Número incremental para control de cambios inmutables.'","COMMENT ON COLUMN public.order_template.base_contract_text IS 'Texto legal/contrato que se copiará como snapshot a la orden.'","-- ==========================================\r\n-- 7. GRANTS\r\n-- ==========================================\r\n\r\n-- Permiso para role authenticated\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template TO authenticated","-- Permiso para el service role\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template TO service_role"}	CREATE_table_order_template
20260413174635	{"create trigger tr_order_template_updated_at\r\nbefore update on public.order_template\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_order_template_update_at
20260413180400	{"-- ==========================================\r\n-- 1. TIPOS ENUM (Definición de respuestas)\r\n-- ==========================================\r\nDO $$ \r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'condition_response_enum') THEN\r\n        CREATE TYPE condition_response_enum AS ENUM ('cumple', 'no_cumple', 'no_aplica');\r\n    END IF;\r\nEND $$","-- ==========================================\r\n-- 2. TABLA: order_template_conditions\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.order_template_conditions (\r\n    -- Identificadores\r\n    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    tenant_id               UUID NOT NULL, -- Agregado para aislamiento directo\r\n    order_template_id       UUID NOT NULL,\r\n    \r\n    -- Configuración de la Pregunta/Condición\r\n    label                   TEXT NOT NULL,\r\n    is_special              BOOLEAN NOT NULL DEFAULT false,\r\n    special_condition_label TEXT,\r\n    default_value           condition_response_enum NOT NULL DEFAULT 'no_aplica',\r\n    \r\n    -- UI y Ordenamiento\r\n    visual_order            INTEGER NOT NULL DEFAULT 0,\r\n\r\n    -- Auditoría\r\n    created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    updated_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    deleted_at              TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 3. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\nALTER TABLE public.order_template_conditions\r\n    ADD CONSTRAINT order_template_conditions_template_id_fkey \r\n    FOREIGN KEY (order_template_id) REFERENCES public.order_template(id) ON DELETE CASCADE","ALTER TABLE public.order_template_conditions\r\n    ADD CONSTRAINT order_template_conditions_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- ==========================================\r\n-- 4. CONSTRAINTS (Validaciones)\r\n-- ==========================================\r\n\r\n-- 1. Si es una condición especial, debería tener un label descriptivo\r\nALTER TABLE public.order_template_conditions\r\n    ADD CONSTRAINT special_condition_label_check \r\n    CHECK (\r\n        (is_special = false) OR \r\n        (is_special = true AND special_condition_label IS NOT NULL)\r\n    )","-- ==========================================\r\n-- 5. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\n-- Búsqueda rápida de condiciones por plantilla\r\nCREATE INDEX IF NOT EXISTS order_template_conditions_template_idx \r\n    ON public.order_template_conditions USING btree (order_template_id)","-- Índice para cargar las preguntas en el orden correcto (Frontend)\r\nCREATE INDEX IF NOT EXISTS order_template_conditions_sorting_idx \r\n    ON public.order_template_conditions (order_template_id, visual_order)\r\n    WHERE (deleted_at IS NULL)","-- ==========================================\r\n-- 6. COMENTARIOS DE DOCUMENTACIÓN\r\n-- ==========================================\r\n\r\nCOMMENT ON TABLE public.order_template_conditions IS 'Preguntas o ítems de inspección asociados a una plantilla específica.'","COMMENT ON COLUMN public.order_template_conditions.is_special IS 'Define si la condición requiere un campo adicional (ej: checkbox de disco de freno).'","COMMENT ON COLUMN public.order_template_conditions.visual_order IS 'Determina la posición en la interfaz de usuario.'","-- ==========================================\r\n-- 7. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template_conditions TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template_conditions TO service_role"}	CREATE_table_order_template_conditions
20260413191221	\N	CREATE_trigger_order_template_conditions_updated_at
20260413191616	{"create trigger set_order_template_conditions_updated_at\r\nbefore update on public.order_template_conditions\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_order_template_conditions_updated_at2
20260414190155	{"-- ==========================================\r\n-- 1. TABLA: order_template_signatures (Firmas Requeridas)\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.order_template_signatures (\r\n    -- Identificadores\r\n    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    tenant_id               UUID NOT NULL,\r\n    order_template_id       UUID NOT NULL,\r\n    \r\n    -- Configuración de la Firma\r\n    representative_type     TEXT NOT NULL, -- Ahora es texto libre (Ej: 'Gerente', 'Secretaria', 'Inspector')\r\n    signature_label         TEXT NOT NULL, -- Ej: 'Firma de quien recibe el vehículo'\r\n    \r\n    -- UI y Ordenamiento\r\n    visual_order            INTEGER NOT NULL DEFAULT 0,\r\n\r\n    -- Auditoría\r\n    created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    updated_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    deleted_at              TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 2. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\nALTER TABLE public.order_template_signatures\r\n    ADD CONSTRAINT order_template_signatures_template_id_fkey \r\n    FOREIGN KEY (order_template_id) REFERENCES public.order_template(id) ON DELETE CASCADE","ALTER TABLE public.order_template_signatures\r\n    ADD CONSTRAINT order_template_signatures_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- ==========================================\r\n-- 3. CONSTRAINTS (Validaciones)\r\n-- ==========================================\r\n\r\n-- Unicidad lógica: Evitar duplicados en el mismo orden visual por plantilla\r\nALTER TABLE public.order_template_signatures\r\n    ADD CONSTRAINT order_template_signatures_unique_pos \r\n    UNIQUE (order_template_id, visual_order, deleted_at)","-- ==========================================\r\n-- 4. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\nCREATE INDEX IF NOT EXISTS order_template_signatures_tenant_idx \r\n    ON public.order_template_signatures USING btree (tenant_id)","CREATE INDEX IF NOT EXISTS order_template_signatures_template_idx \r\n    ON public.order_template_signatures (order_template_id, visual_order)\r\n    WHERE (deleted_at IS NULL)","-- ==========================================\r\n-- 5. COMENTARIOS DE DOCUMENTACIÓN\r\n-- ==========================================\r\n\r\nCOMMENT ON TABLE public.order_template_signatures IS 'Define los roles que deben firmar la orden. Texto libre para máxima adaptabilidad.'","COMMENT ON COLUMN public.order_template_signatures.representative_type IS 'Nombre del rol legal (libre): Gerente, DT, Recepcionista, etc.'","-- ==========================================\r\n-- 6. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template_signatures TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template_signatures TO service_role"}	CREATE_table_order_template_signatures
20260414190540	{"create trigger tr_order_template_signatures_updated_at\r\nbefore update on public.order_template_signatures\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_order_template_swignatures_updatedat
20260414191149	{"-- ==========================================\r\n-- 1. TABLA: order_template_signature_conditions\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.order_template_signature_conditions (\r\n    -- Identificadores\r\n    id                          UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    tenant_id                   UUID NOT NULL,\r\n    order_template_signature_id UUID NOT NULL,\r\n    \r\n    -- Configuración de la Declaración\r\n    declaration_text            TEXT NOT NULL,\r\n    \r\n    \r\n    -- Auditoría\r\n    created_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    updated_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    deleted_at                  TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 2. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\nALTER TABLE public.order_template_signature_conditions\r\n    ADD CONSTRAINT signature_conditions_signature_id_fkey \r\n    FOREIGN KEY (order_template_signature_id) \r\n    REFERENCES public.order_template_signatures(id) ON DELETE CASCADE","ALTER TABLE public.order_template_signature_conditions\r\n    ADD CONSTRAINT signature_conditions_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- ==========================================\r\n-- 3. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\nCREATE INDEX IF NOT EXISTS signature_conditions_tenant_idx \r\n    ON public.order_template_signature_conditions USING btree (tenant_id)","CREATE INDEX IF NOT EXISTS signature_conditions_parent_idx \r\n    ON public.order_template_signature_conditions (order_template_signature_id)\r\n    WHERE (deleted_at IS NULL)","-- ==========================================\r\n-- 4. COMENTARIOS DE DOCUMENTACIÓN\r\n-- ==========================================\r\n\r\nCOMMENT ON TABLE public.order_template_signature_conditions IS 'Textos de aceptación legal vinculados a una firma. Todos son obligatorios por defecto.'","-- ==========================================\r\n-- 5. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template_signature_conditions TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.order_template_signature_conditions TO service_role"}	CREATE_table_order_template_signature_conditions
20260414191240	{"create trigger tr_order_template_signature_conditions_updated_at\r\nbefore update on public.order_template_signature_conditions\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_order_template_signature_conditions_updatedat
20260414193042	{"-- ==========================================\r\n-- 0. CREACIÓN DEL TIPO ENUM (Normalizado)\r\n-- ==========================================\r\nDO $$ \r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'document_type_enum') THEN\r\n        CREATE TYPE document_type_enum AS ENUM (\r\n            'cedula_ciudadania', \r\n            'nit', \r\n            'nn', \r\n            'pasaporte', \r\n            'cedula_extranjeria', \r\n            'tarjeta_identidad', \r\n            'registro_civil', \r\n            'carnet_diplomatico', \r\n            'ti2'\r\n        );\r\n    END IF;\r\nEND $$","-- ==========================================\r\n-- 1. TABLA: personas\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.personas (\r\n    -- Identificador único global.\r\n    id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    \r\n    -- Para que los clientes de un CDA no se mezclen con otros.\r\n    tenant_id           UUID NOT NULL,\r\n    \r\n    -- cedula_ciudadania, nit, nn, pasaporte, etc. (Fundamental para facturación).\r\n    tipo_documento      document_type_enum NOT NULL,\r\n    \r\n    -- La cédula o NIT (Indexado para búsqueda rápida).\r\n    numero_documento    VARCHAR NOT NULL,\r\n    \r\n    -- Nombre o Razón Social.\r\n    nombre_completo     TEXT NOT NULL,\r\n    \r\n    -- Celular de contacto.\r\n    telefono            VARCHAR,\r\n    \r\n    -- Para envío del PDF de la orden o resultados.\r\n    correo              VARCHAR,\r\n    \r\n    -- Dirección de residencia o notificación.\r\n    direccion           TEXT,\r\n\r\n    -- Registro de creación en sistema.\r\n    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Registro de última edición.\r\n    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Para anulación o borrado lógico.\r\n    deleted_at          TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 2. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\n-- Relación con el tenant para aislamiento total.\r\nALTER TABLE public.personas\r\n    ADD CONSTRAINT personas_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- ==========================================\r\n-- 3. CONSTRAINTS (Unicidad)\r\n-- ==========================================\r\n\r\n-- Evita duplicar la misma persona (Tipo + Número) dentro de un mismo CDA.\r\nALTER TABLE public.personas\r\n    ADD CONSTRAINT personas_documento_tenant_key UNIQUE (tenant_id, tipo_documento, numero_documento)","-- ==========================================\r\n-- 4. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\n-- Búsqueda rápida por número de identificación (Fundamental para recepción).\r\nCREATE INDEX IF NOT EXISTS personas_numero_documento_idx \r\n    ON public.personas USING btree (numero_documento)","-- Búsqueda por Tenant para RLS.\r\nCREATE INDEX IF NOT EXISTS personas_tenant_idx \r\n    ON public.personas USING btree (tenant_id)","-- Búsqueda difusa por nombre.\r\nCREATE INDEX IF NOT EXISTS personas_nombre_completo_trgm_idx \r\n    ON public.personas USING gin (nombre_completo gin_trgm_ops)","-- ==========================================\r\n-- 5. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.personas TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.personas TO service_role"}	CREATE_table_personas
20260414193515	{"create trigger tr_personas_updated_at\r\nbefore update on public.personas\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_personas_updatedat
20260414193548	{"-- ==========================================\r\n-- 1. TABLA: vehicles\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.vehicles (\r\n    -- Identificador único global.\r\n    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    \r\n    -- Indispensable para separar los datos de cada CDA (Multi-tenant).\r\n    tenant_id               UUID NOT NULL,\r\n\r\n    -- Única por país (Indexada para búsqueda rápida).\r\n    placa                   VARCHAR NOT NULL,\r\n    \r\n    -- Ej: Chevrolet, Yamaha.\r\n    marca                   VARCHAR,\r\n    \r\n    -- Ej: Spark, NMAX.\r\n    linea                   VARCHAR,\r\n    \r\n    -- El año del vehículo.\r\n    modelo                  INTEGER,\r\n    \r\n    -- Color actual del vehículo.\r\n    color                   VARCHAR,\r\n    \r\n    -- (motocicleta, liviano, pesado, motocarro).\r\n    tipo_vehiculo           vehicle_type_enum NOT NULL,\r\n    \r\n    -- Automóvil, Camioneta, Motocicleta.\r\n    clase                   VARCHAR,\r\n    \r\n    -- Gasolina, Diesel, Eléctrico, GNV.\r\n    combustible             VARCHAR,\r\n    \r\n    -- Vital para determinar tarifas y pruebas de gases.\r\n    cilindrada              INTEGER,\r\n    \r\n    -- Indica si el vehículo posee blindaje legal.\r\n    blindaje                BOOLEAN DEFAULT false,\r\n    \r\n    -- Cantidad máxima de personas permitidas.\r\n    capacidad_pasajeros     INTEGER,\r\n    \r\n    \r\n    -- Indica si es un vehículo de escuela de conducción.\r\n    es_ensenanza            BOOLEAN DEFAULT false,\r\n    \r\n    -- Fecha de vigencia actual del SOAT.\r\n    soat_vencimiento        DATE,\r\n    \r\n    -- Número del certificado de gas (si aplica).\r\n    gas_numero              VARCHAR,\r\n    \r\n    -- Fecha de vigencia del certificado de gas.\r\n    gas_vencimiento         DATE,\r\n\r\n    -- Referencia a la tabla personas (Dueño registrado).\r\n    propietario_actual_id   UUID,\r\n\r\n    -- Registro de creación en sistema.\r\n    created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Registro de última edición.\r\n    updated_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Registro para anulación o borrado lógico.\r\n    deleted_at              TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 2. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\n-- Relación con el tenant para aislamiento total.\r\nALTER TABLE public.vehicles\r\n    ADD CONSTRAINT vehicles_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- Relación con el propietario (Referencia a personas).\r\nALTER TABLE public.vehicles\r\n    ADD CONSTRAINT vehicles_propietario_fkey \r\n    FOREIGN KEY (propietario_actual_id) REFERENCES public.personas(id) ON DELETE SET NULL","-- ==========================================\r\n-- 3. CONSTRAINTS (Unicidad)\r\n-- ==========================================\r\n\r\n-- Unicidad de placa por Tenant (Evita duplicados en el mismo CDA).\r\nALTER TABLE public.vehicles\r\n    ADD CONSTRAINT vehicles_placa_tenant_key UNIQUE (tenant_id, placa)","-- ==========================================\r\n-- 4. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\n-- Búsqueda ultra rápida por placa.\r\nCREATE INDEX IF NOT EXISTS vehicles_placa_idx \r\n    ON public.vehicles USING btree (placa)","-- Búsqueda por propietario.\r\nCREATE INDEX IF NOT EXISTS vehicles_propietario_idx \r\n    ON public.vehicles USING btree (propietario_actual_id)","-- Búsqueda por Tenant para RLS.\r\nCREATE INDEX IF NOT EXISTS vehicles_tenant_idx \r\n    ON public.vehicles USING btree (tenant_id)","-- ==========================================\r\n-- 5. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.vehicles TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.vehicles TO service_role"}	CREATE_table_vehicles
20260414193712	{"create trigger tr_vehicles_updated_at\r\nbefore update on public.vehicles\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_vehicles_updatedat
20260414195345	{"-- ==========================================\r\n-- 1. TIPOS ENUM (Estados y Servicios)\r\n-- ==========================================\r\nDO $$ \r\nBEGIN\r\n    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'order_status_enum') THEN\r\n        CREATE TYPE order_status_enum AS ENUM ('abierta', 'en_prueba', 'finalizada', 'anulada');\r\n    END IF;\r\n    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'service_type_enum') THEN\r\n        CREATE TYPE service_type_enum AS ENUM ('RTM', 'preventiva', 'peritaje', 'otro');\r\n    END IF;\r\nEND $$","-- ==========================================\r\n-- 2. TABLA: entry_orders\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.entry_orders (\r\n    -- Identificador único global.\r\n    id                          UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    \r\n    -- Indispensable para separar los datos de cada CDA.\r\n    tenant_id                   UUID NOT NULL,\r\n    \r\n    -- El número que ve el cliente (ej: 0001, 0002).\r\n    consecutivo                 SERIAL,\r\n    \r\n    -- Fecha y hora exacta de la creación.\r\n    fecha                       TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Referencia al vehículo.\r\n    vehiculo_id                 UUID NOT NULL,\r\n    \r\n    -- Referencia al dueño actual.\r\n    propietario_id              UUID NOT NULL,\r\n    \r\n    -- Quien trae el vehículo (puede ser diferente al dueño).\r\n    cliente_id                  UUID NOT NULL,\r\n    \r\n    -- El recepcionista que atiende (Referencia a service_users).\r\n    funcionario_id              UUID NOT NULL,\r\n    \r\n    -- La plantilla de inspección que se usó.\r\n    plantilla_id                UUID NOT NULL,\r\n    \r\n    -- El valor que marca el odómetro.\r\n    kilometraje                 VARCHAR,\r\n    \r\n    -- RTM, Preventiva, etc.\r\n    tipo_de_servicio            service_type_enum NOT NULL DEFAULT 'RTM',\r\n    \r\n    -- Indica si viene por rechazo previo.\r\n    es_reinspeccion             BOOLEAN DEFAULT false,\r\n    \r\n    -- Notas generales del estado del vehículo.\r\n    observaciones               TEXT,\r\n    \r\n    -- 'abierta', 'en_prueba', 'finalizada', 'anulada'.\r\n    estado_orden                order_status_enum NOT NULL DEFAULT 'abierta',\r\n    \r\n    -- Fecha del SOAT al momento de entrar.\r\n    soat_vencimiento_snapshot   DATE,\r\n    \r\n    -- Número de certificado de gas al momento de entrar.\r\n    gas_numero_snapshot         VARCHAR,\r\n    \r\n    -- Fecha de certificado de gas al momento de entrar.\r\n    gas_vencimiento_snapshot    DATE,\r\n    \r\n    -- El contrato legal exacto que firmó ese día.\r\n    texto_contractual_snapshot  TEXT,\r\n\r\n    -- Registro de creación en sistema.\r\n    created_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Registro de última edición.\r\n    updated_at                  TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Para anular la orden sin borrarla físicamente.\r\n    deleted_at                  TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 3. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\nALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","ALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_vehiculo_id_fkey FOREIGN KEY (vehiculo_id) REFERENCES public.vehicles(id)","ALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_propietario_id_fkey FOREIGN KEY (propietario_id) REFERENCES public.personas(id)","ALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_cliente_id_fkey FOREIGN KEY (cliente_id) REFERENCES public.personas(id)","ALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_plantilla_id_fkey FOREIGN KEY (plantilla_id) REFERENCES public.order_template(id)","-- Nota: funcionario_id referencia a tu tabla de usuarios del sistema\r\nALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_funcionario_id_fkey FOREIGN KEY (funcionario_id) REFERENCES public.service_users(id)","-- ==========================================\r\n-- 4. CONSTRAINTS (Unicidad)\r\n-- ==========================================\r\n\r\n-- El consecutivo debe ser único por cada CDA (Tenant)\r\nALTER TABLE public.entry_orders\r\n    ADD CONSTRAINT entry_orders_consecutivo_tenant_key UNIQUE (tenant_id, consecutivo)","-- ==========================================\r\n-- 5. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\n-- Búsquedas por fecha (Reportes)\r\nCREATE INDEX IF NOT EXISTS entry_orders_fecha_idx ON public.entry_orders (fecha)","-- Aislamiento RLS\r\nCREATE INDEX IF NOT EXISTS entry_orders_tenant_idx ON public.entry_orders (tenant_id)","-- Búsqueda de historial por vehículo\r\nCREATE INDEX IF NOT EXISTS entry_orders_vehiculo_idx ON public.entry_orders (vehiculo_id)","-- ==========================================\r\n-- 6. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.entry_orders TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.entry_orders TO service_role"}	CREATE_table_entry_orders
20260414200128	{"create trigger set_entry_orders_updated_at\r\nbefore update on public.entry_orders\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_entry_orders
20260414201213	{"CREATE TABLE IF NOT EXISTS public.order_condition_results (\r\n    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    tenant_id               UUID NOT NULL,\r\n    entry_order_id          UUID NOT NULL,\r\n    -- Referencia a la pregunta original\r\n    template_condition_id   UUID NOT NULL,\r\n    \r\n    -- El resultado marcado por el inspector\r\n    value                   condition_response_enum NOT NULL,\r\n    -- Si era una condición especial (ej: checkbox de disco de freno), aquí se guarda si se marcó\r\n    special_value           BOOLEAN DEFAULT false,\r\n    \r\n    created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    updated_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n\r\n    CONSTRAINT ocr_tenant_fkey FOREIGN KEY (tenant_id) REFERENCES public.tenants(id),\r\n    CONSTRAINT ocr_order_fkey FOREIGN KEY (entry_order_id) REFERENCES public.entry_orders(id) ON DELETE CASCADE\r\n)"}	CREATE_table_order_condition_results
20260414202541	{"-- ==========================================\r\n-- 1. TABLA: entry_order_tire_pressures\r\n-- ==========================================\r\n\r\nCREATE TABLE IF NOT EXISTS public.entry_order_tire_pressures (\r\n    -- Identificador único global.\r\n    id                      UUID PRIMARY KEY DEFAULT gen_random_uuid(),\r\n    \r\n    -- Indispensable para separar los datos de cada CDA.\r\n    tenant_id               UUID NOT NULL,\r\n    \r\n    -- Referencia a la orden de entrada específica.\r\n    entry_order_id          UUID NOT NULL,\r\n    \r\n    -- Ej: 1, 2, 3... (Útil para ordenar visualmente).\r\n    eje                     INTEGER NOT NULL,\r\n    \r\n    -- Ej: 'izquierda', 'derecha', 'izquierda interior', 'derecha interior'.\r\n    posicion                VARCHAR NOT NULL,\r\n    \r\n    -- La medida inicial tomada por el inspector.\r\n    presion_encontrada      NUMERIC,\r\n    \r\n    -- Si el cliente la infló/desinfló, se registra aquí el nuevo valor.\r\n    presion_ajustada        NUMERIC,\r\n    \r\n    -- Indica si la medida corresponde a la llanta de auxilio.\r\n    es_repuesto             BOOLEAN DEFAULT false,\r\n\r\n    -- Registro de creación en sistema.\r\n    created_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Registro de última edición.\r\n    updated_at              TIMESTAMPTZ NOT NULL DEFAULT NOW(),\r\n    \r\n    -- Para anulación o borrado lógico.\r\n    deleted_at              TIMESTAMPTZ\r\n)","-- ==========================================\r\n-- 2. FOREIGN KEYS (Relaciones)\r\n-- ==========================================\r\n\r\n-- Relación con el tenant\r\nALTER TABLE public.entry_order_tire_pressures\r\n    ADD CONSTRAINT tire_pressures_tenant_id_fkey \r\n    FOREIGN KEY (tenant_id) REFERENCES public.tenants(id) ON DELETE CASCADE","-- Relación con la orden (si la orden se borra, las presiones también)\r\nALTER TABLE public.entry_order_tire_pressures\r\n    ADD CONSTRAINT tire_pressures_order_id_fkey \r\n    FOREIGN KEY (entry_order_id) REFERENCES public.entry_orders(id) ON DELETE CASCADE","-- ==========================================\r\n-- 3. ÍNDICES (Rendimiento)\r\n-- ==========================================\r\n\r\n-- Búsqueda rápida por orden para mostrar en el formulario de inspección.\r\nCREATE INDEX IF NOT EXISTS tire_pressures_order_idx \r\n    ON public.entry_order_tire_pressures (entry_order_id)\r\n    WHERE (deleted_at IS NULL)","-- Aislamiento RLS.\r\nCREATE INDEX IF NOT EXISTS tire_pressures_tenant_idx \r\n    ON public.entry_order_tire_pressures USING btree (tenant_id)","-- ==========================================\r\n-- 4. GRANTS\r\n-- ==========================================\r\n\r\nGRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.entry_order_tire_pressures TO authenticated","GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE public.entry_order_tire_pressures TO service_role"}	CREATE_table_entry_order_tire_pressures
20260414202728	{"create trigger set_entry_order_tire_pressures_updated_at\r\nbefore update on public.entry_order_tire_pressures\r\nfor each row\r\nexecute function public.set_updated_at()"}	CREATE_trigger_entry_order_tire_pressures_updatedat
20260415021026	{"-- ==========================================\r\n-- 5. RLS (Row Level Security)\r\n-- ==========================================\r\n\r\nalter table public.entry_order_tire_pressures enable row level security","-- POLÍTICA: Permite a los miembros del tenant crear registros de presión de llantas\r\nCREATE POLICY \\"Users can create tire pressures for their allowed tenants\\"\r\nON public.entry_order_tire_pressures\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- POLÍTICA: Solo los miembros del tenant pueden ver, escribir y hacer update a las presiones de las llantas\r\ncreate policy \\"Users can see tire pressures from their allowed tenants\\"\r\non public.entry_order_tire_pressures\r\nfor select\r\nto authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- POLÍTICA: Permite a los miembros del tenant actualizar las presiones de llantas existentes\r\nCREATE POLICY \\"Users can update tire pressures from their allowed tenants\\"\r\nON public.entry_order_tire_pressures\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_entry_order_tire_pressures
20260415022515	{"-- ==========================================\r\n-- 7. RLS para entry_orders (CREATE)\r\n-- ==========================================\r\n\r\nalter table public.entry_orders enable row level security","-- POLÍTICA: Permite a los funcionarios crear órdenes de entrada solo en sus tenants autorizados\r\nCREATE POLICY \\"Users can create entry orders for their allowed tenants\\"\r\nON public.entry_orders\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- POLÍTICA: Permite ver las órdenes de entrada de los tenants donde el usuario tiene permisos\r\nCREATE POLICY \\"Users can see entry orders from their allowed tenants\\"\r\nON public.entry_orders\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- POLÍTICA: Permite actualizar órdenes existentes, validando que sigan perteneciendo al tenant\r\nCREATE POLICY \\"Users can update entry orders from their allowed tenants\\"\r\nON public.entry_orders\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_entry_orders
20260415023437	{"-- ==========================================\r\n-- 1. HABILITAR RLS: order_condition_results\r\n-- ==========================================\r\nALTER TABLE public.order_condition_results ENABLE ROW LEVEL SECURITY","-- ==========================================\r\n-- 2. RLS: SELECT\r\n-- ==========================================\r\n-- POLÍTICA: Permite ver los resultados de condiciones asociados a sus tenants autorizados\r\nCREATE POLICY \\"Users can see condition results from their allowed tenants\\"\r\nON public.order_condition_results\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 3. RLS: INSERT (CREATE)\r\n-- ==========================================\r\n-- POLÍTICA: Permite registrar resultados de condiciones solo para sus propios tenants\r\nCREATE POLICY \\"Users can create condition results for their allowed tenants\\"\r\nON public.order_condition_results\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 4. RLS: UPDATE\r\n-- ==========================================\r\n-- POLÍTICA: Permite modificar resultados existentes sin cambiar de tenant\r\nCREATE POLICY \\"Users can update condition results from their allowed tenants\\"\r\nON public.order_condition_results\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_order_condition_results
20260415024135	{"-- ==========================================\r\n-- 1. HABILITAR RLS: order_signatures\r\n-- ==========================================\r\nALTER TABLE public.order_signatures ENABLE ROW LEVEL SECURITY","-- ==========================================\r\n-- 2. RLS: SELECT\r\n-- ==========================================\r\n-- POLÍTICA: Permite ver las firmas asociadas a los tenants autorizados\r\nCREATE POLICY \\"Users can see order signatures from their allowed tenants\\"\r\nON public.order_signatures\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 3. RLS: INSERT (CREATE)\r\n-- ==========================================\r\n-- POLÍTICA: Permite registrar firmas solo para sus propios tenants\r\nCREATE POLICY \\"Users can create order signatures for their allowed tenants\\"\r\nON public.order_signatures\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 4. RLS: UPDATE (order_signatures)\r\n-- ==========================================\r\n\r\n-- POLÍTICA: Permite actualizar registros de firmas, validando la pertenencia al tenant\r\nCREATE POLICY \\"Users can update order signatures from their allowed tenants\\"\r\nON public.order_signatures\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_order_signatures
20260415024340	{"-- ==========================================\r\n-- 1. HABILITAR RLS: order_template_conditions\r\n-- ==========================================\r\nALTER TABLE public.order_template_conditions ENABLE ROW LEVEL SECURITY","-- ==========================================\r\n-- 2. RLS: SELECT\r\n-- ==========================================\r\n-- POLÍTICA: Permite ver los ítems de las plantillas de sus tenants autorizados\r\nCREATE POLICY \\"Users can see template conditions from their allowed tenants\\"\r\nON public.order_template_conditions\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 3. RLS: INSERT (CREATE)\r\n-- ==========================================\r\n-- POLÍTICA: Permite crear ítems de plantilla vinculados a sus propios tenants\r\nCREATE POLICY \\"Users can create template conditions for their allowed tenants\\"\r\nON public.order_template_conditions\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 4. RLS: UPDATE\r\n-- ==========================================\r\n-- POLÍTICA: Permite modificar los ítems de plantilla existentes del tenant\r\nCREATE POLICY \\"Users can update template conditions from their allowed tenants\\"\r\nON public.order_template_conditions\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_order_template_conditions
20260415024533	{"-- ==========================================\r\n-- 1. HABILITAR RLS: order_template_signature_conditions\r\n-- ==========================================\r\nALTER TABLE public.order_template_signature_conditions ENABLE ROW LEVEL SECURITY","-- ==========================================\r\n-- 2. RLS: SELECT\r\n-- ==========================================\r\n-- POLÍTICA: Permite ver la relación entre firmas y condiciones de sus tenants autorizados\r\nCREATE POLICY \\"Users can see template signature conditions from their allowed tenants\\"\r\nON public.order_template_signature_conditions\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 3. RLS: INSERT (CREATE)\r\n-- ==========================================\r\n-- POLÍTICA: Permite crear relaciones firma-condición para sus propios tenants\r\nCREATE POLICY \\"Users can create template signature conditions for their allowed tenants\\"\r\nON public.order_template_signature_conditions\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 4. RLS: UPDATE\r\n-- ==========================================\r\n-- POLÍTICA: Permite actualizar las relaciones existentes dentro del mismo tenant\r\nCREATE POLICY \\"Users can update template signature conditions from their allowed tenants\\"\r\nON public.order_template_signature_conditions\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_order_template_signature_conditions
20260415025427	{"-- ==========================================\r\n-- 1. HABILITAR RLS: order_template_signatures\r\n-- ==========================================\r\nALTER TABLE public.order_template_signatures ENABLE ROW LEVEL SECURITY","-- ==========================================\r\n-- 2. RLS: SELECT\r\n-- ==========================================\r\n-- Permite leer los roles de firma configurados para las plantillas\r\nCREATE POLICY \\"select_order_template_sigs_by_tenant\\"\r\nON public.order_template_signatures\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 3. RLS: INSERT\r\n-- ==========================================\r\n-- Permite definir nuevos roles de firma en las plantillas del tenant\r\nCREATE POLICY \\"insert_order_template_sigs_by_tenant\\"\r\nON public.order_template_signatures\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ==========================================\r\n-- 4. RLS: UPDATE\r\n-- ==========================================\r\n-- Permite modificar los requisitos de firma existentes\r\nCREATE POLICY \\"update_order_template_sigs_by_tenant\\"\r\nON public.order_template_signatures\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_order_template_signatures
20260415025607	{"-- ==========================================\r\n-- 8. RLS (Row Level Security) - order_template\r\n-- ==========================================\r\n\r\nALTER TABLE public.order_template ENABLE ROW LEVEL SECURITY","-- ------------------------------------------\r\n-- SELECT: Ver las plantillas del CDA\r\n-- ------------------------------------------\r\nCREATE POLICY \\"select_order_template_by_tenant\\"\r\nON public.order_template\r\nFOR SELECT\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ------------------------------------------\r\n-- INSERT: Crear nuevas plantillas\r\n-- ------------------------------------------\r\nCREATE POLICY \\"insert_order_template_by_tenant\\"\r\nON public.order_template\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)","-- ------------------------------------------\r\n-- UPDATE: Editar plantillas existentes\r\n-- ------------------------------------------\r\nCREATE POLICY \\"update_order_template_by_tenant\\"\r\nON public.order_template\r\nFOR UPDATE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)\r\nWITH CHECK (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_RLS_table_order_template
