20260415173044	{"INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)\r\nVALUES (\r\n  'tenants-public', \r\n  'tenants-public', \r\n  true, -- Público para que los logos se vean en PDFs y correos fácilmente\r\n  1048576, -- Límite de 1MB (sobra para un logo)\r\n  ARRAY['image/jpeg', 'image/png', 'image/webp'] -- Formatos modernos\r\n)\r\n--El on conflict es por si se hace un cambio en el tamaño o mime type, no haya que borrar el bucket sino solo cambiar los datos y correr la migracion\r\nON CONFLICT (id) DO UPDATE \r\nSET \r\n  file_size_limit = EXCLUDED.file_size_limit,\r\n  allowed_mime_types = EXCLUDED.allowed_mime_types","-- 2. Política: Permitir que solo administradores (authenticated) suban/borren logos\r\n-- Nota: La lectura es automática porque el bucket es public: true\r\nCREATE POLICY \\"Admins can upload logos\\"\r\nON storage.objects\r\nFOR INSERT\r\nTO authenticated\r\nWITH CHECK (\r\n  bucket_id = 'tenants-public'\r\n)","CREATE POLICY \\"Admins can update or delete logos\\"\r\nON storage.objects\r\nFOR ALL -- Cubre UPDATE y DELETE\r\nTO authenticated\r\nUSING (\r\n  bucket_id = 'tenants-public'\r\n)"}	CREATE_bucket_tenants_public
20260416012518	{"-- 1. Eliminar la columna antigua\r\nALTER TABLE public.order_template \r\nDROP COLUMN IF EXISTS applies_to_vehicle","-- 3. Agregar la nueva columna de tipo de servicio\r\nALTER TABLE public.order_template \r\nADD COLUMN service_type service_type_enum NOT NULL DEFAULT 'RTM'","-- 4. Documentar la columna para claridad del equipo\r\nCOMMENT ON COLUMN public.order_template.service_type IS 'Define si la plantilla es para RTM oficial, Preventiva o Peritaje comercial.'","-- 5. Crear un índice para búsquedas rápidas (útil cuando filtres plantillas en el dashboard)\r\nCREATE INDEX IF NOT EXISTS order_templates_service_type_idx \r\nON public.order_template (service_type)"}	DROP_and_ADD_column_table_order_templates
