20260417192503	{"CREATE OR REPLACE FUNCTION test_receive_template(p_data jsonb)\r\nRETURNS text\r\nLANGUAGE plpgsql\r\nAS $$\r\nDECLARE\r\n    v_template_name text;\r\nBEGIN\r\n    -- Extraemos el nombre directamente del JSONB para probar que funciona\r\n    v_template_name := p_data->>'template_name';\r\n\r\n    RETURN 'Conexión exitosa. Postgres recibió la plantilla: ' || v_template_name;\r\nEND;\r\n$$"}	FUNCTION_test_receive_template
20260418190339	{"-- Paso 1: Agregar la columna permitiendo nulos (para no romper los registros actuales)\r\nALTER TABLE tenants \r\nADD COLUMN logo_url TEXT","-- Paso 2: (Opcional) Si quieres que los registros actuales tengan un logo por defecto \r\n-- en lugar de NULL, ejecuta esto antes del paso 3:\r\n-- UPDATE tenants SET logo_url = 'https://tu-url.com/placeholder.png' WHERE logo_url IS NULL;\r\n\r\n-- Paso 3: Establecer el valor por defecto para los NUEVOS registros\r\nALTER TABLE tenants \r\nALTER COLUMN logo_url SET DEFAULT 'https://pixabay.com/images/download/raphaelsilva-avatar-3814049_1920.png'","-- Paso 4: Obligar a que los registros FUTUROS no sean nulos\r\n-- Nota: Para que esto funcione y los registros viejos sigan siendo NULL, \r\n-- no usamos NOT NULL (que valida a todos), sino un CHECK que solo aplique \r\n-- a los que se inserten o actualicen a partir de ahora.\r\nALTER TABLE tenants \r\nADD CONSTRAINT logo_url_not_null_check \r\nCHECK (logo_url IS NOT NULL) NOT VALID","-- El \\"NOT VALID\\" le dice a Postgres: \\"No revises los datos viejos, solo valida los nuevos\\".\r\n\r\n-- 2. (Opcional) Agregar un comentario a la columna para documentación\r\nCOMMENT ON COLUMN tenants.logo_url IS 'URL pública del logo del taller almacenado en Supabase Storage'"}	ALTER_table_tenants_addField_logoUrl
20260418191609	{"-- 1. Eliminamos la función existente para poder cambiar su tipo de retorno\r\n-- Nota: Usamos el tipo de argumento para identificarla correctamente\r\nDROP FUNCTION IF EXISTS public.get_tenant_data(text)","CREATE OR REPLACE FUNCTION public.get_tenant_data(p_tenant_slug text)\r\nRETURNS TABLE (\r\n  id uuid,\r\n  name text,\r\n  domain text,\r\n  logo_url text  -- 1. Agregamos la columna al retorno\r\n) \r\nLANGUAGE sql\r\nSTABLE\r\nSET search_path = public\r\nAS $$\r\n  SELECT id, name, domain, logo_url\r\n  FROM tenants\r\n  WHERE domain = p_tenant_slug\r\n  LIMIT 1;\r\n$$"}	ALTER_function_get_tenant_data
20260418200142	{"-- 1. Eliminar la función de prueba anterior\r\nDROP FUNCTION IF EXISTS public.test_receive_template(jsonb)","-- 2. Crear la nueva función para insertar la plantilla completa\r\nCREATE OR REPLACE FUNCTION public.create_full_order_template(p_data jsonb)\r\nRETURNS uuid -- Devolvemos el ID de la nueva plantilla\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER -- Recomendado si la llamas desde Supabase para manejar permisos\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_template_id uuid;\r\nBEGIN\r\n    -- Insertamos en la tabla principal order_template\r\n    INSERT INTO public.order_template (\r\n        tenant_id,\r\n        template_name,\r\n        version,\r\n        is_active,\r\n        document_date,\r\n        document_code,\r\n        logo_url,\r\n        base_contract_text,\r\n        service_type,\r\n        created_by\r\n    )\r\n    VALUES (\r\n        (p_data->>'tenant_id')::uuid,\r\n        (p_data->>'template_name'),\r\n        (p_data->>'version')::integer,\r\n        (p_data->>'is_active')::boolean,\r\n        (p_data->>'document_date')::date,\r\n        (p_data->>'document_code'),\r\n        (p_data->>'logo_url'),\r\n        (p_data->>'base_contract_text'),\r\n        (p_data->>'service_type')::public.service_type_enum,\r\n        (p_data->>'created_by')::uuid\r\n    )\r\n    RETURNING id INTO v_template_id;\r\n\r\n    -- Devolvemos el ID generado para que el frontend pueda redirigir o confirmar\r\n    RETURN v_template_id;\r\nEND;\r\n$$"}	DROP_test_receive_template_CREATE_create_full_order_template
20260419212513	{"-- 1. Eliminamos la versión anterior de la función\r\n-- Es necesario porque cambiamos la lógica de retorno o estructura interna\r\nDROP FUNCTION IF EXISTS public.create_full_order_template(jsonb)","-- 2. Creamos la función actualizada\r\nCREATE OR REPLACE FUNCTION public.create_full_order_template(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER \r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_template_id uuid;\r\n    v_tenant_id uuid;\r\nBEGIN\r\n    -- 0. Extraemos el tenant_id una sola vez para usarlo en ambas tablas\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n\r\n    -- 1. Insertamos en la tabla principal order_template\r\n    INSERT INTO public.order_template (\r\n        tenant_id,\r\n        template_name,\r\n        version,\r\n        is_active,\r\n        document_date,\r\n        document_code,\r\n        logo_url,\r\n        base_contract_text,\r\n        service_type,\r\n        created_by\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (p_data->>'template_name'),\r\n        (p_data->>'version')::integer,\r\n        (p_data->>'is_active')::boolean,\r\n        (p_data->>'document_date')::date,\r\n        (p_data->>'document_code'),\r\n        (p_data->>'logo_url'),\r\n        (p_data->>'base_contract_text'),\r\n        (p_data->>'service_type')::public.service_type_enum,\r\n        (p_data->>'created_by')::uuid\r\n    )\r\n    -- Este RETURNING atrapa el ID generado automáticamente por Postgres\r\n    -- y lo guarda en nuestra variable para usarlo en el siguiente paso.\r\n    RETURNING id INTO v_template_id;\r\n\r\n    -- 2. Insertamos las condiciones (Hacemos el \\"loop\\" implícito con jsonb_to_recordset)\r\n    -- \\"Inserta en esta tabla todo lo que resulte de esta consulta SELECT\\".\r\n    INSERT INTO public.order_template_conditions (\r\n        tenant_id,\r\n        order_template_id,\r\n        label,\r\n        is_special,\r\n        special_condition_label,\r\n        default_value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        t.label,\r\n        t.is_special,\r\n        t.special_condition_label,\r\n        t.default_value::public.condition_response_enum\r\n    -- Toma el array que viene en p_data->'conditions' y lo transforma en una tabla virtual 't'.\r\n    FROM jsonb_to_recordset(p_data->'conditions') AS t(\r\n        label text,\r\n        is_special boolean,\r\n        special_condition_label text,\r\n        default_value text\r\n    );\r\n\r\n    -- Devolvemos el ID de la plantilla creada al frontend\r\n    RETURN v_template_id;\r\nEND;\r\n$$"}	ALTER_function_create_full_order_template
20260419230810	\N	ALTER_function_create_full_order_template_moreFields
20260419230912	{"-- 1. Eliminamos la versión anterior de la función\r\n-- Es necesario porque cambiamos la lógica de retorno o estructura interna\r\nDROP FUNCTION IF EXISTS public.create_full_order_template(jsonb)","CREATE OR REPLACE FUNCTION public.create_full_order_template(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_template_id uuid;\r\n    v_tenant_id uuid;\r\nBEGIN\r\n    -- 0. Extraemos el tenant_id una sola vez para usarlo en ambas tablas\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n\r\n    -- 1. Insertamos en la tabla principal order_template\r\n    INSERT INTO public.order_template (\r\n        tenant_id,\r\n        template_name,\r\n        version,\r\n        is_active,\r\n        document_date,\r\n        document_code,\r\n        logo_url,\r\n        base_contract_text,\r\n        service_type,\r\n        created_by\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (p_data->>'template_name'),\r\n        (p_data->>'version')::integer,\r\n        (p_data->>'is_active')::boolean,\r\n        (p_data->>'document_date')::date,\r\n        (p_data->>'document_code'),\r\n        (p_data->>'logo_url'),\r\n        (p_data->>'base_contract_text'),\r\n        (p_data->>'service_type')::public.service_type_enum,\r\n        (p_data->>'created_by')::uuid\r\n    )\r\n    --Este returnin es lo que se le puede pedir a la nueva fila creada en order_template despues del insert.\r\n    RETURNING id INTO v_template_id;\r\n\r\n    -- 2. Insertamos las condiciones (Hacemos el loop interno con jsonb_to_recordset)\r\n    --\\"Inserta en esta tabla todo lo que resulte de esta consulta\\".\r\n    INSERT INTO public.order_template_conditions (\r\n        tenant_id,\r\n        order_template_id,\r\n        label,\r\n        is_special,\r\n        special_condition_label,\r\n        default_value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        t.label,\r\n        t.is_special,\r\n        t.special_condition_label,\r\n        t.default_value::public.condition_response_enum\r\n\r\n    --Toma el array que viene en p_data->'conditions' y lo transforma en una tabla virtual.\r\n    --p_data->'conditions': El operador -> extrae el array de condiciones como JSONB.\r\n    --AS t(...): Aquí le defines la estructura a esa tabla virtual. Le dices a Postgres: \r\n    --\\"Confía en mí, cada objeto de ese array tiene estas 4 llaves y quiero que las trates como estas columnas\\".\r\n    FROM jsonb_to_recordset(p_data->'conditions') AS t(\r\n        label text,\r\n        is_special boolean,\r\n        special_condition_label text,\r\n        default_value text\r\n    );\r\n\r\n\r\n\r\n    -- 3. Insertamos las firmas\r\n    -- Nota: Mapeamos los nombres del state (JS) a los nombres de la tabla (SQL)\r\n    INSERT INTO public.order_template_signatures (\r\n        tenant_id,\r\n        order_template_id,\r\n        representative_type,\r\n        signature_label\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        s.a_quien_representa, -- Llave en tu state de React\r\n        s.label_firma         -- Llave en tu state de React\r\n    FROM jsonb_to_recordset(p_data->'signatures') AS s(\r\n        a_quien_representa text,\r\n        label_firma text\r\n    );\r\n\r\n    -- Devolvemos el ID generado\r\n    RETURN v_template_id;\r\nEND;\r\n$$"}	ALTER_function_create_full_order_template_moreFields2
20260502215236	{"ALTER TABLE public.order_template \r\nDROP COLUMN IF EXISTS service_type","-- 1. Agregar la columna service_type a la tabla entry_orders\r\n-- La definimos como NOT NULL porque toda orden debe tener un tipo de servicio\r\nALTER TABLE public.entry_orders \r\nADD COLUMN service_type public.service_type_enum NOT NULL DEFAULT 'RTM'","-- 2. Crear un índice para optimizar búsquedas por tipo de servicio\r\n-- Útil para reportes (ej: \\"¿Cuántas RTM se hicieron este mes?\\")\r\nCREATE INDEX IF NOT EXISTS entry_orders_service_type_idx \r\nON public.entry_orders USING btree (service_type)","-- 3. (Opcional) Comentario de tabla para documentación\r\nCOMMENT ON COLUMN public.entry_orders.service_type IS 'Tipo de servicio legal o comercial asociado a esta orden de entrada'"}	ALTER_table_order_template_dropColumnServiceType
20260419235025	{"-- 1. Eliminamos la versión anterior de la función\r\n-- Es necesario porque cambiamos la lógica de retorno o estructura interna\r\nDROP FUNCTION IF EXISTS public.create_full_order_template(jsonb)","CREATE OR REPLACE FUNCTION public.create_full_order_template(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_template_id uuid;\r\n    v_tenant_id uuid;\r\n    v_signature_record jsonb;\r\n    v_signature_id uuid;\r\nBEGIN\r\n    -- 0. Extraemos el tenant_id una sola vez para usarlo en ambas tablas\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n\r\n    -- 1. Insertamos en la tabla principal order_template\r\n    INSERT INTO public.order_template (\r\n        tenant_id,\r\n        template_name,\r\n        version,\r\n        is_active,\r\n        document_date,\r\n        document_code,\r\n        logo_url,\r\n        base_contract_text,\r\n        service_type,\r\n        created_by\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (p_data->>'template_name'),\r\n        (p_data->>'version')::integer,\r\n        (p_data->>'is_active')::boolean,\r\n        (p_data->>'document_date')::date,\r\n        (p_data->>'document_code'),\r\n        (p_data->>'logo_url'),\r\n        (p_data->>'base_contract_text'),\r\n        (p_data->>'service_type')::public.service_type_enum,\r\n        (p_data->>'created_by')::uuid\r\n    )\r\n    --Este returnin es lo que se le puede pedir a la nueva fila creada en order_template despues del insert.\r\n    RETURNING id INTO v_template_id;\r\n\r\n\r\n\r\n    -- 2. Insertamos las condiciones (Hacemos el loop interno con jsonb_to_recordset)\r\n    --\\"Inserta en esta tabla todo lo que resulte de esta consulta\\".\r\n    INSERT INTO public.order_template_conditions (\r\n        tenant_id,\r\n        order_template_id,\r\n        label,\r\n        is_special,\r\n        special_condition_label,\r\n        default_value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        t.label,\r\n        t.is_special,\r\n        t.special_condition_label,\r\n        t.default_value::public.condition_response_enum\r\n\r\n    --Toma el array que viene en p_data->'conditions' y lo transforma en una tabla virtual.\r\n    --p_data->'conditions': El operador -> extrae el array de condiciones como JSONB.\r\n    --AS t(...): Aquí le defines la estructura a esa tabla virtual. Le dices a Postgres: \r\n    --\\"Confía en mí, cada objeto de ese array tiene estas 4 llaves y quiero que las trates como estas columnas\\".\r\n    FROM jsonb_to_recordset(p_data->'conditions') AS t(\r\n        label text,\r\n        is_special boolean,\r\n        special_condition_label text,\r\n        default_value text\r\n    );\r\n\r\n\r\n/*\r\n    -- 3. Insertamos las firmas\r\n    -- Nota: Mapeamos los nombres del state (JS) a los nombres de la tabla (SQL)\r\n    INSERT INTO public.order_template_signatures (\r\n        tenant_id,\r\n        order_template_id,\r\n        representative_type,\r\n        signature_label\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        s.a_quien_representa, -- Llave en tu state de React\r\n        s.label_firma         -- Llave en tu state de React\r\n    FROM jsonb_to_recordset(p_data->'signatures') AS s(\r\n        a_quien_representa text,\r\n        label_firma text\r\n    );\r\n*/\r\n\r\n\r\n-- 3. PROCESO DE FIRMAS Y DECLARACIONES\r\n    -- Iteramos sobre el array de firmas porque cada una genera un ID necesario para sus declaraciones\r\n    FOR v_signature_record IN SELECT * FROM jsonb_array_elements(p_data->'signatures')\r\n    LOOP\r\n        -- A. Insertamos la Firma actual del loop\r\n        INSERT INTO public.order_template_signatures (\r\n            tenant_id,\r\n            order_template_id,\r\n            representative_type,\r\n            signature_label\r\n        )\r\n        VALUES (\r\n            v_tenant_id,\r\n            v_template_id,\r\n            v_signature_record->>'a_quien_representa',\r\n            v_signature_record->>'label_firma'\r\n        )\r\n        RETURNING id INTO v_signature_id;\r\n\r\n        -- B. Insertamos todas las declaraciones de ESTA firma específica\r\n        -- Volvemos a la lógica masiva (SELECT) usando el ID de la firma recién creada\r\n        INSERT INTO public.order_template_signature_conditions (\r\n            tenant_id,\r\n            order_template_signature_id,\r\n            declaration_text\r\n        )\r\n        SELECT \r\n            v_tenant_id,\r\n            v_signature_id,\r\n            d.texto_declaracion\r\n        FROM jsonb_to_recordset(v_signature_record->'declarations') AS d(\r\n            texto_declaracion text\r\n        );\r\n    END LOOP;\r\n\r\n    \r\n    -- Devolvemos el ID generado\r\n    RETURN v_template_id;\r\nEND;\r\n$$"}	ALTER_function_create_full_order_template_moreFields3
20260420203653	{"CREATE OR REPLACE FUNCTION fetch_orders_templates(p_tenant_id UUID)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    tenant_id UUID,\r\n    template_name TEXT,\r\n    version INTEGER,\r\n    is_active BOOLEAN,\r\n    document_date DATE,\r\n    document_code TEXT,\r\n    logo_url TEXT,\r\n    base_contract_text TEXT,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    created_by UUID,\r\n    service_type public.service_type_enum\r\n) \r\nLANGUAGE plpgsql\r\nSECURITY DEFINER -- Permite que la función acceda a la tabla incluso con RLS estricto\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        t.id,\r\n        t.tenant_id,\r\n        t.template_name,\r\n        t.version,\r\n        t.is_active,\r\n        t.document_date,\r\n        t.document_code,\r\n        t.logo_url,\r\n        t.base_contract_text,\r\n        t.created_at,\r\n        t.updated_at,\r\n        t.created_by,\r\n        t.service_type\r\n    FROM order_template t\r\n    WHERE t.tenant_id = p_tenant_id\r\n      AND t.deleted_at IS NULL -- Filtramos los eliminados lógicamente\r\n    ORDER BY t.created_at DESC;\r\nEND;\r\n$$"}	CREATE_function_fetch_orders_templates
20260424002358	{"DROP FUNCTION IF EXISTS fetch_orders_templates(p_tenant_id UUID)","CREATE OR REPLACE FUNCTION fetch_orders_templates(p_tenant_id UUID)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    tenant_id UUID,\r\n    template_name TEXT,\r\n    version INTEGER,\r\n    is_active BOOLEAN,\r\n    document_date DATE,\r\n    document_code TEXT,\r\n    logo_url TEXT,\r\n    base_contract_text TEXT,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    created_by UUID,\r\n    service_type public.service_type_enum,\r\n    conditions JSONB -- Nueva columna para las condiciones\r\n) \r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        t.id,\r\n        t.tenant_id,\r\n        t.template_name,\r\n        t.version,\r\n        t.is_active,\r\n        t.document_date,\r\n        t.document_code,\r\n        t.logo_url,\r\n        t.base_contract_text,\r\n        t.created_at,\r\n        t.updated_at,\r\n        t.created_by,\r\n        t.service_type,\r\n        --aqui el coalesce que esta hecho para devolver el primer valor no null que se encuentre, en este caso especifico solo tendria o el array de objects\r\n        --o null, y en el caso de null pues lo convierte a un array vacio [].\r\n        COALESCE(\r\n            (\r\n                --el jsonb_agg es como un agregador que va llenando el array [] con cada object que sale de jsonb_build_object, que se ejectua por cada\r\n                --c.order_template_id = t.id que se encuentre y eso dentro de cada t.tenant_id = p_tenant_id de la consulta externa\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', c.id,\r\n                    'label', c.label,\r\n                    'is_special', c.is_special,\r\n                    'special_condition_label', c.special_condition_label,\r\n                    'default_value', c.default_value\r\n                ) ORDER BY c.created_at ASC)\r\n                FROM order_template_conditions c\r\n                --Por cada plantilla (t.id), Postgres va a la tabla de condiciones y busca todas las que le pertenecen. \r\n                --Imagina que para la \\"Plantilla A\\" encuentra 3 filas.\r\n                WHERE c.order_template_id = t.id \r\n                  AND c.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as conditions\r\n    FROM order_template t\r\n    WHERE t.tenant_id = p_tenant_id\r\n      AND t.deleted_at IS NULL\r\n    ORDER BY t.created_at DESC;\r\nEND;\r\n$$"}	ALTER_function_fetch_orders_templates_addNewfetchs
20260424170654	{"-- Eliminación de columnas de documentos de la tabla vehicles\r\nALTER TABLE public.vehicles \r\nDROP COLUMN IF EXISTS soat_vencimiento,\r\nDROP COLUMN IF EXISTS gas_numero,\r\nDROP COLUMN IF EXISTS gas_vencimiento","-- Comentario para documentar el cambio en el esquema\r\nCOMMENT ON TABLE public.vehicles IS 'Tabla de vehículos. Los datos de SOAT y Gas se gestionan ahora directamente en entry_orders para mantener trazabilidad histórica.'"}	ALTER_table_vehicles_dropcolumns
20260424184643	{"-- 1. Crear el nuevo tipo ENUM\r\nCREATE TYPE public.vehicle_service_type_enum AS ENUM (\r\n  'particular', \r\n  'enseñanza', \r\n  'oficial', \r\n  'publico', \r\n  'diplomático', \r\n  'especial'\r\n)","-- 2. Agregar la columna a la tabla vehicles\r\nALTER TABLE public.vehicles \r\nADD COLUMN tipo_servicio_vehiculo public.vehicle_service_type_enum NOT NULL DEFAULT 'particular'","-- 3. (Opcional) Crear un índice para mejorar búsquedas por tipo de servicio\r\nCREATE INDEX IF NOT EXISTS vehicles_tipo_servicio_idx ON public.vehicles (tipo_servicio_vehiculo)","-- 4. Comentario para documentar el campo\r\nCOMMENT ON COLUMN public.vehicles.tipo_servicio_vehiculo IS 'Clasificación del servicio según la tarjeta de propiedad (Particular, Público, etc.)'"}	ALTER_table_vehicles_addtypeserviceColumn
20260424202242	{"DROP FUNCTION IF EXISTS fetch_orders_templates(p_tenant_id UUID)","CREATE OR REPLACE FUNCTION fetch_orders_templates(p_tenant_id UUID)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    tenant_id UUID,\r\n    template_name TEXT,\r\n    version INTEGER,\r\n    is_active BOOLEAN,\r\n    document_date DATE,\r\n    document_code TEXT,\r\n    logo_url TEXT,\r\n    base_contract_text TEXT,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    created_by UUID,\r\n    service_type public.service_type_enum,\r\n    conditions JSONB, -- Nueva columna para las condiciones\r\n    signatures JSONB -- Nueva columna para las firmas\r\n) \r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        t.id,\r\n        t.tenant_id,\r\n        t.template_name,\r\n        t.version,\r\n        t.is_active,\r\n        t.document_date,\r\n        t.document_code,\r\n        t.logo_url,\r\n        t.base_contract_text,\r\n        t.created_at,\r\n        t.updated_at,\r\n        t.created_by,\r\n        t.service_type,\r\n        --aqui el coalesce que esta hecho para devolver el primer valor no null que se encuentre, en este caso especifico solo tendria o el array de objects\r\n        --o null, y en el caso de null pues lo convierte a un array vacio [].\r\n        COALESCE(\r\n            (\r\n                --el jsonb_agg es como un agregador que va llenando el array [] con cada object que sale de jsonb_build_object, que se ejectua por cada\r\n                --c.order_template_id = t.id que se encuentre y eso dentro de cada t.tenant_id = p_tenant_id de la consulta externa\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', c.id,\r\n                    'label', c.label,\r\n                    'is_special', c.is_special,\r\n                    'special_condition_label', c.special_condition_label,\r\n                    'default_value', c.default_value\r\n                ) ORDER BY c.created_at ASC)\r\n                FROM order_template_conditions c\r\n                --Por cada plantilla (t.id), Postgres va a la tabla de condiciones y busca todas las que le pertenecen. \r\n                --Imagina que para la \\"Plantilla A\\" encuentra 3 filas.\r\n                WHERE c.order_template_id = t.id \r\n                  AND c.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as conditions,\r\n        -- Subconsulta para Firmas (Agregada)\r\n        COALESCE(\r\n            (\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', s.id,\r\n                    'representative_type', s.representative_type,\r\n                    'signature_label', s.signature_label\r\n                ) ORDER BY s.created_at ASC)\r\n                FROM order_template_signatures s\r\n                WHERE s.order_template_id = t.id \r\n                  AND s.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as signatures\r\n    FROM order_template t\r\n    WHERE t.tenant_id = p_tenant_id\r\n      AND t.deleted_at IS NULL\r\n    ORDER BY t.created_at DESC;\r\nEND;\r\n$$"}	ALTER_function_fetch_orders_templates_addQuery
20260519171008	{"ALTER TABLE public.entry_orders \r\n    ALTER COLUMN consecutivo DROP DEFAULT,\r\n    ALTER COLUMN consecutivo TYPE integer"}	ALTER_table_entry_orders_DROPserial
20260425172901	{"DROP FUNCTION IF EXISTS fetch_orders_templates(p_tenant_id UUID)","CREATE OR REPLACE FUNCTION fetch_orders_templates(p_tenant_id UUID)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    tenant_id UUID,\r\n    template_name TEXT,\r\n    version INTEGER,\r\n    is_active BOOLEAN,\r\n    document_date DATE,\r\n    document_code TEXT,\r\n    logo_url TEXT,\r\n    base_contract_text TEXT,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    created_by UUID,\r\n    service_type public.service_type_enum,\r\n    conditions JSONB,-- Nueva columna para las condiciones\r\n    signatures JSONB -- Nueva columna para las firmas\r\n) \r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        t.id,\r\n        t.tenant_id,\r\n        t.template_name,\r\n        t.version,\r\n        t.is_active,\r\n        t.document_date,\r\n        t.document_code,\r\n        t.logo_url,\r\n        t.base_contract_text,\r\n        t.created_at,\r\n        t.updated_at,\r\n        t.created_by,\r\n        t.service_type,\r\n        -- 1. AGREGACIÓN DE CONDICIONES DE LA PLANTILLA\r\n        --aqui el coalesce que esta hecho para devolver el primer valor no null que se encuentre, en este caso especifico solo tendria o el array de objects\r\n        --o null, y en el caso de null pues lo convierte a un array vacio [].\r\n        COALESCE(\r\n            (\r\n                --el jsonb_agg es como un agregador que va llenando el array [] con cada object que sale de jsonb_build_object, que se ejectua por cada\r\n                --c.order_template_id = t.id que se encuentre y eso dentro de cada t.tenant_id = p_tenant_id de la consulta externa\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', c.id,\r\n                    'label', c.label,\r\n                    'is_special', c.is_special,\r\n                    'special_condition_label', c.special_condition_label,\r\n                    'default_value', c.default_value\r\n                ) ORDER BY c.created_at ASC)\r\n                FROM order_template_conditions c\r\n                --Por cada plantilla (t.id), Postgres va a la tabla de condiciones y busca todas las que le pertenecen. \r\n                --Imagina que para la \\"Plantilla A\\" encuentra 3 filas.\r\n                WHERE c.order_template_id = t.id \r\n                  AND c.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as conditions,\r\n        -- 2. AGREGACIÓN DE FIRMAS CON SUS DECLARACIONES (ANIDADO)\r\n        -- Subconsulta para Firmas (Agregada)\r\n        COALESCE(\r\n            (\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', s.id,\r\n                    'representative_type', s.representative_type,\r\n                    'signature_label', s.signature_label,\r\n                    -- Sub-agregación de condiciones/declaraciones por firma\r\n                    'declarations', COALESCE(\r\n                        (\r\n                            SELECT jsonb_agg(jsonb_build_object(\r\n                                'id', sc.id,\r\n                                'declaration_text', sc.declaration_text\r\n                            ) ORDER BY sc.created_at ASC)\r\n                            FROM order_template_signature_conditions sc\r\n                            WHERE sc.order_template_signature_id = s.id\r\n                              AND sc.deleted_at IS NULL\r\n                        ),\r\n                        '[]'::jsonb\r\n                    )\r\n                ) ORDER BY s.created_at ASC)\r\n                FROM order_template_signatures s\r\n                WHERE s.order_template_id = t.id \r\n                  AND s.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as signatures\r\n    FROM order_template t\r\n    WHERE t.tenant_id = p_tenant_id\r\n      AND t.deleted_at IS NULL\r\n    ORDER BY t.created_at DESC;\r\nEND;\r\n$$"}	ALTER_function_fetch_orders_templates_addquery
20260429190907	{"-- 1. Eliminamos la restricción anterior que limitaba a un solo rol por usuario/tenant\r\nALTER TABLE public.tenant_permissions \r\nDROP CONSTRAINT IF EXISTS tenant_permissions_unique_pair","-- 2. Creamos la nueva restricción de triplete único\r\n-- Esto permite:\r\n-- (Tenant A, Usuario 1, 'recepcionista') -> OK\r\n-- (Tenant A, Usuario 1, 'director_tecnico') -> OK (Diferente rol)\r\n-- (Tenant A, Usuario 1, 'recepcionista') -> ERROR (Ya existe este triplete exacto)\r\nALTER TABLE public.tenant_permissions \r\nADD CONSTRAINT tenant_permissions_unique_triplet \r\nUNIQUE (tenant_id, service_user_id, role)"}	ALTER_table_tenant_permissions_addRoleConstrain
20260429195626	{"CREATE OR REPLACE FUNCTION public.get_tenant_roles(p_tenant_id uuid)\r\nRETURNS text[] AS $$\r\nDECLARE\r\n  v_service_user_id uuid;\r\n  v_roles_array text[];\r\nBEGIN\r\n  -- 1. Obtenemos el ID de nuestra tabla de negocio 'service_users' \r\n  -- usando el ID de autenticación del JWT (auth.uid())\r\n  SELECT id INTO v_service_user_id \r\n  FROM public.service_users \r\n  WHERE auth_user_id = auth.uid();\r\n\r\n  -- 2. Si no encontramos un usuario de servicio, retornamos un array vacío\r\n  IF v_service_user_id IS NULL THEN\r\n    RETURN ARRAY[]::text[];\r\n  END IF;\r\n\r\n  -- 3. Buscamos todos los roles asignados a ese usuario en ESE tenant específico\r\n  SELECT array_agg(role) INTO v_roles_array\r\n  FROM public.tenant_permissions\r\n  WHERE service_user_id = v_service_user_id \r\n    AND tenant_id = p_tenant_id;\r\n\r\n  -- 4. Retornamos el array (o un array vacío si no tiene permisos)\r\n  RETURN COALESCE(v_roles_array, ARRAY[]::text[]);\r\nEND;\r\n$$ LANGUAGE plpgsql SECURITY DEFINER"}	CREATE_function_get_tenant_roles
20260501213911	{"DROP FUNCTION IF EXISTS public.get_service_users_with_tenant(target_tenant_id uuid)","DROP TRIGGER IF EXISTS tr_comments_derive_tenant ON public.comments","DROP TRIGGER IF EXISTS set_comments_updated_at ON public.comments","DROP TRIGGER IF EXISTS trg_comments_autoset_author_name ON public.comments","DROP TRIGGER IF EXISTS tr_comments_autoset_created_by ON public.comments","DROP TRIGGER IF EXISTS tr_set_comments_attachments_updated_at ON public.comment_attachments","-- 1. Eliminar el trigger de actualización automática de fecha\r\nDROP TRIGGER IF EXISTS set_tickets_updated_at ON public.tickets","-- 2. Eliminar el trigger que asigna el autor (creador)\r\nDROP TRIGGER IF EXISTS tr_set_author ON public.tickets","-- 3. Eliminar el trigger que genera el número secuencial de ticket\r\nDROP TRIGGER IF EXISTS tr_set_ticket_number ON public.tickets","-- 4. Eliminar el trigger que asigna el nombre del responsable (assignee)\r\nDROP TRIGGER IF EXISTS trg_set_ticket_assignee_name ON public.tickets","DROP FUNCTION IF EXISTS public.derive_tenant_from_ticket()","DROP FUNCTION IF EXISTS public.set_comment_author_name()","DROP FUNCTION IF EXISTS public.set_created_by_value()","DROP FUNCTION IF EXISTS public.set_created_by_table_tickets()","DROP FUNCTION IF EXISTS public.set_next_ticket_number()","DROP FUNCTION IF EXISTS public.set_ticket_assignee_name()"}	DROP_tickets_functions
