20260501220533	{"-- 1. Eliminar las políticas de RLS (Opcional si vas a borrar la tabla, pero útil para limpieza selectiva)\r\nDROP POLICY IF EXISTS \\"Users can see tickets from their tenants\\" ON public.tickets","DROP POLICY IF EXISTS \\"Users can create tickets in their tenants\\" ON public.tickets","DROP POLICY IF EXISTS \\"Authors can update their own tickets\\" ON public.tickets","DROP POLICY IF EXISTS \\"Users can delete own tickets\\" ON public.tickets","-- 2. Eliminar la tabla (Esto borra automáticamente índices, particiones y grants)\r\nDROP TABLE IF EXISTS public.tickets CASCADE"}	DROP_tickets_tables
20260501220729	{"-- 1. Eliminar las políticas de RLS\r\nDROP POLICY IF EXISTS \\"Users can see comments from their tenants\\" ON public.comments","DROP POLICY IF EXISTS \\"Users can insert comments in their tenants\\" ON public.comments","DROP POLICY IF EXISTS \\"Users can delete comments from their tenats\\" ON public.comments","-- 2. Eliminar la tabla (esto borra automáticamente los índices y los grants)\r\nDROP TABLE IF EXISTS public.comments CASCADE","-- 1. Eliminar las políticas de RLS\r\nDROP POLICY IF EXISTS \\"Users can see attachments from their tenants\\" ON public.comment_attachments","DROP POLICY IF EXISTS \\"Users can insert attachments into their tenants\\" ON public.comment_attachments","-- 2. Eliminar la tabla (esto borra índices, comentarios de tabla y grants automáticamente)\r\nDROP TABLE IF EXISTS public.comment_attachments CASCADE"}	DROP_tickets_tables2
20260502201346	{"-- 1. Renombrar el ENUM actual (el que tiene los valores que no quieres)\r\nALTER TYPE public.vehicle_type_enum RENAME TO vehicle_type_enum_old","-- 2. Crear el ENUM nuevo con la lista perfecta\r\nCREATE TYPE public.vehicle_type_enum AS ENUM (\r\n  'liviano', \r\n  'pesado', \r\n  'motocicleta_4t', \r\n  'motocicleta_2t', \r\n  'motocarro_4t', \r\n  'motocarro_2t'\r\n)","-- 3. Actualizar la tabla Vehicles para que use el NUEVO tipo\r\n-- El \\"USING\\" es la clave: convierte el valor viejo a texto y luego al nuevo enum\r\nALTER TABLE public.vehicles \r\n  ALTER COLUMN tipo_vehiculo TYPE public.vehicle_type_enum \r\n  USING tipo_vehiculo::text::public.vehicle_type_enum","-- 4. Ahora que la tabla Vehicles ya no usa el viejo, puedes borrarlo\r\nDROP TYPE public.vehicle_type_enum_old"}	ALTER_enum_vehicle_type_enum
