20260502220917	{"DROP FUNCTION IF EXISTS public.create_full_order_template(jsonb)","CREATE OR REPLACE FUNCTION public.create_full_order_template(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_template_id uuid;\r\n    v_tenant_id uuid;\r\n    v_signature_record jsonb;\r\n    v_signature_id uuid;\r\nBEGIN\r\n    -- 0. Extraemos el tenant_id una sola vez para usarlo en ambas tablas\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n\r\n    -- 1. Insertamos en la tabla principal order_template\r\n    INSERT INTO public.order_template (\r\n        tenant_id,\r\n        template_name,\r\n        version,\r\n        is_active,\r\n        document_date,\r\n        document_code,\r\n        logo_url,\r\n        base_contract_text,\r\n        created_by\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (p_data->>'template_name'),\r\n        (p_data->>'version')::integer,\r\n        (p_data->>'is_active')::boolean,\r\n        (p_data->>'document_date')::date,\r\n        (p_data->>'document_code'),\r\n        (p_data->>'logo_url'),\r\n        (p_data->>'base_contract_text'),\r\n        (p_data->>'created_by')::uuid\r\n    )\r\n    --Este returnin es lo que se le puede pedir a la nueva fila creada en order_template despues del insert.\r\n    RETURNING id INTO v_template_id;\r\n\r\n\r\n\r\n    -- 2. Insertamos las condiciones (Hacemos el loop interno con jsonb_to_recordset)\r\n    --\\"Inserta en esta tabla todo lo que resulte de esta consulta\\".\r\n    INSERT INTO public.order_template_conditions (\r\n        tenant_id,\r\n        order_template_id,\r\n        label,\r\n        is_special,\r\n        special_condition_label,\r\n        default_value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        t.label,\r\n        t.is_special,\r\n        t.special_condition_label,\r\n        t.default_value::public.condition_response_enum\r\n\r\n    --Toma el array que viene en p_data->'conditions' y lo transforma en una tabla virtual.\r\n    --p_data->'conditions': El operador -> extrae el array de condiciones como JSONB.\r\n    --AS t(...): Aquí le defines la estructura a esa tabla virtual. Le dices a Postgres: \r\n    --\\"Confía en mí, cada objeto de ese array tiene estas 4 llaves y quiero que las trates como estas columnas\\".\r\n    FROM jsonb_to_recordset(p_data->'conditions') AS t(\r\n        label text,\r\n        is_special boolean,\r\n        special_condition_label text,\r\n        default_value text\r\n    );\r\n\r\n\r\n/*\r\n    -- 3. Insertamos las firmas\r\n    -- Nota: Mapeamos los nombres del state (JS) a los nombres de la tabla (SQL)\r\n    INSERT INTO public.order_template_signatures (\r\n        tenant_id,\r\n        order_template_id,\r\n        representative_type,\r\n        signature_label\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        s.a_quien_representa, -- Llave en tu state de React\r\n        s.label_firma         -- Llave en tu state de React\r\n    FROM jsonb_to_recordset(p_data->'signatures') AS s(\r\n        a_quien_representa text,\r\n        label_firma text\r\n    );\r\n*/\r\n\r\n\r\n-- 3. PROCESO DE FIRMAS Y DECLARACIONES\r\n    -- Iteramos sobre el array de firmas porque cada una genera un ID necesario para sus declaraciones\r\n    FOR v_signature_record IN SELECT * FROM jsonb_array_elements(p_data->'signatures')\r\n    LOOP\r\n        -- A. Insertamos la Firma actual del loop\r\n        INSERT INTO public.order_template_signatures (\r\n            tenant_id,\r\n            order_template_id,\r\n            representative_type,\r\n            signature_label\r\n        )\r\n        VALUES (\r\n            v_tenant_id,\r\n            v_template_id,\r\n            v_signature_record->>'a_quien_representa',\r\n            v_signature_record->>'label_firma'\r\n        )\r\n        RETURNING id INTO v_signature_id;\r\n\r\n        -- B. Insertamos todas las declaraciones de ESTA firma específica\r\n        -- Volvemos a la lógica masiva (SELECT) usando el ID de la firma recién creada\r\n        INSERT INTO public.order_template_signature_conditions (\r\n            tenant_id,\r\n            order_template_signature_id,\r\n            declaration_text\r\n        )\r\n        SELECT \r\n            v_tenant_id,\r\n            v_signature_id,\r\n            d.texto_declaracion\r\n        FROM jsonb_to_recordset(v_signature_record->'declarations') AS d(\r\n            texto_declaracion text\r\n        );\r\n    END LOOP;\r\n\r\n    \r\n    -- Devolvemos el ID generado\r\n    RETURN v_template_id;\r\nEND;\r\n$$"}	ALTER_function_create_full_order_template_dropServiceType
20260502221316	{"DROP FUNCTION IF EXISTS public.fetch_orders_templates(uuid)","CREATE OR REPLACE FUNCTION fetch_orders_templates(p_tenant_id UUID)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    tenant_id UUID,\r\n    template_name TEXT,\r\n    version INTEGER,\r\n    is_active BOOLEAN,\r\n    document_date DATE,\r\n    document_code TEXT,\r\n    logo_url TEXT,\r\n    base_contract_text TEXT,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    created_by UUID,\r\n    conditions JSONB,\r\n    signatures JSONB \r\n) \r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        t.id,\r\n        t.tenant_id,\r\n        t.template_name,\r\n        t.version,\r\n        t.is_active,\r\n        t.document_date,\r\n        t.document_code,\r\n        t.logo_url,\r\n        t.base_contract_text,\r\n        t.created_at,\r\n        t.updated_at,\r\n        t.created_by,\r\n        -- 1. AGREGACIÓN DE CONDICIONES DE LA PLANTILLA\r\n        --aqui el coalesce que esta hecho para devolver el primer valor no null que se encuentre, en este caso especifico solo tendria o el array de objects\r\n        --o null, y en el caso de null pues lo convierte a un array vacio [].\r\n        COALESCE(\r\n            (\r\n                 --el jsonb_agg es como un agregador que va llenando el array [] con cada object que sale de jsonb_build_object, que se ejectua por cada\r\n                --c.order_template_id = t.id que se encuentre y eso dentro de cada t.tenant_id = p_tenant_id de la consulta externa\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', c.id,\r\n                    'label', c.label,\r\n                    'is_special', c.is_special,\r\n                    'special_condition_label', c.special_condition_label,\r\n                    'default_value', c.default_value\r\n                ) ORDER BY c.created_at ASC)\r\n                FROM order_template_conditions c\r\n                --Por cada plantilla (t.id), Postgres va a la tabla de condiciones y busca todas las que le pertenecen. \r\n                --Imagina que para la \\"Plantilla A\\" encuentra 3 filas.\r\n                WHERE c.order_template_id = t.id \r\n                  AND c.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as conditions,\r\n        -- 2. AGREGACIÓN DE FIRMAS CON SUS DECLARACIONES (ANIDADO)\r\n        -- Subconsulta para Firmas (Agregada)\r\n        COALESCE(\r\n            (\r\n                SELECT jsonb_agg(jsonb_build_object(\r\n                    'id', s.id,\r\n                    'representative_type', s.representative_type,\r\n                    'signature_label', s.signature_label,\r\n                    -- Sub-agregación de condiciones/declaraciones por firma\r\n                    'declarations', COALESCE(\r\n                        (\r\n                            SELECT jsonb_agg(jsonb_build_object(\r\n                                'id', sc.id,\r\n                                'declaration_text', sc.declaration_text\r\n                            ) ORDER BY sc.created_at ASC)\r\n                            FROM order_template_signature_conditions sc\r\n                            WHERE sc.order_template_signature_id = s.id\r\n                              AND sc.deleted_at IS NULL\r\n                        ),\r\n                        '[]'::jsonb\r\n                    )\r\n                ) ORDER BY s.created_at ASC)\r\n                FROM order_template_signatures s\r\n                WHERE s.order_template_id = t.id \r\n                  AND s.deleted_at IS NULL\r\n            ), \r\n            '[]'::jsonb\r\n        ) as signatures\r\n    FROM order_template t\r\n    WHERE t.tenant_id = p_tenant_id\r\n      AND t.deleted_at IS NULL\r\n    ORDER BY t.created_at DESC;\r\nEND;\r\n$$"}	ALTER_function_fetch_orders_templates_dropServiceType
20260506183206	{"ALTER TABLE public.vehicles\r\nADD COLUMN es_extranjero boolean NOT NULL DEFAULT false"}	ALTER_table_vehicles_addextrangeroColumn
20260509175534	{"-- 1. Eliminamos la columna redundante\r\nALTER TABLE public.entry_order_tire_pressures \r\nDROP COLUMN IF EXISTS es_repuesto","-- 2. (Opcional pero recomendado) Añadimos una restricción para asegurar \r\n-- que la posición solo acepte valores válidos, incluyendo 'repuesto'\r\nALTER TABLE public.entry_order_tire_pressures\r\nADD CONSTRAINT check_tire_position \r\nCHECK (posicion IN ('izquierda', 'derecha', 'repuesto', 'interno_izquierdo', 'interno_derecho'))","-- 3. Comentario para documentar el cambio en la tabla\r\nCOMMENT ON COLUMN public.entry_order_tire_pressures.posicion IS 'Posición de la llanta: izquierda, derecha o repuesto'"}	ALTER_entry_order_tire_pressures_DROPis_repuesto
20260510212511	{"-- 1. Eliminamos la columna special_value\r\nALTER TABLE public.order_condition_results \r\nDROP COLUMN IF EXISTS special_value"}	ALTER_order_condition_results_DROP_specialvaluecolumn
20260516171927	{"-- 1. Eliminamos el constraint viejo para que no haga estorbo\r\nALTER TABLE public.order_template \r\n    DROP CONSTRAINT IF EXISTS order_template_name_version_tenant_key","-- 2. Creamos el nuevo constraint incluyendo el document_code\r\nALTER TABLE public.order_template\r\n    ADD CONSTRAINT order_template_name_version_code_tenant_key \r\n    UNIQUE (tenant_id, template_name, version, document_code)"}	ALTER_table_order_template_ADDConstrainInuniqueness
20260516172355	{"-- Eliminamos el constraint viejo para que no haga estorbo\r\nALTER TABLE public.order_template \r\n    DROP CONSTRAINT IF EXISTS order_template_name_version_code_tenant_key","-- Evita que se repita la combinación de Código + Versión por cada CDA (tenant_id)\r\nALTER TABLE public.order_template\r\n    ADD CONSTRAINT order_template_code_version_tenant_key \r\n    UNIQUE (tenant_id, document_code, version)","--  Creamos TU restricción exacta: Nombre + Versión + Código Únicos por Tenant\r\nALTER TABLE public.order_template\r\n    ADD CONSTRAINT order_template_name_version_code_tenant_key \r\n    UNIQUE (tenant_id, template_name, version, document_code)"}	ALTER_table_order_template_ADDConstrainInuniquenes2
20260518225934	{"ALTER TABLE public.vehicles\r\n    -- Datos de identificación y aspecto\r\n    ALTER COLUMN marca SET NOT NULL,\r\n    ALTER COLUMN linea SET NOT NULL,\r\n    ALTER COLUMN modelo SET NOT NULL,\r\n    ALTER COLUMN color SET NOT NULL,\r\n    \r\n    -- Características técnicas del RUNT\r\n    ALTER COLUMN clase SET NOT NULL,\r\n    ALTER COLUMN combustible SET NOT NULL,\r\n    ALTER COLUMN cilindrada SET NOT NULL,\r\n    \r\n    -- Atributos específicos e indicadores\r\n    ALTER COLUMN blindaje SET NOT NULL,\r\n    ALTER COLUMN capacidad_pasajeros SET NOT NULL,\r\n    ALTER COLUMN es_ensenanza SET NOT NULL","-- ⚠️ NOTA SOBRE PROPIETARIO: No le aplicamos NOT NULL aquí. \r\n   \r\n\r\nCOMMIT"}	ALTER_table_vehicles_addNOTnulltoAll
20260519165125	{"-- =========================================================================\r\n-- 2. ELIMINACIÓN DEL CONSTRAINT ANTERIOR\r\n-- =========================================================================\r\nALTER TABLE public.entry_order_tire_pressures\r\n    DROP CONSTRAINT IF EXISTS check_tire_position","-- =========================================================================\r\n-- 3. APLICACIÓN DEL NUEVO CONSTRAINT (Alineado con tu Frontend)\r\n-- =========================================================================\r\nALTER TABLE public.entry_order_tire_pressures\r\n    ADD CONSTRAINT check_tire_position CHECK (\r\n        posicion::text = ANY (\r\n            ARRAY[\r\n                'izquierda'::text,\r\n                'derecha'::text,\r\n                'centro'::text,\r\n                'izquierda_interior'::text,\r\n                'derecha_interior'::text,\r\n                'repuesto'::text\r\n            ]\r\n        )\r\n    )"}	ALTER_table_entry_order_tire_pressures_CHANGEconstrains
20260519204926	{"-- 1. CREACIÓN DE LA FUNCIÓN MAESTRA CON BLINDAJE TOTAL ANTI-NULL\r\nCREATE OR REPLACE FUNCTION public.create_full_order(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_order_id uuid;\r\n    v_tenant_id uuid;\r\n    v_input_id uuid;\r\n    v_consecutivo integer;\r\n    \r\n    -- Variables para almacenar los IDs de las relaciones\r\n    v_propietario_id uuid;\r\n    v_cliente_id uuid;\r\n    v_vehiculo_id uuid;\r\n    \r\n    -- Atajos para navegar los objetos anidados del JSONB\r\n    v_vehicle_json jsonb;\r\n    v_customer_json jsonb;\r\n    v_owner_json jsonb;\r\n    v_conditions_json jsonb;\r\n    v_signatures_json jsonb;\r\nBEGIN\r\n    -- =========================================================================\r\n    -- PASO 0: INICIALIZACIÓN DE VARIABLES Y ATAJOS\r\n    -- =========================================================================\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n    v_input_id := (p_data->>'id')::uuid; \r\n    v_vehicle_json := p_data->'vehicle';\r\n    v_customer_json := p_data->'customer_data';\r\n    v_owner_json := p_data->'owner_data';\r\n    v_conditions_json := p_data->'condition_results';\r\n    v_signatures_json := p_data->'signatures';\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 0.1: CÁLCULO DEL CONSECUTIVO POR TENANT (Solo en Creación)\r\n    -- =========================================================================\r\n    --Si el id no es null y se encuentra presente, entonces asignar a la variable v_consecutivo el consecutivo que ya existia.\r\n    IF v_input_id IS NOT NULL AND EXISTS (SELECT 1 FROM public.entry_orders WHERE id = v_input_id) THEN\r\n        SELECT consecutivo INTO v_consecutivo FROM public.entry_orders WHERE id = v_input_id;\r\n        --de lo contrario coger el maximo del consecutivo que ya existe, sumarle uno y mandarlo a la insercion de la columna correspondiente\r\n    ELSE\r\n        SELECT COALESCE(MAX(consecutivo), 0) + 1 \r\n        INTO v_consecutivo \r\n        FROM public.entry_orders \r\n        WHERE tenant_id = v_tenant_id;\r\n    END IF;\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 1: PROCESO DEL CLIENTE (customer_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_customer_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_customer_json->>'numero_documento'),\r\n        (v_customer_json->>'nombre_completo'),\r\n        NULLIF(v_customer_json->>'telefono', ''),\r\n        NULLIF(v_customer_json->>'correo', ''),\r\n        NULLIF(v_customer_json->>'direccion', '')\r\n    )\r\n    --si hay un conflicto con esactamente esos tres valores, entonces ejecutar el update\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n    -- Quitamos el RETURNING directo de este bloque para evitar el bug del NULL y lo rescatamos con SELECT seguro:\r\n    --seleccionamos el id directamente por medio de un select con las condiciones aqui presentes\r\n    SELECT id INTO v_cliente_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_customer_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_customer_json->>'numero_documento');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 2: PROCESO DEL PROPIETARIO (owner_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_owner_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_owner_json->>'numero_documento'),\r\n        (v_owner_json->>'nombre_completo'),\r\n        NULLIF(v_owner_json->>'telefono', ''),\r\n        NULLIF(v_owner_json->>'correo', ''),\r\n        NULLIF(v_owner_json->>'direccion', '')\r\n    )\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n    -- Rescate seguro del ID del propietario por su llave única:\r\n\r\n    SELECT id INTO v_propietario_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_owner_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_owner_json->>'numero_documento');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 3: PROCESO DEL VEHÍCULO\r\n    -- =========================================================================\r\n    INSERT INTO public.vehicles (\r\n        tenant_id,\r\n        placa,\r\n        marca,\r\n        linea,\r\n        modelo,\r\n        color,\r\n        tipo_vehiculo,\r\n        clase,\r\n        combustible,\r\n        cilindrada, \r\n        blindaje,\r\n        capacidad_pasajeros,\r\n        es_ensenanza,\r\n        es_extranjero,\r\n        tipo_servicio_vehiculo,\r\n        propietario_actual_id\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        UPPER(v_vehicle_json->>'placa'),\r\n        (v_vehicle_json->>'marca'),\r\n        (v_vehicle_json->>'linea'),\r\n        (v_vehicle_json->>'modelo')::integer,\r\n        (v_vehicle_json->>'color'),\r\n        (v_vehicle_json->>'tipo_vehiculo')::public.vehicle_type_enum,\r\n        (v_vehicle_json->>'clase'),\r\n        (v_vehicle_json->>'combustible'),\r\n        (v_vehicle_json->>'cilindrada')::integer, \r\n        (v_vehicle_json->>'blindaje')::boolean,\r\n        (v_vehicle_json->>'capacidad_pasajeros')::integer,\r\n        (v_vehicle_json->>'es_ensenanza')::boolean,\r\n        (v_vehicle_json->>'es_extranjero')::boolean,\r\n        (v_vehicle_json->>'tipo_servicio_vehiculo')::public.vehicle_service_type_enum,\r\n        v_propietario_id -- Pasa el v_propietario_id rescatado limpiamente arriba\r\n    )\r\n    ON CONFLICT (tenant_id, placa) \r\n    DO UPDATE SET\r\n        marca = EXCLUDED.marca,\r\n        linea = EXCLUDED.linea,\r\n        modelo = EXCLUDED.modelo,\r\n        color = EXCLUDED.color,\r\n        tipo_vehiculo = EXCLUDED.tipo_vehiculo,\r\n        clase = EXCLUDED.clase,\r\n        combustible = EXCLUDED.combustible,\r\n        cilindrada = EXCLUDED.cilindrada, \r\n        blindaje = EXCLUDED.blindaje,\r\n        capacidad_pasajeros = EXCLUDED.capacidad_pasajeros,\r\n        es_ensenanza = EXCLUDED.es_ensenanza,\r\n        es_extranjero = EXCLUDED.es_extranjero,\r\n        tipo_servicio_vehiculo = EXCLUDED.tipo_servicio_vehiculo,\r\n        propietario_actual_id = EXCLUDED.propietario_actual_id;\r\n    -- Rescate seguro del ID del vehículo por su llave única:\r\n\r\n    SELECT id INTO v_vehiculo_id \r\n    FROM public.vehicles \r\n    WHERE tenant_id = v_tenant_id \r\n      AND placa = UPPER(v_vehicle_json->>'placa');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 4: PROCESO DE LA ORDEN DE ENTRADA (Con todas las variables garantizadas)\r\n    -- =========================================================================\r\n    INSERT INTO public.entry_orders (\r\n        id,\r\n        tenant_id,\r\n        consecutivo,\r\n        vehiculo_id,\r\n        propietario_id,\r\n        cliente_id,\r\n        funcionario_id,\r\n        plantilla_id,\r\n        kilometraje,\r\n        es_reinspeccion,\r\n        observaciones,\r\n        estado_orden,\r\n        soat_vencimiento_snapshot,\r\n        gas_numero_snapshot,\r\n        gas_vencimiento_snapshot,\r\n        texto_contractual_snapshot,\r\n        service_type\r\n    )\r\n    VALUES (\r\n        COALESCE(v_input_id, gen_random_uuid()),\r\n        v_tenant_id,\r\n        v_consecutivo,\r\n        v_vehiculo_id,    -- Real, asegurado por el SELECT previo\r\n        v_propietario_id, -- Real, asegurado por el SELECT previo\r\n        v_cliente_id,     -- Real, asegurado por el SELECT previo\r\n        (p_data->>'funcionario_id')::uuid,\r\n        (p_data->>'plantilla_id')::uuid,\r\n        (p_data->>'kilometraje'),\r\n        COALESCE((p_data->>'es_reinspeccion')::boolean, false),\r\n        (p_data->>'observaciones'),\r\n        COALESCE((p_data->>'estado_orden')::public.order_status_enum, 'abierta'::public.order_status_enum),\r\n        \r\n        NULLIF(p_data->>'soat_vencimiento_snapshot', '')::date,\r\n        (p_data->>'gas_numero_snapshot'),\r\n        NULLIF(p_data->>'gas_vencimiento_snapshot', '')::date,\r\n        \r\n        (p_data->>'texto_contractual_snapshot'),\r\n        COALESCE((p_data->>'service_type')::public.service_type_enum, 'RTM'::public.service_type_enum)\r\n    )\r\n    ON CONFLICT (id) \r\n    DO UPDATE SET\r\n        vehiculo_id = EXCLUDED.vehiculo_id,\r\n        propietario_id = EXCLUDED.propietario_id,\r\n        cliente_id = EXCLUDED.cliente_id,\r\n        funcionario_id = EXCLUDED.funcionario_id,\r\n        kilometraje = EXCLUDED.kilometraje,\r\n        es_reinspeccion = EXCLUDED.es_reinspeccion,\r\n        observaciones = EXCLUDED.observaciones,\r\n        estado_orden = EXCLUDED.estado_orden,\r\n        soat_vencimiento_snapshot = EXCLUDED.soat_vencimiento_snapshot,\r\n        gas_numero_snapshot = EXCLUDED.gas_numero_snapshot,\r\n        gas_vencimiento_snapshot = EXCLUDED.gas_vencimiento_snapshot,\r\n        texto_contractual_snapshot = EXCLUDED.texto_contractual_snapshot,\r\n        service_type = EXCLUDED.service_type\r\n    RETURNING id INTO v_order_id;\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 5: PROCESO DETALLE - PRESIONES DE LLANTAS (tire_pressures)\r\n    -- =========================================================================\r\n    DELETE FROM public.entry_order_tire_pressures \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    INSERT INTO public.entry_order_tire_pressures (\r\n        tenant_id,\r\n        entry_order_id,\r\n        eje,\r\n        posicion,\r\n        presion_encontrada,\r\n        presion_ajustada\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        t.eje,\r\n        t.posicion,\r\n        NULLIF(t.presion_encontrada, '')::numeric,\r\n        NULLIF(t.presion_ajustada, '')::numeric\r\n    FROM jsonb_to_recordset(p_data->'tire_pressures') AS t(\r\n        eje integer,\r\n        posicion character varying,\r\n        presion_encontrada character varying,\r\n        presion_ajustada character varying\r\n    );\r\n\r\n    \r\n    -- =========================================================================\r\n    -- PASO 6: PROCESO DETALLE - CONDICIONES DE RECEPCIÓN (conditions - Masivo)\r\n    -- =========================================================================\r\n    -- En caso de edición, limpiamos los resultados previos para esta orden\r\n    DELETE FROM public.order_condition_results \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    -- Inserción masiva transformando el arreglo JSON en registros SQL reales\r\n    INSERT INTO public.order_condition_results (\r\n        tenant_id,\r\n        entry_order_id,\r\n        template_condition_id,\r\n        value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        c.template_condition_id,\r\n        c.value::public.condition_response_enum\r\n    FROM jsonb_to_recordset(v_conditions_json) AS c(\r\n        template_condition_id uuid,\r\n        value character varying\r\n    );\r\n\r\n\r\n-- =========================================================================\r\n    -- ➕ PASO 7: PROCESO DETALLE - FIRMAS DE LA ORDEN (signatures - Masivo)\r\n    -- =========================================================================\r\n    -- En caso de edición, limpiamos las firmas previas de esta orden\r\n    DELETE FROM public.order_signatures \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    -- Inserción masiva transformando el arreglo de firmas en registros reales\r\n    INSERT INTO public.order_signatures (\r\n        tenant_id,\r\n        entry_order_id,\r\n        template_signature_id,\r\n        signature_url\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        s.template_signature_id,\r\n        s.signature_url\r\n    FROM jsonb_to_recordset(v_signatures_json) AS s(\r\n        template_signature_id uuid,\r\n        signature_url text\r\n    );\r\n\r\n\r\nRETURN v_order_id;\r\n\r\n\r\nEND;\r\n$$"}	CREATE_function_create_full_order
20260522173218	{"CREATE OR REPLACE FUNCTION fetch_data_with_placa(\r\n    p_placa TEXT,\r\n    p_tenant_id UUID\r\n)\r\nRETURNS JSONB\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_vehicle_row RECORD;\r\n    v_owner_json JSONB;\r\n    v_customer_json JSONB;\r\n    v_last_customer_id UUID; -- ⚡ Volvemos a extraer solo el UUID del cliente\r\n    v_is_owner_same_as_customer BOOLEAN := FALSE;\r\n    v_result JSONB;\r\nBEGIN\r\n    -- 1. Buscar el vehículo mediante aislamiento por tenant\r\n    SELECT * INTO v_vehicle_row\r\n    FROM public.vehicles v\r\n    WHERE UPPER(TRIM(v.placa)) = UPPER(TRIM(p_placa))\r\n      AND v.tenant_id = p_tenant_id\r\n      AND v.deleted_at IS NULL\r\n    LIMIT 1;\r\n\r\n    -- 2. Si NO existe el vehículo en este CDA, retornamos NULL plano de inmediato\r\n    IF v_vehicle_row.id IS NULL THEN\r\n        RETURN NULL;\r\n    END IF;\r\n\r\n    -- 3. Si existe, buscamos los datos del propietario actual en la tabla personas\r\n    IF v_vehicle_row.propietario_actual_id IS NOT NULL THEN\r\n        SELECT jsonb_build_object(\r\n            'id', p.id,\r\n            'tipo_documento', p.tipo_documento,\r\n            'numero_documento', p.numero_documento,\r\n            'nombre_completo', p.nombre_completo,\r\n            'telefono', p.telefono,\r\n            'correo', p.correo,\r\n            'direccion', p.direccion\r\n        ) INTO v_owner_json\r\n        FROM public.personas p\r\n        WHERE p.id = v_vehicle_row.propietario_actual_id;\r\n    ELSE\r\n        v_owner_json := NULL;\r\n    END IF;\r\n\r\n    -- 4. ✅ Buscar ÚNICAMENTE el cliente_id de la última orden de entrada para este vehículo\r\n    SELECT o.cliente_id INTO v_last_customer_id\r\n    FROM public.entry_orders o\r\n    WHERE o.vehiculo_id = v_vehicle_row.id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL\r\n    ORDER BY o.created_at DESC\r\n    LIMIT 1;\r\n\r\n    -- 5. Si encontramos una orden previa, extraemos los datos de ese cliente histórico\r\n    IF v_last_customer_id IS NOT NULL THEN\r\n        SELECT jsonb_build_object(\r\n            'id', p.id,\r\n            'tipo_documento', p.tipo_documento,\r\n            'numero_documento', p.numero_documento,\r\n            'nombre_completo', p.nombre_completo,\r\n            'telefono', p.telefono,\r\n            'correo', p.correo,\r\n            'direccion', p.direccion\r\n        ) INTO v_customer_json\r\n        FROM public.personas p\r\n        WHERE p.id = v_last_customer_id;\r\n\r\n        -- 6. Evaluamos dinámicamente si el propietario actual es el mismo cliente de la última visita\r\n        IF v_vehicle_row.propietario_actual_id = v_last_customer_id THEN\r\n            v_is_owner_same_as_customer := TRUE;\r\n        END IF;\r\n    ELSE\r\n        v_customer_json := NULL;\r\n    END IF;\r\n\r\n    -- 7. ✅ Construimos el objeto unificado de salida SIN los snapshots de vencimiento\r\n    v_result := jsonb_build_object(\r\n        'vehicle', jsonb_build_object(\r\n            'id', v_vehicle_row.id,\r\n            'placa', v_vehicle_row.placa,\r\n            'marca', v_vehicle_row.marca,\r\n            'linea', v_vehicle_row.linea,\r\n            'modelo', v_vehicle_row.modelo,\r\n            'color', v_vehicle_row.color,\r\n            'tipo_vehiculo', v_vehicle_row.tipo_vehiculo,\r\n            'clase', v_vehicle_row.clase,\r\n            'combustible', v_vehicle_row.combustible,\r\n            'cilindrada', v_vehicle_row.cilindrada,\r\n            'blindaje', v_vehicle_row.blindaje,\r\n            'capacidad_pasajeros', v_vehicle_row.capacidad_pasajeros,\r\n            'es_ensenanza', v_vehicle_row.es_ensenanza,\r\n            'tipo_servicio_vehiculo', v_vehicle_row.tipo_servicio_vehiculo,\r\n            'propietario_actual_id', v_vehicle_row.propietario_actual_id,\r\n            'es_extranjero', v_vehicle_row.es_extranjero\r\n        ),\r\n        'owner_data', v_owner_json,\r\n        'customer_data', v_customer_json,\r\n        'is_owner_same_as_customer', v_is_owner_same_as_customer\r\n    );\r\n\r\n    RETURN v_result;\r\nEND;\r\n$$"}	CREATE_function_fetch_data_with_placa
20260531203401	{"CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n\r\n    -- Tenant obligatorio para aislamiento multiempresa\r\n    p_tenant_id UUID,\r\n\r\n    -- Cuántos registros traer\r\n    p_limit INTEGER DEFAULT 20,\r\n\r\n    -- Desde qué posición empezar (paginación)\r\n    p_offset INTEGER DEFAULT 0,\r\n\r\n    -- Filtros opcionales\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL\r\n\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT\r\n        -- ============================\r\n        -- DATOS PRINCIPALES DE LA ORDEN\r\n        -- ============================\r\n        o.id,\r\n        v.placa::TEXT,\r\n        o.fecha,\r\n        v.marca::TEXT,\r\n        v.linea::TEXT,\r\n        -- ============================\r\n        -- DATOS DEL PROPIETARIO\r\n        -- ============================\r\n        propietario.nombre_completo,\r\n        propietario.numero_documento::TEXT,\r\n        -- ============================\r\n        -- DATOS DEL CLIENTE\r\n        -- ============================\r\n        cliente.nombre_completo,\r\n        cliente.numero_documento::TEXT,\r\n        -- ============================\r\n        -- ESTADO\r\n        -- ============================\r\n        o.estado_orden,\r\n\t-- ============================\r\n        -- CONTEO TOTAL\r\n        -- ============================\r\n\tCOUNT(*) OVER() AS total_count\r\n\r\n    FROM public.entry_orders o\r\n    -- ============================\r\n    -- JOIN VEHÍCULO\r\n    -- ============================\r\n    INNER JOIN public.vehicles v\r\n        ON v.id = o.vehiculo_id\r\n    -- ============================\r\n    -- JOIN PROPIETARIO\r\n    -- ============================\r\n    INNER JOIN public.personas propietario\r\n        ON propietario.id = o.propietario_id\r\n    -- ============================\r\n    -- JOIN CLIENTE\r\n    -- ============================\r\n    INNER JOIN public.personas cliente\r\n        ON cliente.id = o.cliente_id\r\n    WHERE\r\n        -- ==========================================\r\n        -- AISLAMIENTO MULTI-TENANT\r\n        -- ==========================================\r\n        o.tenant_id = p_tenant_id\r\n        -- ==========================================\r\n        -- SOFT DELETE\r\n        -- ==========================================\r\n        AND o.deleted_at IS NULL\r\n        AND v.deleted_at IS NULL\r\n        AND propietario.deleted_at IS NULL\r\n        AND cliente.deleted_at IS NULL\r\n        -- ==========================================\r\n        -- FILTRO POR PLACA\r\n        -- Si viene NULL, no filtra\r\n\t-- con que una de las dos condiciones sea verdadera, pasa.\r\n-- PARA ENTENDER MEJOR LA LOGICA DE ESTA CONDICIONAL: si se coloca solo AND (true), es redundante, pero si alguno de los or da true (esto v.placa ILIKE '%' || TRIM(p_placa) || '%', es un lado del null, entonces la condición pasa y la fila se inyecta en lo que se va a devolver\r\n        -- ==========================================\r\n        AND (p_placa IS NULL OR v.placa ILIKE '%' || TRIM(p_placa) || '%')\r\n        -- ==========================================\r\n        -- FILTRO POR ESTADO\r\n        -- ==========================================\r\n        AND ( p_estado IS NULL OR o.estado_orden = p_estado)\r\n        -- ==========================================\r\n        -- FILTRO FECHA DESDE\r\n        -- ==========================================\r\n        AND o.fecha::DATE >= p_fecha_desde\r\n        -- ==========================================\r\n        -- FILTRO FECHA HASTA\r\n        -- ==========================================\r\n        AND o.fecha::DATE <= p_fecha_hasta\r\n        -- ==========================================\r\n        -- FILTRO DOCUMENTO CLIENTE\r\n        -- ==========================================\r\n        AND (p_cliente_documento IS NULL OR cliente.numero_documento ILIKE '%' || TRIM(p_cliente_documento) || '%')\r\n        -- ==========================================\r\n        -- FILTRO DOCUMENTO PROPIETARIO\r\n        -- ==========================================\r\n        AND ( p_propietario_documento IS NULL OR propietario.numero_documento ILIKE '%' || TRIM(p_propietario_documento) || '%')\r\n    -- Más recientes primero\r\n    ORDER BY o.fecha DESC\r\n    -- Paginación\r\n    LIMIT p_limit\r\n    OFFSET p_offset;\r\nEND;\r\n$$"}	CREATE_funcion_entry_orders_list
20260602202720	{"-- ============================================================================\r\n-- 1. LIMPIEZA DE FIRMAS ANTERIORES\r\n-- ============================================================================\r\nDROP FUNCTION IF EXISTS public.fetch_entry_order_by_id(UUID, UUID)","-- ============================================================================\r\n-- 2. CREACIÓN DE LA FUNCIÓN MULTI-TENANT CON CONDICIONES DE PLANTILLA\r\n-- ============================================================================\r\nCREATE OR REPLACE FUNCTION public.fetch_entry_order_by_id(\r\n    p_order_id UUID,\r\n    p_tenant_id UUID DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    -- Datos principales de la Orden de Entrada\r\n    id UUID,\r\n    tenant_id UUID,\r\n    consecutivo INTEGER,\r\n    fecha TIMESTAMPTZ,\r\n    kilometraje VARCHAR,\r\n    es_reinspeccion BOOLEAN,\r\n    observaciones TEXT,\r\n    estado_orden order_status_enum,\r\n    soat_vencimiento_snapshot DATE,\r\n    gas_numero_snapshot VARCHAR,\r\n    gas_vencimiento_snapshot DATE,\r\n    texto_contractual_snapshot TEXT,\r\n    service_type service_type_enum,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    \r\n    -- Identificadores de relaciones relativas a la orden\r\n    vehiculo_id UUID,\r\n    propietario_id UUID,\r\n    cliente_id UUID,\r\n    funcionario_id UUID,\r\n    plantilla_id UUID,\r\n\r\n    -- Datos de la Plantilla (Control de Calidad / Encabezado PDF)\r\n    plantilla_nombre TEXT,\r\n    plantilla_version INTEGER,\r\n    plantilla_fecha_documento DATE,\r\n    plantilla_codigo_documento TEXT,\r\n    plantilla_logo_url TEXT,\r\n\r\n    -- Atributos Técnicos del Vehículo Asociado\r\n    vehiculo_placa VARCHAR,\r\n    vehiculo_marca VARCHAR,\r\n    vehiculo_linea VARCHAR,\r\n    vehiculo_modelo INTEGER,\r\n    vehiculo_color VARCHAR,\r\n    vehiculo_tipo_vehiculo public.vehicle_type_enum,\r\n    vehiculo_clase VARCHAR,\r\n    vehiculo_combustible VARCHAR,\r\n    vehiculo_cilindrada INTEGER,\r\n    vehiculo_blindaje BOOLEAN,\r\n    vehiculo_capacidad_pasajeros INTEGER,\r\n    vehiculo_es_ensenanza BOOLEAN,\r\n    vehiculo_tipo_servicio_vehiculo public.vehicle_service_type_enum,\r\n    vehiculo_es_extranjero BOOLEAN,\r\n\r\n    -- Colección de Mediciones de Presión\r\n    presiones_llantas JSONB,\r\n\r\n    -- 🔥 NUEVO CAMPO: Estructura de condiciones de inspección configuradas en el formato\r\n    condiciones_plantilla JSONB\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        -- Bloque: Orden de Entrada\r\n        o.id,\r\n        o.tenant_id,\r\n        o.consecutivo,\r\n        o.fecha,\r\n        o.kilometraje,\r\n        o.es_reinspeccion,\r\n        o.observaciones,\r\n        o.estado_orden,\r\n        o.soat_vencimiento_snapshot,\r\n        o.gas_numero_snapshot,\r\n        o.gas_vencimiento_snapshot,\r\n        o.texto_contractual_snapshot,\r\n        o.service_type,\r\n        o.created_at,\r\n        o.updated_at,\r\n        o.vehiculo_id,\r\n        o.propietario_id,\r\n        o.cliente_id,\r\n        o.funcionario_id,\r\n        o.plantilla_id,\r\n        \r\n        -- Bloque: Metadatos del Formato / Plantilla\r\n        t.template_name AS plantilla_nombre,\r\n        t.version AS plantilla_version,\r\n        t.document_date AS plantilla_fecha_documento,\r\n        t.document_code AS plantilla_codigo_documento,\r\n        t.logo_url AS plantilla_logo_url,\r\n\r\n        -- Bloque: Especificaciones del Vehículo\r\n        v.placa AS vehiculo_placa,\r\n        v.marca AS vehiculo_marca,\r\n        v.linea AS vehiculo_linea,\r\n        v.modelo AS vehiculo_modelo,\r\n        v.color AS vehiculo_color,\r\n        v.tipo_vehiculo AS vehiculo_tipo_vehiculo,\r\n        v.clase AS vehiculo_clase,\r\n        v.combustible AS vehiculo_combustible,\r\n        v.cilindrada AS vehiculo_cilindrada,\r\n        v.blindaje AS vehiculo_blindaje,\r\n        v.capacidad_pasajeros AS vehiculo_capacidad_pasajeros,\r\n        v.es_ensenanza AS vehiculo_es_ensenanza,\r\n        v.tipo_servicio_vehiculo AS vehiculo_tipo_servicio_vehiculo,\r\n        v.es_extranjero AS vehiculo_es_extranjero,\r\n        \r\n        -- Bloque Subconsulta: Mediciones de Presión\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'eje', tp.eje,\r\n                    'posicion', tp.posicion,\r\n                    'encontrada', tp.presion_encontrada,\r\n                    'ajustada', tp.presion_ajustada\r\n                ) \r\n                ORDER BY tp.eje ASC, tp.posicion ASC\r\n            )\r\n            FROM public.entry_order_tire_pressures tp\r\n            WHERE tp.entry_order_id = o.id \r\n              AND tp.tenant_id = o.tenant_id\r\n              AND tp.deleted_at IS NULL\r\n        ) AS presiones_llantas,\r\n\r\n        -- 🔥 Bloque Subconsulta: Lista ordenada de condiciones requeridas por la plantilla\r\n        -- --------------------------------------------------------------------\r\n        -- 🔥 Subconsulta 2: MAROMA TÉCNICA - Lógica de Inferencia de Resultados\r\n        -- --------------------------------------------------------------------\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'id', tc.id,\r\n                    'label', tc.label,\r\n                    'is_special', tc.is_special,\r\n                    'special_condition_label', tc.special_condition_label,\r\n                    \r\n                    -- AQUÍ ESTÁ LA MAGIA: Calculamos el valor final según tus reglas\r\n                    'value', CASE \r\n                        -- REGLA 1: Si hay un dato real guardado en la DB, ese manda sobre todo.\r\n                        WHEN ocr.value IS NOT NULL THEN ocr.value\r\n                        \r\n                        -- REGLA 2: Si NO está guardado y es especial, hereda su default ('no_aplica')\r\n                        WHEN tc.is_special = TRUE THEN tc.default_value\r\n                        \r\n                        -- REGLA 3: Si NO está guardado y es normal, intuimos que está todo OK ('cumple')\r\n                        ELSE 'cumple'::public.condition_response_enum\r\n                    END\r\n                )\r\n                ORDER BY tc.is_special DESC, tc.created_at ASC\r\n            )\r\n            FROM public.order_template_conditions tc\r\n            \r\n            -- Buscamos si existe un resultado guardado para ESTA orden y ESTA condición\r\n            LEFT JOIN public.order_condition_results ocr\r\n                ON ocr.template_condition_id = tc.id\r\n                AND ocr.entry_order_id = o.id -- Amarrado a la orden actual del SELECT principal\r\n                AND ocr.tenant_id = o.tenant_id -- Seguridad y rendimiento Multi-tenant\r\n                \r\n            WHERE tc.order_template_id = o.plantilla_id\r\n              AND tc.tenant_id = o.tenant_id\r\n              AND tc.deleted_at IS NULL\r\n        ) AS condiciones_plantilla\r\n\r\n    FROM public.entry_orders o\r\n    \r\n    LEFT JOIN public.order_template t \r\n        ON o.plantilla_id = t.id \r\n        AND t.deleted_at IS NULL\r\n        \r\n    LEFT JOIN public.vehicles v\r\n        ON o.vehiculo_id = v.id\r\n        AND v.deleted_at IS NULL\r\n        \r\n    WHERE o.id = p_order_id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL;\r\nEND;\r\n$$"}	CREATE_function_fetch_entry_order_by_id
20260603032740	{"-- Migración: Adición de campo para firma en formato Base64\r\nALTER TABLE public.service_users \r\nADD COLUMN signature_base64 TEXT","-- Comentario de auditoría técnica explicativo\r\nCOMMENT ON COLUMN public.service_users.signature_base64 IS 'Snapshot de la firma del recepcionista codificada en Base64 (JPEG, calidad 0.4) para incrustación directa en PDFs.'"}	ALTER_table_service_users_addfirmaURL
20260603222839	{"ALTER TABLE public.entry_orders \r\nDROP COLUMN IF EXISTS texto_contractual_snapshot CASCADE"}	ALTER_table_entry_orders_DROPcontractsnapshot
20260603224553	{"DROP FUNCTION IF EXISTS public.create_full_order(jsonb)","-- 1. CREACIÓN DE LA FUNCIÓN MAESTRA CON BLINDAJE TOTAL ANTI-NULL\r\nCREATE OR REPLACE FUNCTION public.create_full_order(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_order_id uuid;\r\n    v_tenant_id uuid;\r\n    v_input_id uuid;\r\n    v_consecutivo integer;\r\n    \r\n    -- Variables para almacenar los IDs de las relaciones\r\n    v_propietario_id uuid;\r\n    v_cliente_id uuid;\r\n    v_vehiculo_id uuid;\r\n    \r\n    -- Atajos para navegar los objetos anidados del JSONB\r\n    v_vehicle_json jsonb;\r\n    v_customer_json jsonb;\r\n    v_owner_json jsonb;\r\n    v_conditions_json jsonb;\r\n    v_signatures_json jsonb;\r\nBEGIN\r\n    -- =========================================================================\r\n    -- PASO 0: INICIALIZACIÓN DE VARIABLES Y ATAJOS\r\n    -- =========================================================================\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n    v_input_id := (p_data->>'id')::uuid; \r\n    v_vehicle_json := p_data->'vehicle';\r\n    v_customer_json := p_data->'customer_data';\r\n    v_owner_json := p_data->'owner_data';\r\n    v_conditions_json := p_data->'condition_results';\r\n    v_signatures_json := p_data->'signatures';\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 0.1: CÁLCULO DEL CONSECUTIVO POR TENANT (Solo en Creación)\r\n    -- =========================================================================\r\n    --Si el id no es null y se encuentra presente, entonces asignar a la variable v_consecutivo el consecutivo que ya existia.\r\n    IF v_input_id IS NOT NULL AND EXISTS (SELECT 1 FROM public.entry_orders WHERE id = v_input_id) THEN\r\n        SELECT consecutivo INTO v_consecutivo FROM public.entry_orders WHERE id = v_input_id;\r\n        --de lo contrario coger el maximo del consecutivo que ya existe, sumarle uno y mandarlo a la insercion de la columna correspondiente\r\n    ELSE\r\n        SELECT COALESCE(MAX(consecutivo), 0) + 1 \r\n        INTO v_consecutivo \r\n        FROM public.entry_orders \r\n        WHERE tenant_id = v_tenant_id;\r\n    END IF;\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 1: PROCESO DEL CLIENTE (customer_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_customer_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_customer_json->>'numero_documento'),\r\n        (v_customer_json->>'nombre_completo'),\r\n        NULLIF(v_customer_json->>'telefono', ''),\r\n        NULLIF(v_customer_json->>'correo', ''),\r\n        NULLIF(v_customer_json->>'direccion', '')\r\n    )\r\n    --si hay un conflicto con esactamente esos tres valores, entonces ejecutar el update\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n    -- Quitamos el RETURNING directo de este bloque para evitar el bug del NULL y lo rescatamos con SELECT seguro:\r\n    --seleccionamos el id directamente por medio de un select con las condiciones aqui presentes\r\n    SELECT id INTO v_cliente_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_customer_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_customer_json->>'numero_documento');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 2: PROCESO DEL PROPIETARIO (owner_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_owner_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_owner_json->>'numero_documento'),\r\n        (v_owner_json->>'nombre_completo'),\r\n        NULLIF(v_owner_json->>'telefono', ''),\r\n        NULLIF(v_owner_json->>'correo', ''),\r\n        NULLIF(v_owner_json->>'direccion', '')\r\n    )\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n    -- Rescate seguro del ID del propietario por su llave única:\r\n\r\n    SELECT id INTO v_propietario_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_owner_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_owner_json->>'numero_documento');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 3: PROCESO DEL VEHÍCULO\r\n    -- =========================================================================\r\n    INSERT INTO public.vehicles (\r\n        tenant_id,\r\n        placa,\r\n        marca,\r\n        linea,\r\n        modelo,\r\n        color,\r\n        tipo_vehiculo,\r\n        clase,\r\n        combustible,\r\n        cilindrada, \r\n        blindaje,\r\n        capacidad_pasajeros,\r\n        es_ensenanza,\r\n        es_extranjero,\r\n        tipo_servicio_vehiculo,\r\n        propietario_actual_id\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        UPPER(v_vehicle_json->>'placa'),\r\n        (v_vehicle_json->>'marca'),\r\n        (v_vehicle_json->>'linea'),\r\n        (v_vehicle_json->>'modelo')::integer,\r\n        (v_vehicle_json->>'color'),\r\n        (v_vehicle_json->>'tipo_vehiculo')::public.vehicle_type_enum,\r\n        (v_vehicle_json->>'clase'),\r\n        (v_vehicle_json->>'combustible'),\r\n        (v_vehicle_json->>'cilindrada')::integer, \r\n        (v_vehicle_json->>'blindaje')::boolean,\r\n        (v_vehicle_json->>'capacidad_pasajeros')::integer,\r\n        (v_vehicle_json->>'es_ensenanza')::boolean,\r\n        (v_vehicle_json->>'es_extranjero')::boolean,\r\n        (v_vehicle_json->>'tipo_servicio_vehiculo')::public.vehicle_service_type_enum,\r\n        v_propietario_id -- Pasa el v_propietario_id rescatado limpiamente arriba\r\n    )\r\n    ON CONFLICT (tenant_id, placa) \r\n    DO UPDATE SET\r\n        marca = EXCLUDED.marca,\r\n        linea = EXCLUDED.linea,\r\n        modelo = EXCLUDED.modelo,\r\n        color = EXCLUDED.color,\r\n        tipo_vehiculo = EXCLUDED.tipo_vehiculo,\r\n        clase = EXCLUDED.clase,\r\n        combustible = EXCLUDED.combustible,\r\n        cilindrada = EXCLUDED.cilindrada, \r\n        blindaje = EXCLUDED.blindaje,\r\n        capacidad_pasajeros = EXCLUDED.capacidad_pasajeros,\r\n        es_ensenanza = EXCLUDED.es_ensenanza,\r\n        es_extranjero = EXCLUDED.es_extranjero,\r\n        tipo_servicio_vehiculo = EXCLUDED.tipo_servicio_vehiculo,\r\n        propietario_actual_id = EXCLUDED.propietario_actual_id;\r\n    -- Rescate seguro del ID del vehículo por su llave única:\r\n\r\n    SELECT id INTO v_vehiculo_id \r\n    FROM public.vehicles \r\n    WHERE tenant_id = v_tenant_id \r\n      AND placa = UPPER(v_vehicle_json->>'placa');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 4: PROCESO DE LA ORDEN DE ENTRADA (Con todas las variables garantizadas)\r\n    -- =========================================================================\r\n    INSERT INTO public.entry_orders (\r\n        id,\r\n        tenant_id,\r\n        consecutivo,\r\n        vehiculo_id,\r\n        propietario_id,\r\n        cliente_id,\r\n        funcionario_id,\r\n        plantilla_id,\r\n        kilometraje,\r\n        es_reinspeccion,\r\n        observaciones,\r\n        estado_orden,\r\n        soat_vencimiento_snapshot,\r\n        gas_numero_snapshot,\r\n        gas_vencimiento_snapshot,\r\n        texto_contractual_snapshot,\r\n        service_type\r\n    )\r\n    VALUES (\r\n        COALESCE(v_input_id, gen_random_uuid()),\r\n        v_tenant_id,\r\n        v_consecutivo,\r\n        v_vehiculo_id,    -- Real, asegurado por el SELECT previo\r\n        v_propietario_id, -- Real, asegurado por el SELECT previo\r\n        v_cliente_id,     -- Real, asegurado por el SELECT previo\r\n        (p_data->>'funcionario_id')::uuid,\r\n        (p_data->>'plantilla_id')::uuid,\r\n        (p_data->>'kilometraje'),\r\n        COALESCE((p_data->>'es_reinspeccion')::boolean, false),\r\n        (p_data->>'observaciones'),\r\n        COALESCE((p_data->>'estado_orden')::public.order_status_enum, 'abierta'::public.order_status_enum),\r\n        \r\n        NULLIF(p_data->>'soat_vencimiento_snapshot', '')::date,\r\n        (p_data->>'gas_numero_snapshot'),\r\n        NULLIF(p_data->>'gas_vencimiento_snapshot', '')::date,\r\n        \r\n        (p_data->>'texto_contractual_snapshot'),\r\n        COALESCE((p_data->>'service_type')::public.service_type_enum, 'RTM'::public.service_type_enum)\r\n    )\r\n    ON CONFLICT (id) \r\n    DO UPDATE SET\r\n        vehiculo_id = EXCLUDED.vehiculo_id,\r\n        propietario_id = EXCLUDED.propietario_id,\r\n        cliente_id = EXCLUDED.cliente_id,\r\n        funcionario_id = EXCLUDED.funcionario_id,\r\n        kilometraje = EXCLUDED.kilometraje,\r\n        es_reinspeccion = EXCLUDED.es_reinspeccion,\r\n        observaciones = EXCLUDED.observaciones,\r\n        estado_orden = EXCLUDED.estado_orden,\r\n        soat_vencimiento_snapshot = EXCLUDED.soat_vencimiento_snapshot,\r\n        gas_numero_snapshot = EXCLUDED.gas_numero_snapshot,\r\n        gas_vencimiento_snapshot = EXCLUDED.gas_vencimiento_snapshot,\r\n        texto_contractual_snapshot = EXCLUDED.texto_contractual_snapshot,\r\n        service_type = EXCLUDED.service_type\r\n    RETURNING id INTO v_order_id;\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 5: PROCESO DETALLE - PRESIONES DE LLANTAS (tire_pressures)\r\n    -- =========================================================================\r\n    DELETE FROM public.entry_order_tire_pressures \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    INSERT INTO public.entry_order_tire_pressures (\r\n        tenant_id,\r\n        entry_order_id,\r\n        eje,\r\n        posicion,\r\n        presion_encontrada,\r\n        presion_ajustada\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        t.eje,\r\n        t.posicion,\r\n        NULLIF(t.presion_encontrada, '')::numeric,\r\n        NULLIF(t.presion_ajustada, '')::numeric\r\n    FROM jsonb_to_recordset(p_data->'tire_pressures') AS t(\r\n        eje integer,\r\n        posicion character varying,\r\n        presion_encontrada character varying,\r\n        presion_ajustada character varying\r\n    );\r\n\r\n    \r\n    -- =========================================================================\r\n    -- PASO 6: PROCESO DETALLE - CONDICIONES DE RECEPCIÓN (conditions - Masivo)\r\n    -- =========================================================================\r\n    -- En caso de edición, limpiamos los resultados previos para esta orden\r\n    DELETE FROM public.order_condition_results \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    -- Inserción masiva transformando el arreglo JSON en registros SQL reales\r\n    INSERT INTO public.order_condition_results (\r\n        tenant_id,\r\n        entry_order_id,\r\n        template_condition_id,\r\n        value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        c.template_condition_id,\r\n        c.value::public.condition_response_enum\r\n    FROM jsonb_to_recordset(v_conditions_json) AS c(\r\n        template_condition_id uuid,\r\n        value character varying\r\n    );\r\n\r\n\r\n-- =========================================================================\r\n    -- ➕ PASO 7: PROCESO DETALLE - FIRMAS DE LA ORDEN (signatures - Masivo)\r\n    -- =========================================================================\r\n    -- En caso de edición, limpiamos las firmas previas de esta orden\r\n    DELETE FROM public.order_signatures \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    -- Inserción masiva transformando el arreglo de firmas en registros reales\r\n    INSERT INTO public.order_signatures (\r\n        tenant_id,\r\n        entry_order_id,\r\n        template_signature_id,\r\n        signature_url\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        s.template_signature_id,\r\n        s.signature_url\r\n    FROM jsonb_to_recordset(v_signatures_json) AS s(\r\n        template_signature_id uuid,\r\n        signature_url text\r\n    );\r\n\r\n\r\nRETURN v_order_id;\r\n\r\n\r\nEND;\r\n$$"}	ALTER_function_create_full_order_DROPcontratotexto
20260603225015	{"-- ============================================================================\r\n-- 1. LIMPIEZA DE LA FUNCIÓN ANTERIOR (Para evitar conflictos de firmas)\r\n-- ============================================================================\r\nDROP FUNCTION IF EXISTS public.fetch_entry_order_by_id(UUID, UUID)","-- ============================================================================\r\n-- 2. CREACIÓN DE LA FUNCIÓN MULTI-TENANT OPTIMIZADA\r\n-- ============================================================================\r\nCREATE OR REPLACE FUNCTION public.fetch_entry_order_by_id(\r\n    p_order_id UUID,\r\n    p_tenant_id UUID DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    -- Datos principales de la Orden de Entrada\r\n    id UUID,\r\n    tenant_id UUID,\r\n    consecutivo INTEGER,\r\n    fecha TIMESTAMPTZ,\r\n    kilometraje VARCHAR,\r\n    es_reinspeccion BOOLEAN,\r\n    observaciones TEXT,\r\n    estado_orden order_status_enum,\r\n    soat_vencimiento_snapshot DATE,\r\n    gas_numero_snapshot VARCHAR,\r\n    gas_vencimiento_snapshot DATE,\r\n    \r\n    service_type service_type_enum,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    \r\n    -- Identificadores de relaciones relativas a la orden\r\n    vehiculo_id UUID,\r\n    propietario_id UUID,\r\n    cliente_id UUID,\r\n    funcionario_id UUID,\r\n    plantilla_id UUID,\r\n\r\n    -- Datos de la Plantilla (Control de Calidad / Encabezado PDF)\r\n    plantilla_nombre TEXT,\r\n    plantilla_version INTEGER,\r\n    plantilla_fecha_documento DATE,\r\n    plantilla_codigo_documento TEXT,\r\n    plantilla_logo_url TEXT,\r\n    plantilla_texto_contractual TEXT,\r\n\r\n    -- Atributos Técnicos del Vehículo Asociado\r\n    vehiculo_placa VARCHAR,\r\n    vehiculo_marca VARCHAR,\r\n    vehiculo_linea VARCHAR,\r\n    vehiculo_modelo INTEGER,\r\n    vehiculo_color VARCHAR,\r\n    vehiculo_tipo_vehiculo public.vehicle_type_enum,\r\n    vehiculo_clase VARCHAR,\r\n    vehiculo_combustible VARCHAR,\r\n    vehiculo_cilindrada INTEGER,\r\n    vehiculo_blindaje BOOLEAN,\r\n    vehiculo_capacidad_pasajeros INTEGER,\r\n    vehiculo_es_ensenanza BOOLEAN,\r\n    vehiculo_tipo_servicio_vehiculo public.vehicle_service_type_enum,\r\n    vehiculo_es_extranjero BOOLEAN,\r\n\r\n    -- Colección de Mediciones de Presión\r\n    presiones_llantas JSONB,\r\n\r\n    -- Estructura de condiciones de inspección configuradas en el formato\r\n    condiciones_plantilla JSONB,\r\n\r\n    -- 🔥 NUEVO CAMPO: Colección ordenada de firmas requeridas y capturadas\r\n    firmas_orden JSONB\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        -- Bloque: Orden de Entrada\r\n        o.id,\r\n        o.tenant_id,\r\n        o.consecutivo,\r\n        o.fecha,\r\n        o.kilometraje,\r\n        o.es_reinspeccion,\r\n        o.observaciones,\r\n        o.estado_orden,\r\n        o.soat_vencimiento_snapshot,\r\n        o.gas_numero_snapshot,\r\n        o.gas_vencimiento_snapshot,\r\n        \r\n        o.service_type,\r\n        o.created_at,\r\n        o.updated_at,\r\n        o.vehiculo_id,\r\n        o.propietario_id,\r\n        o.cliente_id,\r\n        o.funcionario_id,\r\n        o.plantilla_id,\r\n        \r\n        -- Bloque: Metadatos del Formato / Plantilla\r\n        t.template_name AS plantilla_nombre,\r\n        t.version AS plantilla_version,\r\n        t.document_date AS plantilla_fecha_documento,\r\n        t.document_code AS plantilla_codigo_documento,\r\n        t.logo_url AS plantilla_logo_url,\r\n        t.base_contract_text as plantilla_texto_contractual,\r\n\r\n        -- Bloque: Especificaciones del Vehículo\r\n        v.placa AS vehiculo_placa,\r\n        v.marca AS vehiculo_marca,\r\n        v.linea AS vehiculo_linea,\r\n        v.modelo AS vehiculo_modelo,\r\n        v.color AS vehiculo_color,\r\n        v.tipo_vehiculo AS vehiculo_tipo_vehiculo,\r\n        v.clase AS vehiculo_clase,\r\n        v.combustible AS vehiculo_combustible,\r\n        v.cilindrada AS vehiculo_cilindrada,\r\n        v.blindaje AS vehiculo_blindaje,\r\n        v.capacidad_pasajeros AS vehiculo_capacidad_pasajeros,\r\n        v.es_ensenanza AS vehiculo_es_ensenanza,\r\n        v.tipo_servicio_vehiculo AS vehiculo_tipo_servicio_vehiculo,\r\n        v.es_extranjero AS vehiculo_es_extranjero,\r\n        \r\n        -- Bloque Subconsulta: Mediciones de Presión\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'eje', tp.eje,\r\n                    'posicion', tp.posicion,\r\n                    'encontrada', tp.presion_encontrada,\r\n                    'ajustada', tp.presion_ajustada\r\n                ) \r\n                ORDER BY tp.eje ASC, tp.posicion ASC\r\n            )\r\n            FROM public.entry_order_tire_pressures tp\r\n            WHERE tp.entry_order_id = o.id \r\n              AND tp.tenant_id = o.tenant_id\r\n              AND tp.deleted_at IS NULL\r\n        ) AS presiones_llantas,\r\n\r\n        -- Bloque Subconsulta: Lista ordenada de condiciones de control\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'id', tc.id,\r\n                    'label', tc.label,\r\n                    'is_special', tc.is_special,\r\n                    'special_condition_label', tc.special_condition_label,\r\n                    'value', CASE \r\n                        WHEN ocr.value IS NOT NULL THEN ocr.value\r\n                        WHEN tc.is_special = TRUE THEN tc.default_value\r\n                        ELSE 'cumple'::public.condition_response_enum\r\n                    END\r\n                )\r\n                ORDER BY tc.is_special DESC, tc.created_at ASC\r\n            )\r\n            FROM public.order_template_conditions tc\r\n            LEFT JOIN public.order_condition_results ocr\r\n                ON ocr.template_condition_id = tc.id\r\n               AND ocr.entry_order_id = o.id\r\n               AND ocr.tenant_id = o.tenant_id\r\n            WHERE tc.order_template_id = o.plantilla_id\r\n              AND tc.tenant_id = o.tenant_id\r\n              AND tc.deleted_at IS NULL\r\n        ) AS condiciones_plantilla,\r\n\r\n        -- 🔥 Bloque Subconsulta 3: Extracción e Inferencia de Firmas con Textos Legales\r\n        -- --------------------------------------------------------------------\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'template_signature_id', ots.id,\r\n                    'representative_type', ots.representative_type,\r\n                    'signature_label', ots.signature_label,\r\n                    \r\n                    -- Si la orden ya fue firmada, trae la URL de Supabase Storage, si no, NULL\r\n                    'signature_url', os.signature_url,\r\n                    \r\n                    -- Traemos la declaración de responsabilidad mapeada a esta firma específica\r\n                    'declaration_text', os_cond.declaration_text\r\n                )\r\n                ORDER BY ots.created_at ASC\r\n            )\r\n            FROM public.order_template_signatures ots\r\n            \r\n            -- 1. Buscamos la firma física guardada de esta orden\r\n            LEFT JOIN public.order_signatures os\r\n                ON os.template_signature_id = ots.id\r\n               AND os.entry_order_id = o.id\r\n               AND os.tenant_id = o.tenant_id\r\n               \r\n            -- 2. Buscamos el texto legal anidado a este tipo de firma en la plantilla\r\n            LEFT JOIN public.order_template_signature_conditions os_cond\r\n                ON os_cond.order_template_signature_id = ots.id\r\n               AND os_cond.tenant_id = o.tenant_id\r\n               AND os_cond.deleted_at IS NULL\r\n               \r\n            WHERE ots.order_template_id = o.plantilla_id\r\n              AND ots.tenant_id = o.tenant_id\r\n              AND ots.deleted_at IS NULL\r\n        ) AS firmas_orden\r\n\r\n    FROM public.entry_orders o\r\n    \r\n    LEFT JOIN public.order_template t \r\n        ON o.plantilla_id = t.id \r\n        AND t.deleted_at IS NULL\r\n        \r\n    LEFT JOIN public.vehicles v\r\n        ON o.vehiculo_id = v.id\r\n        AND v.deleted_at IS NULL\r\n        \r\n    WHERE o.id = p_order_id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_order_by_id_changetextocontractual
20260603230252	{"DROP FUNCTION IF EXISTS public.create_full_order(jsonb)","-- 1. CREACIÓN DE LA FUNCIÓN MAESTRA CON BLINDAJE TOTAL ANTI-NULL\r\nCREATE OR REPLACE FUNCTION public.create_full_order(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_order_id uuid;\r\n    v_tenant_id uuid;\r\n    v_input_id uuid;\r\n    v_consecutivo integer;\r\n    \r\n    -- Variables para almacenar los IDs de las relaciones\r\n    v_propietario_id uuid;\r\n    v_cliente_id uuid;\r\n    v_vehiculo_id uuid;\r\n    \r\n    -- Atajos para navegar los objetos anidados del JSONB\r\n    v_vehicle_json jsonb;\r\n    v_customer_json jsonb;\r\n    v_owner_json jsonb;\r\n    v_conditions_json jsonb;\r\n    v_signatures_json jsonb;\r\nBEGIN\r\n    -- =========================================================================\r\n    -- PASO 0: INICIALIZACIÓN DE VARIABLES Y ATAJOS\r\n    -- =========================================================================\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n    v_input_id := (p_data->>'id')::uuid; \r\n    v_vehicle_json := p_data->'vehicle';\r\n    v_customer_json := p_data->'customer_data';\r\n    v_owner_json := p_data->'owner_data';\r\n    v_conditions_json := p_data->'condition_results';\r\n    v_signatures_json := p_data->'signatures';\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 0.1: CÁLCULO DEL CONSECUTIVO POR TENANT (Solo en Creación)\r\n    -- =========================================================================\r\n    --Si el id no es null y se encuentra presente, entonces asignar a la variable v_consecutivo el consecutivo que ya existia.\r\n    IF v_input_id IS NOT NULL AND EXISTS (SELECT 1 FROM public.entry_orders WHERE id = v_input_id) THEN\r\n        SELECT consecutivo INTO v_consecutivo FROM public.entry_orders WHERE id = v_input_id;\r\n        --de lo contrario coger el maximo del consecutivo que ya existe, sumarle uno y mandarlo a la insercion de la columna correspondiente\r\n    ELSE\r\n        SELECT COALESCE(MAX(consecutivo), 0) + 1 \r\n        INTO v_consecutivo \r\n        FROM public.entry_orders \r\n        WHERE tenant_id = v_tenant_id;\r\n    END IF;\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 1: PROCESO DEL CLIENTE (customer_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_customer_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_customer_json->>'numero_documento'),\r\n        (v_customer_json->>'nombre_completo'),\r\n        NULLIF(v_customer_json->>'telefono', ''),\r\n        NULLIF(v_customer_json->>'correo', ''),\r\n        NULLIF(v_customer_json->>'direccion', '')\r\n    )\r\n    --si hay un conflicto con esactamente esos tres valores, entonces ejecutar el update\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n    -- Quitamos el RETURNING directo de este bloque para evitar el bug del NULL y lo rescatamos con SELECT seguro:\r\n    --seleccionamos el id directamente por medio de un select con las condiciones aqui presentes\r\n    SELECT id INTO v_cliente_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_customer_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_customer_json->>'numero_documento');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 2: PROCESO DEL PROPIETARIO (owner_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_owner_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_owner_json->>'numero_documento'),\r\n        (v_owner_json->>'nombre_completo'),\r\n        NULLIF(v_owner_json->>'telefono', ''),\r\n        NULLIF(v_owner_json->>'correo', ''),\r\n        NULLIF(v_owner_json->>'direccion', '')\r\n    )\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n    -- Rescate seguro del ID del propietario por su llave única:\r\n\r\n    SELECT id INTO v_propietario_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_owner_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_owner_json->>'numero_documento');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 3: PROCESO DEL VEHÍCULO\r\n    -- =========================================================================\r\n    INSERT INTO public.vehicles (\r\n        tenant_id,\r\n        placa,\r\n        marca,\r\n        linea,\r\n        modelo,\r\n        color,\r\n        tipo_vehiculo,\r\n        clase,\r\n        combustible,\r\n        cilindrada, \r\n        blindaje,\r\n        capacidad_pasajeros,\r\n        es_ensenanza,\r\n        es_extranjero,\r\n        tipo_servicio_vehiculo,\r\n        propietario_actual_id\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        UPPER(v_vehicle_json->>'placa'),\r\n        (v_vehicle_json->>'marca'),\r\n        (v_vehicle_json->>'linea'),\r\n        (v_vehicle_json->>'modelo')::integer,\r\n        (v_vehicle_json->>'color'),\r\n        (v_vehicle_json->>'tipo_vehiculo')::public.vehicle_type_enum,\r\n        (v_vehicle_json->>'clase'),\r\n        (v_vehicle_json->>'combustible'),\r\n        (v_vehicle_json->>'cilindrada')::integer, \r\n        (v_vehicle_json->>'blindaje')::boolean,\r\n        (v_vehicle_json->>'capacidad_pasajeros')::integer,\r\n        (v_vehicle_json->>'es_ensenanza')::boolean,\r\n        (v_vehicle_json->>'es_extranjero')::boolean,\r\n        (v_vehicle_json->>'tipo_servicio_vehiculo')::public.vehicle_service_type_enum,\r\n        v_propietario_id -- Pasa el v_propietario_id rescatado limpiamente arriba\r\n    )\r\n    ON CONFLICT (tenant_id, placa) \r\n    DO UPDATE SET\r\n        marca = EXCLUDED.marca,\r\n        linea = EXCLUDED.linea,\r\n        modelo = EXCLUDED.modelo,\r\n        color = EXCLUDED.color,\r\n        tipo_vehiculo = EXCLUDED.tipo_vehiculo,\r\n        clase = EXCLUDED.clase,\r\n        combustible = EXCLUDED.combustible,\r\n        cilindrada = EXCLUDED.cilindrada, \r\n        blindaje = EXCLUDED.blindaje,\r\n        capacidad_pasajeros = EXCLUDED.capacidad_pasajeros,\r\n        es_ensenanza = EXCLUDED.es_ensenanza,\r\n        es_extranjero = EXCLUDED.es_extranjero,\r\n        tipo_servicio_vehiculo = EXCLUDED.tipo_servicio_vehiculo,\r\n        propietario_actual_id = EXCLUDED.propietario_actual_id;\r\n    -- Rescate seguro del ID del vehículo por su llave única:\r\n\r\n    SELECT id INTO v_vehiculo_id \r\n    FROM public.vehicles \r\n    WHERE tenant_id = v_tenant_id \r\n      AND placa = UPPER(v_vehicle_json->>'placa');\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 4: PROCESO DE LA ORDEN DE ENTRADA (Con todas las variables garantizadas)\r\n    -- =========================================================================\r\n    INSERT INTO public.entry_orders (\r\n        id,\r\n        tenant_id,\r\n        consecutivo,\r\n        vehiculo_id,\r\n        propietario_id,\r\n        cliente_id,\r\n        funcionario_id,\r\n        plantilla_id,\r\n        kilometraje,\r\n        es_reinspeccion,\r\n        observaciones,\r\n        estado_orden,\r\n        soat_vencimiento_snapshot,\r\n        gas_numero_snapshot,\r\n        gas_vencimiento_snapshot,\r\n        \r\n        service_type\r\n    )\r\n    VALUES (\r\n        COALESCE(v_input_id, gen_random_uuid()),\r\n        v_tenant_id,\r\n        v_consecutivo,\r\n        v_vehiculo_id,    -- Real, asegurado por el SELECT previo\r\n        v_propietario_id, -- Real, asegurado por el SELECT previo\r\n        v_cliente_id,     -- Real, asegurado por el SELECT previo\r\n        (p_data->>'funcionario_id')::uuid,\r\n        (p_data->>'plantilla_id')::uuid,\r\n        (p_data->>'kilometraje'),\r\n        COALESCE((p_data->>'es_reinspeccion')::boolean, false),\r\n        (p_data->>'observaciones'),\r\n        COALESCE((p_data->>'estado_orden')::public.order_status_enum, 'abierta'::public.order_status_enum),\r\n        \r\n        NULLIF(p_data->>'soat_vencimiento_snapshot', '')::date,\r\n        (p_data->>'gas_numero_snapshot'),\r\n        NULLIF(p_data->>'gas_vencimiento_snapshot', '')::date,\r\n        \r\n        \r\n        COALESCE((p_data->>'service_type')::public.service_type_enum, 'RTM'::public.service_type_enum)\r\n    )\r\n    ON CONFLICT (id) \r\n    DO UPDATE SET\r\n        vehiculo_id = EXCLUDED.vehiculo_id,\r\n        propietario_id = EXCLUDED.propietario_id,\r\n        cliente_id = EXCLUDED.cliente_id,\r\n        funcionario_id = EXCLUDED.funcionario_id,\r\n        kilometraje = EXCLUDED.kilometraje,\r\n        es_reinspeccion = EXCLUDED.es_reinspeccion,\r\n        observaciones = EXCLUDED.observaciones,\r\n        estado_orden = EXCLUDED.estado_orden,\r\n        soat_vencimiento_snapshot = EXCLUDED.soat_vencimiento_snapshot,\r\n        gas_numero_snapshot = EXCLUDED.gas_numero_snapshot,\r\n        gas_vencimiento_snapshot = EXCLUDED.gas_vencimiento_snapshot,\r\n        \r\n        service_type = EXCLUDED.service_type\r\n    RETURNING id INTO v_order_id;\r\n\r\n\r\n    -- =========================================================================\r\n    -- PASO 5: PROCESO DETALLE - PRESIONES DE LLANTAS (tire_pressures)\r\n    -- =========================================================================\r\n    DELETE FROM public.entry_order_tire_pressures \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    INSERT INTO public.entry_order_tire_pressures (\r\n        tenant_id,\r\n        entry_order_id,\r\n        eje,\r\n        posicion,\r\n        presion_encontrada,\r\n        presion_ajustada\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        t.eje,\r\n        t.posicion,\r\n        NULLIF(t.presion_encontrada, '')::numeric,\r\n        NULLIF(t.presion_ajustada, '')::numeric\r\n    FROM jsonb_to_recordset(p_data->'tire_pressures') AS t(\r\n        eje integer,\r\n        posicion character varying,\r\n        presion_encontrada character varying,\r\n        presion_ajustada character varying\r\n    );\r\n\r\n    \r\n    -- =========================================================================\r\n    -- PASO 6: PROCESO DETALLE - CONDICIONES DE RECEPCIÓN (conditions - Masivo)\r\n    -- =========================================================================\r\n    -- En caso de edición, limpiamos los resultados previos para esta orden\r\n    DELETE FROM public.order_condition_results \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    -- Inserción masiva transformando el arreglo JSON en registros SQL reales\r\n    INSERT INTO public.order_condition_results (\r\n        tenant_id,\r\n        entry_order_id,\r\n        template_condition_id,\r\n        value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        c.template_condition_id,\r\n        c.value::public.condition_response_enum\r\n    FROM jsonb_to_recordset(v_conditions_json) AS c(\r\n        template_condition_id uuid,\r\n        value character varying\r\n    );\r\n\r\n\r\n-- =========================================================================\r\n    -- ➕ PASO 7: PROCESO DETALLE - FIRMAS DE LA ORDEN (signatures - Masivo)\r\n    -- =========================================================================\r\n    -- En caso de edición, limpiamos las firmas previas de esta orden\r\n    DELETE FROM public.order_signatures \r\n    WHERE entry_order_id = v_order_id;\r\n\r\n    -- Inserción masiva transformando el arreglo de firmas en registros reales\r\n    INSERT INTO public.order_signatures (\r\n        tenant_id,\r\n        entry_order_id,\r\n        template_signature_id,\r\n        signature_url\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_order_id,\r\n        s.template_signature_id,\r\n        s.signature_url\r\n    FROM jsonb_to_recordset(v_signatures_json) AS s(\r\n        template_signature_id uuid,\r\n        signature_url text\r\n    );\r\n\r\n\r\nRETURN v_order_id;\r\n\r\n\r\nEND;\r\n$$"}	ALTER_function_create_full_order_DROPcontratotexto2
20260604000103	{"-- ==========================================\r\n-- SNAPSHOT DEL VEHÍCULO\r\n-- ==========================================\r\n\r\nALTER TABLE public.entry_orders\r\n\r\nADD COLUMN vehiculo_placa_snapshot VARCHAR NOT NULL,\r\nADD COLUMN vehiculo_marca_snapshot VARCHAR NOT NULL,\r\nADD COLUMN vehiculo_linea_snapshot VARCHAR NOT NULL,\r\nADD COLUMN vehiculo_modelo_snapshot INTEGER NOT NULL,\r\nADD COLUMN vehiculo_color_snapshot VARCHAR NOT NULL,\r\nADD COLUMN vehiculo_tipo_snapshot public.vehicle_type_enum NOT NULL,\r\nADD COLUMN vehiculo_clase_snapshot VARCHAR NOT NULL,\r\nADD COLUMN vehiculo_combustible_snapshot VARCHAR NOT NULL,\r\nADD COLUMN vehiculo_cilindrada_snapshot INTEGER NOT NULL,\r\nADD COLUMN vehiculo_blindaje_snapshot BOOLEAN NOT NULL,\r\nADD COLUMN vehiculo_capacidad_pasajeros_snapshot INTEGER NOT NULL,\r\nADD COLUMN vehiculo_es_ensenanza_snapshot BOOLEAN NOT NULL,\r\nADD COLUMN vehiculo_tipo_servicio_snapshot public.vehicle_service_type_enum NOT NULL,\r\nADD COLUMN vehiculo_es_extranjero_snapshot BOOLEAN NOT NULL","-- ==========================================\r\n-- SNAPSHOT DEL PROPIETARIO\r\n-- ==========================================\r\n\r\nALTER TABLE public.entry_orders\r\n\r\nADD COLUMN propietario_tipo_documento_snapshot TEXT NOT NULL,\r\nADD COLUMN propietario_numero_documento_snapshot VARCHAR NOT NULL,\r\nADD COLUMN propietario_nombre_snapshot TEXT NOT NULL,\r\n\r\nADD COLUMN propietario_telefono_snapshot VARCHAR,\r\nADD COLUMN propietario_email_snapshot TEXT,\r\nADD COLUMN propietario_direccion_snapshot TEXT","-- ==========================================\r\n-- SNAPSHOT DEL CLIENTE\r\n-- ==========================================\r\n\r\nALTER TABLE public.entry_orders\r\n\r\nADD COLUMN cliente_tipo_documento_snapshot TEXT NOT NULL,\r\nADD COLUMN cliente_numero_documento_snapshot VARCHAR NOT NULL,\r\nADD COLUMN cliente_nombre_snapshot TEXT NOT NULL,\r\n\r\nADD COLUMN cliente_telefono_snapshot VARCHAR,\r\nADD COLUMN cliente_email_snapshot TEXT,\r\nADD COLUMN cliente_direccion_snapshot TEXT","-- ==========================================\r\n-- SNAPSHOT DEL FUNCIONARIO\r\n-- ==========================================\r\n\r\nALTER TABLE public.entry_orders\r\n\r\nADD COLUMN funcionario_tipo_documento_snapshot TEXT NOT NULL,\r\nADD COLUMN funcionario_numero_documento_snapshot VARCHAR NOT NULL,\r\nADD COLUMN funcionario_nombre_snapshot TEXT NOT NULL,\r\nADD COLUMN funcionario_firma_base64_snapshot TEXT NOT NULL"}	ALTER_table_entry_orders_addSnapshotsTodos
20260604182614	{"CREATE OR REPLACE FUNCTION public.create_full_order(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_order_id uuid;\r\n    v_tenant_id uuid;\r\n    v_input_id uuid;\r\n    v_consecutivo integer;\r\n    \r\n    -- Variables para almacenar los IDs de las relaciones primarias\r\n    v_propietario_id uuid;\r\n    v_cliente_id uuid;\r\n    v_vehiculo_id uuid;\r\n    \r\n    -- Variables temporales calibradas con la estructura real de public.service_users\r\n    v_func_tipo_doc text;\r\n    v_func_num_doc text;\r\n    v_func_nombre text;\r\n    v_func_firma text;\r\n    \r\n    -- Atajos para navegar los objetos anidados del JSONB payload\r\n    v_vehicle_json jsonb;\r\n    v_customer_json jsonb;\r\n    v_owner_json jsonb;\r\n    v_conditions_json jsonb;\r\n    v_signatures_json jsonb;\r\nBEGIN\r\n    -- =========================================================================\r\n    -- PASO 0: INICIALIZACIÓN DE VARIABLES Y ATAJOS\r\n    -- =========================================================================\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n    v_input_id := (p_data->>'id')::uuid; \r\n    v_vehicle_json := p_data->'vehicle';\r\n    v_customer_json := p_data->'customer_data';\r\n    v_owner_json := p_data->'owner_data';\r\n    v_conditions_json := p_data->'condition_results';\r\n    v_signatures_json := p_data->'signatures';\r\n\r\n    -- =========================================================================\r\n    -- PASO 0.1: CÁLCULO DEL CONSECUTIVO POR TENANT (Solo en Creación)\r\n    -- =========================================================================\r\n--Si el id no es null y se encuentra presente, entonces asignar a la variable v_consecutivo el consecutivo que ya existia.\r\n    IF v_input_id IS NOT NULL AND EXISTS (SELECT 1 FROM public.entry_orders WHERE id = v_input_id) THEN\r\n        SELECT consecutivo INTO v_consecutivo FROM public.entry_orders WHERE id = v_input_id;\r\n--de lo contrario coger el maximo del consecutivo que ya existe, sumarle uno y mandarlo a la insercion de la columna correspondiente0\r\n    ELSE\r\n        SELECT COALESCE(MAX(consecutivo), 0) + 1 \r\n        INTO v_consecutivo \r\n        FROM public.entry_orders \r\n        WHERE tenant_id = v_tenant_id;\r\n    END IF;\r\n\r\n    -- =========================================================================\r\n    -- PASO 1: PROCESO E IDENTIFICACIÓN DEL CLIENTE (customer_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_customer_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_customer_json->>'numero_documento'),\r\n        (v_customer_json->>'nombre_completo'),\r\n        NULLIF(v_customer_json->>'telefono', ''),\r\n        NULLIF(v_customer_json->>'correo', ''),\r\n        NULLIF(v_customer_json->>'direccion', '')\r\n    )\r\n--si hay un conflicto con esactamente esos tres valores, entonces ejecutar el update\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n\r\n    SELECT id INTO v_cliente_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_customer_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_customer_json->>'numero_documento');\r\n\r\n    -- =========================================================================\r\n    -- PASO 2: PROCESO E IDENTIFICACIÓN DEL PROPIETARIO (owner_data)\r\n    -- =========================================================================\r\n    INSERT INTO public.personas (\r\n        tenant_id,\r\n        tipo_documento,\r\n        numero_documento,\r\n        nombre_completo,\r\n        telefono,\r\n        correo,\r\n        direccion\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (v_owner_json->>'tipo_documento')::public.document_type_enum,\r\n        (v_owner_json->>'numero_documento'),\r\n        (v_owner_json->>'nombre_completo'),\r\n        NULLIF(v_owner_json->>'telefono', ''),\r\n        NULLIF(v_owner_json->>'correo', ''),\r\n        NULLIF(v_owner_json->>'direccion', '')\r\n    )\r\n    ON CONFLICT (tenant_id, tipo_documento, numero_documento) \r\n    DO UPDATE SET\r\n        nombre_completo = EXCLUDED.nombre_completo,\r\n        telefono = EXCLUDED.telefono,\r\n        correo = EXCLUDED.correo,\r\n        direccion = EXCLUDED.direccion;\r\n\r\n    SELECT id INTO v_propietario_id \r\n    FROM public.personas \r\n    WHERE tenant_id = v_tenant_id \r\n      AND tipo_documento = (v_owner_json->>'tipo_documento')::public.document_type_enum \r\n      AND numero_documento = (v_owner_json->>'numero_documento');\r\n\r\n    -- =========================================================================\r\n    -- PASO 3: PROCESO E IDENTIFICACIÓN DEL VEHÍCULO\r\n    -- =========================================================================\r\n    INSERT INTO public.vehicles (\r\n        tenant_id,\r\n        placa,\r\n        marca,\r\n        linea,\r\n        modelo,\r\n        color,\r\n        tipo_vehiculo,\r\n        clase,\r\n        combustible,\r\n        cilindrada, \r\n        blindaje,\r\n        capacidad_pasajeros,\r\n        es_ensenanza,\r\n        es_extranjero,\r\n        tipo_servicio_vehiculo,\r\n        propietario_actual_id\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        UPPER(v_vehicle_json->>'placa'),\r\n        (v_vehicle_json->>'marca'),\r\n        (v_vehicle_json->>'linea'),\r\n        (v_vehicle_json->>'modelo')::integer,\r\n        (v_vehicle_json->>'color'),\r\n        (v_vehicle_json->>'tipo_vehiculo')::public.vehicle_type_enum,\r\n        (v_vehicle_json->>'clase'),\r\n        (v_vehicle_json->>'combustible'),\r\n        (v_vehicle_json->>'cilindrada')::integer, \r\n        COALESCE((v_vehicle_json->>'blindaje')::boolean, false),\r\n        (v_vehicle_json->>'capacidad_pasajeros')::integer,\r\n        COALESCE((v_vehicle_json->>'es_ensenanza')::boolean, false),\r\n        COALESCE((v_vehicle_json->>'es_extranjero')::boolean, false),\r\n        COALESCE((v_vehicle_json->>'tipo_servicio_vehiculo')::public.vehicle_service_type_enum, 'particular'::public.vehicle_service_type_enum),\r\n        v_propietario_id -- Pasa el v_propietario_id rescatado limpiamente arriba\r\n    )\r\n    ON CONFLICT (tenant_id, placa) \r\n    DO UPDATE SET\r\n        marca = EXCLUDED.marca,\r\n        linea = EXCLUDED.linea,\r\n        modelo = EXCLUDED.modelo,\r\n        color = EXCLUDED.color,\r\n        tipo_vehiculo = EXCLUDED.tipo_vehiculo,\r\n        clase = EXCLUDED.clase,\r\n        combustible = EXCLUDED.combustible,\r\n        cilindrada = EXCLUDED.cilindrada, \r\n        blindaje = EXCLUDED.blindaje,\r\n        capacidad_pasajeros = EXCLUDED.capacidad_pasajeros,\r\n        es_ensenanza = EXCLUDED.es_ensenanza,\r\n        es_extranjero = EXCLUDED.es_extranjero,\r\n        tipo_servicio_vehiculo = EXCLUDED.tipo_servicio_vehiculo,\r\n        propietario_actual_id = EXCLUDED.propietario_actual_id;\r\n\r\n\r\n -- Rescate seguro del ID del vehículo por su llave única:\r\n    SELECT id INTO v_vehiculo_id \r\n    FROM public.vehicles \r\n    WHERE tenant_id = v_tenant_id \r\n      AND placa = UPPER(v_vehicle_json->>'placa');\r\n\r\n    -- =========================================================================\r\n    -- PASO 3.1: OBTENER DATOS DESDE SERVICE_USERS (Firma obligatoria de la tabla)\r\n    -- =========================================================================\r\n    SELECT \r\n        COALESCE(document_type, 'cedula'), \r\n        COALESCE(document_number, '00000000'), \r\n        COALESCE(full_name, 'Funcionario no registrado'),\r\n        COALESCE(signature_base64, '') -- Extrae la firma de la tabla. Si está vacía, devuelve ''\r\n    INTO v_func_tipo_doc, v_func_num_doc, v_func_nombre, v_func_firma\r\n    FROM public.service_users \r\n    WHERE id = (p_data->>'funcionario_id')::uuid;\r\n\r\n    -- =========================================================================\r\n    -- PASO 4: PROCESO DE LA ORDEN DE ENTRADA CON MAPEO MASIVO DE SNAPSHOTS\r\n    -- =========================================================================\r\n    INSERT INTO public.entry_orders (\r\n        id,\r\n        tenant_id,\r\n        vehiculo_id,\r\n        propietario_id,\r\n        cliente_id,\r\n        funcionario_id,\r\n        plantilla_id,\r\n        consecutivo,\r\n        es_reinspeccion,\r\n        service_type,\r\n        estado_orden,\r\n        kilometraje,\r\n        observaciones,\r\n\r\n        -- Snapshots del Vehículo\r\n        vehiculo_placa_snapshot,\r\n        vehiculo_marca_snapshot,\r\n        vehiculo_linea_snapshot,\r\n        vehiculo_modelo_snapshot,\r\n        vehiculo_color_snapshot,\r\n        vehiculo_tipo_snapshot,\r\n        vehiculo_clase_snapshot,\r\n        vehiculo_combustible_snapshot,\r\n        vehiculo_cilindrada_snapshot,\r\n        vehiculo_blindaje_snapshot,\r\n        vehiculo_capacidad_pasajeros_snapshot,\r\n        vehiculo_es_ensenanza_snapshot,\r\n        vehiculo_tipo_servicio_snapshot,\r\n        vehiculo_es_extranjero_snapshot,\r\n\r\n        -- Snapshots del Propietario\r\n        propietario_tipo_documento_snapshot,\r\n        propietario_numero_documento_snapshot,\r\n        propietario_nombre_snapshot,\r\n        propietario_telefono_snapshot,\r\n        propietario_email_snapshot,\r\n        propietario_direccion_snapshot,\r\n\r\n        -- Snapshots del Cliente\r\n        cliente_tipo_documento_snapshot,\r\n        cliente_numero_documento_snapshot,\r\n        cliente_nombre_snapshot,\r\n        cliente_telefono_snapshot,\r\n        cliente_email_snapshot,\r\n        cliente_direccion_snapshot,\r\n\r\n        -- Snapshots del Funcionario\r\n        funcionario_tipo_documento_snapshot,\r\n        funcionario_numero_documento_snapshot,\r\n        funcionario_nombre_snapshot,\r\n        funcionario_firma_base64_snapshot,\r\n\r\n        -- Snapshots Documentales\r\n        soat_vencimiento_snapshot,\r\n        gas_numero_snapshot,\r\n        gas_vencimiento_snapshot\r\n        \r\n        \r\n    )\r\n    VALUES (\r\n        COALESCE(v_input_id, gen_random_uuid()),\r\n        v_tenant_id,\r\n        v_vehiculo_id,\r\n        v_propietario_id,\r\n        v_cliente_id,\r\n        (p_data->>'funcionario_id')::uuid,\r\n        (p_data->>'plantilla_id')::uuid,\r\n        v_consecutivo,\r\n        COALESCE((p_data->>'es_reinspeccion')::boolean, false),\r\n        COALESCE((p_data->>'service_type')::public.service_type_enum, 'RTM'::public.service_type_enum),\r\n        COALESCE((p_data->>'estado_orden')::public.order_status_enum, 'abierta'::public.order_status_enum),\r\n        (p_data->>'kilometraje'),\r\n        (p_data->>'observaciones'),\r\n\r\n        -- Mapeo Vehículo\r\n        UPPER(v_vehicle_json->>'placa'),\r\n        (v_vehicle_json->>'marca'),\r\n        (v_vehicle_json->>'linea'),\r\n        (v_vehicle_json->>'modelo')::integer,\r\n        (v_vehicle_json->>'color'),\r\n        (v_vehicle_json->>'tipo_vehiculo')::public.vehicle_type_enum,\r\n        (v_vehicle_json->>'clase'),\r\n        (v_vehicle_json->>'combustible'),\r\n        (v_vehicle_json->>'cilindrada')::integer,\r\n        COALESCE((v_vehicle_json->>'blindaje')::boolean, false),\r\n        (v_vehicle_json->>'capacidad_pasajeros')::integer,\r\n        COALESCE((v_vehicle_json->>'es_ensenanza')::boolean, false),\r\n        COALESCE((v_vehicle_json->>'tipo_servicio_vehiculo')::public.vehicle_service_type_enum, 'particular'::public.vehicle_service_type_enum),\r\n        COALESCE((v_vehicle_json->>'es_extranjero')::boolean, false),\r\n\r\n        -- Mapeo Propietario\r\n        (v_owner_json->>'tipo_documento'),\r\n        (v_owner_json->>'numero_documento'),\r\n        (v_owner_json->>'nombre_completo'),\r\n        NULLIF(v_owner_json->>'telefono', ''),\r\n        NULLIF(v_owner_json->>'correo', ''),\r\n        NULLIF(v_owner_json->>'direccion', ''),\r\n\r\n        -- Mapeo Cliente\r\n        (v_customer_json->>'tipo_documento'),\r\n        (v_customer_json->>'numero_documento'),\r\n        (v_customer_json->>'nombre_completo'),\r\n        NULLIF(v_customer_json->>'telefono', ''),\r\n        NULLIF(v_customer_json->>'correo', ''),\r\n        NULLIF(v_customer_json->>'direccion', ''),\r\n\r\n        -- Mapeo Funcionario (Extraído estrictamente de service_users)\r\n        v_func_tipo_doc,\r\n        v_func_num_doc,\r\n        v_func_nombre,\r\n        v_func_firma, -- Directo de la tabla. Si no existe, viaja vacío ''\r\n\r\n        -- Mapeo Documentos\r\n        NULLIF(p_data->>'soat_vencimiento_snapshot', '')::date,\r\n        (p_data->>'gas_numero_snapshot'),\r\n        NULLIF(p_data->>'gas_vencimiento_snapshot', '')::date\r\n        \r\n        \r\n    )\r\n    ON CONFLICT (id) \r\n    DO UPDATE SET\r\n        vehiculo_id = EXCLUDED.vehiculo_id,\r\n        propietario_id = EXCLUDED.propietario_id,\r\n        cliente_id = EXCLUDED.cliente_id,\r\n        funcionario_id = EXCLUDED.funcionario_id,\r\n        plantilla_id = EXCLUDED.plantilla_id,\r\n        es_reinspeccion = EXCLUDED.es_reinspeccion,\r\n        service_type = EXCLUDED.service_type,\r\n        estado_orden = EXCLUDED.estado_orden,\r\n        kilometraje = EXCLUDED.kilometraje,\r\n        observaciones = EXCLUDED.observaciones,\r\n\r\n        -- Actualización de Snapshots en Edición\r\n        vehiculo_placa_snapshot = EXCLUDED.vehiculo_placa_snapshot,\r\n        vehiculo_marca_snapshot = EXCLUDED.vehiculo_marca_snapshot,\r\n        vehiculo_linea_snapshot = EXCLUDED.vehiculo_linea_snapshot,\r\n        vehiculo_modelo_snapshot = EXCLUDED.vehiculo_modelo_snapshot,\r\n        vehiculo_color_snapshot = EXCLUDED.vehiculo_color_snapshot,\r\n        vehiculo_tipo_snapshot = EXCLUDED.vehiculo_tipo_snapshot,\r\n        vehiculo_clase_snapshot = EXCLUDED.vehiculo_clase_snapshot,\r\n        vehiculo_combustible_snapshot = EXCLUDED.vehiculo_combustible_snapshot,\r\n        vehiculo_cilindrada_snapshot = EXCLUDED.vehiculo_cilindrada_snapshot,\r\n        vehiculo_blindaje_snapshot = EXCLUDED.vehiculo_blindaje_snapshot,\r\n        vehiculo_capacidad_pasajeros_snapshot = EXCLUDED.vehiculo_capacidad_pasajeros_snapshot,\r\n        vehiculo_es_ensenanza_snapshot = EXCLUDED.vehiculo_es_ensenanza_snapshot,\r\n        vehiculo_tipo_servicio_snapshot = EXCLUDED.vehiculo_tipo_servicio_snapshot,\r\n        vehiculo_es_extranjero_snapshot = EXCLUDED.vehiculo_es_extranjero_snapshot,\r\n\r\n        propietario_tipo_documento_snapshot = EXCLUDED.propietario_tipo_documento_snapshot,\r\n        propietario_numero_documento_snapshot = EXCLUDED.propietario_numero_documento_snapshot,\r\n        propietario_nombre_snapshot = EXCLUDED.propietario_nombre_snapshot,\r\n        propietario_telefono_snapshot = EXCLUDED.propietario_telefono_snapshot,\r\n        propietario_email_snapshot = EXCLUDED.propietario_email_snapshot,\r\n        propietario_direccion_snapshot = EXCLUDED.propietario_direccion_snapshot,\r\n\r\n        cliente_tipo_documento_snapshot = EXCLUDED.cliente_tipo_documento_snapshot,\r\n        cliente_numero_documento_snapshot = EXCLUDED.cliente_numero_documento_snapshot,\r\n        cliente_nombre_snapshot = EXCLUDED.cliente_nombre_snapshot,\r\n        cliente_telefono_snapshot = EXCLUDED.cliente_telefono_snapshot,\r\n        cliente_email_snapshot = EXCLUDED.cliente_email_snapshot,\r\n        cliente_direccion_snapshot = EXCLUDED.cliente_direccion_snapshot,\r\n\r\n        funcionario_tipo_documento_snapshot = EXCLUDED.funcionario_tipo_documento_snapshot,\r\n        funcionario_numero_documento_snapshot = EXCLUDED.funcionario_numero_documento_snapshot,\r\n        funcionario_nombre_snapshot = EXCLUDED.funcionario_nombre_snapshot,\r\n        funcionario_firma_base64_snapshot = EXCLUDED.funcionario_firma_base64_snapshot,\r\n\r\n        soat_vencimiento_snapshot = EXCLUDED.soat_vencimiento_snapshot,\r\n        gas_numero_snapshot = EXCLUDED.gas_numero_snapshot,\r\n        gas_vencimiento_snapshot = EXCLUDED.gas_vencimiento_snapshot\r\n        \r\n        \r\n    RETURNING id INTO v_order_id;\r\n\r\n    -- =========================================================================\r\n    -- PASO 5: PROCESO DETALLE - PRESIONES DE LLANTAS (tire_pressures)\r\n    -- =========================================================================\r\n    DELETE FROM public.entry_order_tire_pressures WHERE entry_order_id = v_order_id;\r\n\r\n    INSERT INTO public.entry_order_tire_pressures (\r\n        tenant_id, \r\n\tentry_order_id, \r\n\teje, posicion, \r\n\tpresion_encontrada, \r\n\tpresion_ajustada\r\n    )\r\n    SELECT \r\n        v_tenant_id, \r\n\tv_order_id, \r\n\tt.eje, t.posicion,\r\n        NULLIF(t.presion_encontrada, '')::numeric, \r\n\tNULLIF(t.presion_ajustada, '')::numeric\r\n\r\n    FROM jsonb_to_recordset(p_data->'tire_pressures') AS t(\r\n        eje integer, \r\n\tposicion character varying, \r\n\tpresion_encontrada character varying, \r\n\tpresion_ajustada character varying\r\n    );\r\n    \r\n    -- =========================================================================\r\n    -- PASO 6: PROCESO DETALLE - CONDICIONES DE RECEPCIÓN (conditions)\r\n    -- =========================================================================\r\n -- En caso de edición, limpiamos los resultados previos para esta orden\r\n    DELETE FROM public.order_condition_results \r\n\tWHERE entry_order_id = v_order_id;\r\n\r\n -- Inserción masiva transformando el arreglo JSON en registros SQL reales\r\n    INSERT INTO public.order_condition_results (\r\n        tenant_id, \r\n\tentry_order_id, \r\n\ttemplate_condition_id, \r\n\tvalue\r\n    )\r\n    SELECT \r\n        v_tenant_id, \r\n\tv_order_id, \r\n\tc.template_condition_id, \r\n\tc.value::public.condition_response_enum\r\n\r\n    FROM jsonb_to_recordset(v_conditions_json) AS c(\r\n        template_condition_id uuid, \r\n\tvalue character varying\r\n    );\r\n\r\n    -- =========================================================================\r\n    -- PASO 7: PROCESO DETALLE - FIRMAS CAPTURADAS EN LA ORDEN (customer/owner signatures)\r\n    -- =========================================================================\r\n    DELETE FROM public.order_signatures \r\n\tWHERE entry_order_id = v_order_id;\r\n\r\n    INSERT INTO public.order_signatures (\r\n        tenant_id, \r\n\tentry_order_id, \r\n\ttemplate_signature_id, \r\n\tsignature_url\r\n    )\r\n    SELECT \r\n        v_tenant_id, \r\n\tv_order_id, \r\n\ts.template_signature_id, \r\n\ts.signature_url\r\n\r\n    FROM jsonb_to_recordset(v_signatures_json) AS s(\r\n        template_signature_id uuid, \r\n\tsignature_url text\r\n    );\r\n\r\n    RETURN v_order_id;\r\nEND;\r\n$$"}	ALTER_function_create_full_order_addSnapshots
20260604183836	{"CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    -- Tenant obligatorio para aislamiento multiempresa\r\n    p_tenant_id UUID,\r\n\r\n    -- Cuántos registros traer\r\n    p_limit INTEGER DEFAULT 20,\r\n\r\n    -- Desde qué posición empezar (paginación)\r\n    p_offset INTEGER DEFAULT 0,\r\n\r\n    -- Filtros opcionales\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT\r\n        -- =====================================================================\r\n        -- TODO SE SACA DIRECTAMENTE DESDE LA TABLA DE ORDENES (GRACIAS A LOS SNAPSHOTS)\r\n        -- =====================================================================\r\n        o.id,\r\n        o.vehiculo_placa_snapshot::TEXT,\r\n        o.fecha,\r\n        o.vehiculo_marca_snapshot::TEXT,\r\n        o.vehiculo_linea_snapshot::TEXT,\r\n        o.propietario_nombre_snapshot,\r\n        o.propietario_numero_documento_snapshot::TEXT,\r\n        o.cliente_nombre_snapshot,\r\n        o.cliente_numero_documento_snapshot::TEXT,\r\n        o.estado_orden,\r\n        \r\n        -- Conteo total eficiente usando función de ventana\r\n        COUNT(*) OVER() AS total_count\r\n\r\n    FROM public.entry_orders o\r\n    WHERE\r\n        -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n        o.tenant_id = p_tenant_id\r\n        AND o.deleted_at IS NULL\r\n        \r\n        -- FILTRO POR PLACA (Sobre el Snapshot)\r\n        AND (p_placa IS NULL OR o.vehiculo_placa_snapshot ILIKE '%' || TRIM(p_placa) || '%')\r\n        \r\n        -- FILTRO POR ESTADO\r\n        AND (p_estado IS NULL OR o.estado_orden = p_estado)\r\n        \r\n        -- FILTROS DE FECHAS\r\n        AND o.fecha::DATE >= p_fecha_desde\r\n        AND o.fecha::DATE <= p_fecha_hasta\r\n        \r\n        -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n        AND (p_cliente_documento IS NULL OR o.cliente_numero_documento_snapshot ILIKE '%' || TRIM(p_cliente_documento) || '%')\r\n        \r\n        -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n        AND (p_propietario_documento IS NULL OR o.propietario_numero_documento_snapshot ILIKE '%' || TRIM(p_propietario_documento) || '%')\r\n\r\n    -- Más recientes primero\r\n    ORDER BY o.fecha DESC\r\n    LIMIT p_limit\r\n    OFFSET p_offset;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_seSimplificaLaConsulta
20260604184205	{"DROP FUNCTION IF EXISTS public.fetch_entry_order_by_id(UUID, UUID)","CREATE OR REPLACE FUNCTION public.fetch_entry_order_by_id(\r\n    p_order_id UUID,\r\n    p_tenant_id UUID DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    -- Datos principales de la Orden de Entrada\r\n    id UUID,\r\n    tenant_id UUID,\r\n    consecutivo INTEGER,\r\n    fecha TIMESTAMPTZ,\r\n    kilometraje VARCHAR,\r\n    es_reinspeccion BOOLEAN,\r\n    observaciones TEXT,\r\n    estado_orden order_status_enum,\r\n    soat_vencimiento_snapshot DATE,\r\n    gas_numero_snapshot VARCHAR,\r\n    gas_vencimiento_snapshot DATE,\r\n    \r\n    service_type service_type_enum,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    \r\n    -- Identificadores de relaciones relativas a la orden\r\n    vehiculo_id UUID,\r\n    propietario_id UUID,\r\n    cliente_id UUID,\r\n    funcionario_id UUID,\r\n    plantilla_id UUID,\r\n\r\n    -- Datos de la Plantilla (Control de Calidad / Encabezado PDF)\r\n    plantilla_nombre TEXT,\r\n    plantilla_version INTEGER,\r\n    plantilla_fecha_documento DATE,\r\n    plantilla_codigo_documento TEXT,\r\n    plantilla_logo_url TEXT,\r\n    plantilla_texto_contractual TEXT,\r\n\r\n    -- Atributos Técnicos del Vehículo Asociado (AHORA DESDE EL SNAPSHOT - INMUTABLE)\r\n    vehiculo_placa VARCHAR,\r\n    vehiculo_marca VARCHAR,\r\n    vehiculo_linea VARCHAR,\r\n    vehiculo_modelo INTEGER,\r\n    vehiculo_color VARCHAR,\r\n    vehiculo_tipo_vehiculo public.vehicle_type_enum,\r\n    vehiculo_clase VARCHAR,\r\n    vehiculo_combustible VARCHAR,\r\n    vehiculo_cilindrada INTEGER,\r\n    vehiculo_blindaje BOOLEAN,\r\n    vehiculo_capacidad_pasajeros INTEGER,\r\n    vehiculo_es_ensenanza BOOLEAN,\r\n    vehiculo_tipo_servicio_vehiculo public.vehicle_service_type_enum,\r\n    vehiculo_es_extranjero BOOLEAN,\r\n\r\n    -- Snapshots de Personas (Nuevos campos para eliminar dependencias externas en el PDF)\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,\r\n    funcionario_nombre TEXT,\r\n    funcionario_documento TEXT,\r\n\r\n    -- Colecciones de Datos Detalle\r\n    presiones_llantas JSONB,\r\n    condiciones_plantilla JSONB,\r\n    firmas_orden JSONB\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        -- Bloque: Orden de Entrada\r\n        o.id,\r\n        o.tenant_id,\r\n        o.consecutivo,\r\n        o.fecha,\r\n        o.kilometraje,\r\n        o.es_reinspeccion,\r\n        o.observaciones,\r\n        o.estado_orden,\r\n        o.soat_vencimiento_snapshot,\r\n        o.gas_numero_snapshot,\r\n        o.gas_vencimiento_snapshot,\r\n        \r\n        o.service_type,\r\n        o.created_at,\r\n        o.updated_at,\r\n        o.vehiculo_id,\r\n        o.propietario_id,\r\n        o.cliente_id,\r\n        o.funcionario_id,\r\n        o.plantilla_id,\r\n        \r\n        -- Bloque: Metadatos de la Plantilla\r\n        t.template_name AS plantilla_nombre,\r\n        t.version AS plantilla_version,\r\n        t.document_date AS plantilla_fecha_documento,\r\n        t.document_code AS plantilla_codigo_documento,\r\n        t.logo_url AS plantilla_logo_url,\r\n        t.base_contract_text AS plantilla_texto_contractual,\r\n\r\n        -- Bloque: Especificaciones del Vehículo EXTRAÍDAS DEL SNAPSHOT (Rendimiento puro)\r\n        o.vehiculo_placa_snapshot AS vehiculo_placa,\r\n        o.vehiculo_marca_snapshot AS vehiculo_marca,\r\n        o.vehiculo_linea_snapshot AS vehiculo_linea,\r\n        o.vehiculo_modelo_snapshot AS vehiculo_modelo,\r\n        o.vehiculo_color_snapshot AS vehiculo_color,\r\n        o.vehiculo_tipo_snapshot AS vehiculo_tipo_vehiculo,\r\n        o.vehiculo_clase_snapshot AS vehiculo_clase,\r\n        o.vehiculo_combustible_snapshot AS vehiculo_combustible,\r\n        o.vehiculo_cilindrada_snapshot AS vehiculo_cilindrada,\r\n        o.vehiculo_blindaje_snapshot AS vehiculo_blindaje,\r\n        o.vehiculo_capacidad_pasajeros_snapshot AS vehiculo_capacidad_pasajeros,\r\n        o.vehiculo_es_ensenanza_snapshot AS vehiculo_es_ensenanza,\r\n        o.vehiculo_tipo_servicio_snapshot AS vehiculo_tipo_servicio_vehiculo,\r\n        o.vehiculo_es_extranjero_snapshot AS vehiculo_es_extranjero,\r\n        \r\n        -- Bloque: Snapshots de Personas (Evita consultar la tabla personas)\r\n        o.propietario_nombre_snapshot AS propietario_nombre,\r\n        o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n        o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,\r\n        o.cliente_nombre_snapshot AS cliente_nombre,\r\n        o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n        o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,\r\n        o.funcionario_nombre_snapshot AS funcionario_nombre,\r\n        o.funcionario_numero_documento_snapshot::TEXT AS funcionario_documento,\r\n\r\n        -- Bloque Subconsulta: Mediciones de Presión\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'eje', tp.eje,\r\n                    'posicion', tp.posicion,\r\n                    'encontrada', tp.presion_encontrada,\r\n                    'ajustada', tp.presion_ajustada\r\n                ) \r\n                ORDER BY tp.eje ASC, tp.posicion ASC\r\n            )\r\n            FROM public.entry_order_tire_pressures tp\r\n            WHERE tp.entry_order_id = o.id \r\n              AND tp.tenant_id = o.tenant_id\r\n              AND tp.deleted_at IS NULL\r\n        ) AS presiones_llantas,\r\n\r\n        -- Bloque Subconsulta: Condiciones de Control\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'id', tc.id,\r\n                    'label', tc.label,\r\n                    'is_special', tc.is_special,\r\n                    'special_condition_label', tc.special_condition_label,\r\n                    'value', CASE \r\n                        WHEN ocr.value IS NOT NULL THEN ocr.value\r\n                        WHEN tc.is_special = TRUE THEN tc.default_value\r\n                        ELSE 'cumple'::public.condition_response_enum\r\n                    END\r\n                )\r\n                ORDER BY tc.is_special DESC, tc.created_at ASC\r\n            )\r\n            FROM public.order_template_conditions tc\r\n            LEFT JOIN public.order_condition_results ocr\r\n                ON ocr.template_condition_id = tc.id\r\n               AND ocr.entry_order_id = o.id\r\n               AND ocr.tenant_id = o.tenant_id\r\n            WHERE tc.order_template_id = o.plantilla_id\r\n              AND tc.tenant_id = o.tenant_id\r\n              AND tc.deleted_at IS NULL\r\n        ) AS condiciones_plantilla,\r\n\r\n        -- Bloque Subconsulta 3: Firmas Combinadas (Dinámicas + Snapshot Funcionario)\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'template_signature_id', ots.id,\r\n                    'representative_type', ots.representative_type,\r\n                    'signature_label', ots.signature_label,\r\n                    \r\n                    -- Si el rol es el funcionario/inspector, inyectamos directamente su snapshot inmutable.\r\n                    -- De lo contrario, extraemos la URL de las firmas capturadas en la orden (cliente/propietario).\r\n                    'signature_url', CASE \r\n                        WHEN ots.representative_type = 'inspector' THEN COALESCE(NULLIF(o.funcionario_firma_base64_snapshot, ''), '')\r\n                        ELSE COALESCE(os.signature_url, '')\r\n                    END,\r\n                    \r\n                    'declaration_text', os_cond.declaration_text\r\n                )\r\n                ORDER BY ots.created_at ASC\r\n            )\r\n            FROM public.order_template_signatures ots\r\n            \r\n            LEFT JOIN public.order_signatures os\r\n                ON os.template_signature_id = ots.id\r\n               AND os.entry_order_id = o.id\r\n               AND os.tenant_id = o.tenant_id\r\n               \r\n            LEFT JOIN public.order_template_signature_conditions os_cond\r\n                ON os_cond.order_template_signature_id = ots.id\r\n               AND os_cond.tenant_id = o.tenant_id\r\n               AND os_cond.deleted_at IS NULL\r\n               \r\n            WHERE ots.order_template_id = o.plantilla_id\r\n              AND ots.tenant_id = o.tenant_id\r\n              AND ots.deleted_at IS NULL\r\n        ) AS firmas_orden\r\n\r\n    FROM public.entry_orders o\r\n    \r\n    LEFT JOIN public.order_template t \r\n        ON o.plantilla_id = t.id \r\n        AND t.deleted_at IS NULL\r\n        \r\n    WHERE o.id = p_order_id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_order_by_id_SeSimplificaGraciasASnapshots
20260604185646	{"CREATE OR REPLACE FUNCTION public.fetch_entry_order_by_id(\r\n    p_order_id UUID,\r\n    p_tenant_id UUID DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    -- Datos principales de la Orden de Entrada\r\n    id UUID,\r\n    tenant_id UUID,\r\n    consecutivo INTEGER,\r\n    fecha TIMESTAMPTZ,\r\n    kilometraje VARCHAR,\r\n    es_reinspeccion BOOLEAN,\r\n    observaciones TEXT,\r\n    estado_orden order_status_enum,\r\n    soat_vencimiento_snapshot DATE,\r\n    gas_numero_snapshot VARCHAR,\r\n    gas_vencimiento_snapshot DATE,\r\n    \r\n    service_type service_type_enum,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    \r\n    -- Identificadores de relaciones relativas a la orden\r\n    vehiculo_id UUID,\r\n    propietario_id UUID,\r\n    cliente_id UUID,\r\n    funcionario_id UUID,\r\n    plantilla_id UUID,\r\n\r\n    -- Datos de la Plantilla (Control de Calidad / Encabezado PDF)\r\n    plantilla_nombre TEXT,\r\n    plantilla_version INTEGER,\r\n    plantilla_fecha_documento DATE,\r\n    plantilla_codigo_documento TEXT,\r\n    plantilla_logo_url TEXT,\r\n    plantilla_texto_contractual TEXT,\r\n\r\n    -- Atributos Técnicos del Vehículo Asociado (AHORA DESDE EL SNAPSHOT - INMUTABLE)\r\n    vehiculo_placa VARCHAR,\r\n    vehiculo_marca VARCHAR,\r\n    vehiculo_linea VARCHAR,\r\n    vehiculo_modelo INTEGER,\r\n    vehiculo_color VARCHAR,\r\n    vehiculo_tipo_vehiculo public.vehicle_type_enum,\r\n    vehiculo_clase VARCHAR,\r\n    vehiculo_combustible VARCHAR,\r\n    vehiculo_cilindrada INTEGER,\r\n    vehiculo_blindaje BOOLEAN,\r\n    vehiculo_capacidad_pasajeros INTEGER,\r\n    vehiculo_es_ensenanza BOOLEAN,\r\n    vehiculo_tipo_servicio_vehiculo public.vehicle_service_type_enum,\r\n    vehiculo_es_extranjero BOOLEAN,\r\n\r\n    -- Snapshots de Personas (Nuevos campos para eliminar dependencias externas en el PDF)\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,\r\n    funcionario_nombre TEXT,\r\n    funcionario_documento TEXT,\r\n\r\n    -- Colecciones de Datos Detalle\r\n    presiones_llantas JSONB,\r\n    condiciones_plantilla JSONB,\r\n    firmas_orden JSONB\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        -- Bloque: Orden de Entrada\r\n        o.id,\r\n        o.tenant_id,\r\n        o.consecutivo,\r\n        o.fecha,\r\n        o.kilometraje,\r\n        o.es_reinspeccion,\r\n        o.observaciones,\r\n        o.estado_orden,\r\n        o.soat_vencimiento_snapshot,\r\n        o.gas_numero_snapshot,\r\n        o.gas_vencimiento_snapshot,\r\n        \r\n        o.service_type,\r\n        o.created_at,\r\n        o.updated_at,\r\n        o.vehiculo_id,\r\n        o.propietario_id,\r\n        o.cliente_id,\r\n        o.funcionario_id,\r\n        o.plantilla_id,\r\n        \r\n        -- Bloque: Metadatos de la Plantilla\r\n        t.template_name AS plantilla_nombre,\r\n        t.version AS plantilla_version,\r\n        t.document_date AS plantilla_fecha_documento,\r\n        t.document_code AS plantilla_codigo_documento,\r\n        t.logo_url AS plantilla_logo_url,\r\n        t.base_contract_text AS plantilla_texto_contractual,\r\n\r\n        -- Bloque: Especificaciones del Vehículo EXTRAÍDAS DEL SNAPSHOT (Rendimiento puro)\r\n        o.vehiculo_placa_snapshot AS vehiculo_placa,\r\n        o.vehiculo_marca_snapshot AS vehiculo_marca,\r\n        o.vehiculo_linea_snapshot AS vehiculo_linea,\r\n        o.vehiculo_modelo_snapshot AS vehiculo_modelo,\r\n        o.vehiculo_color_snapshot AS vehiculo_color,\r\n        o.vehiculo_tipo_snapshot AS vehiculo_tipo_vehiculo,\r\n        o.vehiculo_clase_snapshot AS vehiculo_clase,\r\n        o.vehiculo_combustible_snapshot AS vehiculo_combustible,\r\n        o.vehiculo_cilindrada_snapshot AS vehiculo_cilindrada,\r\n        o.vehiculo_blindaje_snapshot AS vehiculo_blindaje,\r\n        o.vehiculo_capacidad_pasajeros_snapshot AS vehiculo_capacidad_pasajeros,\r\n        o.vehiculo_es_ensenanza_snapshot AS vehiculo_es_ensenanza,\r\n        o.vehiculo_tipo_servicio_snapshot AS vehiculo_tipo_servicio_vehiculo,\r\n        o.vehiculo_es_extranjero_snapshot AS vehiculo_es_extranjero,\r\n        \r\n        -- Bloque: Snapshots de Personas (Evita consultar la tabla personas)\r\n        o.propietario_nombre_snapshot AS propietario_nombre,\r\n        o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n        o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,\r\n        o.cliente_nombre_snapshot AS cliente_nombre,\r\n        o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n        o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,\r\n        o.funcionario_nombre_snapshot AS funcionario_nombre,\r\n        o.funcionario_numero_documento_snapshot::TEXT AS funcionario_documento,\r\n\r\n        -- Bloque Subconsulta: Mediciones de Presión\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'eje', tp.eje,\r\n                    'posicion', tp.posicion,\r\n                    'encontrada', tp.presion_encontrada,\r\n                    'ajustada', tp.presion_ajustada\r\n                ) \r\n                ORDER BY tp.eje ASC, tp.posicion ASC\r\n            )\r\n            FROM public.entry_order_tire_pressures tp\r\n            WHERE tp.entry_order_id = o.id \r\n              AND tp.tenant_id = o.tenant_id\r\n              AND tp.deleted_at IS NULL\r\n        ) AS presiones_llantas,\r\n\r\n        -- Bloque Subconsulta: Condiciones de Control\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'id', tc.id,\r\n                    'label', tc.label,\r\n                    'is_special', tc.is_special,\r\n                    'special_condition_label', tc.special_condition_label,\r\n                    'value', CASE \r\n                        WHEN ocr.value IS NOT NULL THEN ocr.value\r\n                        WHEN tc.is_special = TRUE THEN tc.default_value\r\n                        ELSE 'cumple'::public.condition_response_enum\r\n                    END\r\n                )\r\n                ORDER BY tc.is_special DESC, tc.created_at ASC\r\n            )\r\n            FROM public.order_template_conditions tc\r\n            LEFT JOIN public.order_condition_results ocr\r\n                ON ocr.template_condition_id = tc.id\r\n               AND ocr.entry_order_id = o.id\r\n               AND ocr.tenant_id = o.tenant_id\r\n            WHERE tc.order_template_id = o.plantilla_id\r\n              AND tc.tenant_id = o.tenant_id\r\n              AND tc.deleted_at IS NULL\r\n        ) AS condiciones_plantilla,\r\n\r\n        -- Bloque Subconsulta 3: Firmas Combinadas (Dinámicas + Snapshot Funcionario)\r\n        -- Subconsulta Corregida: Jerárquica por Grupo de Firma (order_template_signatures)\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'template_signature_id', ots.id,\r\n                    'representative_type', ots.representative_type,\r\n                    'signature_label', ots.signature_label,\r\n                    \r\n                    -- Asignación de firma única por grupo\r\n                    'signature_url', CASE \r\n                        WHEN ots.representative_type = 'inspector' THEN COALESCE(NULLIF(o.funcionario_firma_base64_snapshot, ''), '')\r\n                        ELSE COALESCE(os.signature_url, '')\r\n                    END,\r\n                    \r\n                    -- SUB-AGREGACIÓN LIMPIA: Trae exclusivamente las condiciones de este grupo de firma\r\n                    'conditions', COALESCE(\r\n                        (\r\n                            SELECT jsonb_agg(\r\n                                jsonb_build_object(\r\n                                    'condition_id', os_cond.id,\r\n                                    'declaration_text', os_cond.declaration_text\r\n                                )\r\n                                ORDER BY os_cond.created_at ASC\r\n                            )\r\n                            FROM public.order_template_signature_conditions os_cond\r\n                            WHERE os_cond.order_template_signature_id = ots.id\r\n                              AND os_cond.tenant_id = o.tenant_id\r\n                              AND os_cond.deleted_at IS NULL\r\n                        ), \r\n                        '[]'::jsonb\r\n                    )\r\n                )\r\n                ORDER BY ots.created_at ASC\r\n            )\r\n            FROM public.order_template_signatures ots\r\n            \r\n            -- Buscamos la firma física única asociada a este template_signature_id para esta orden\r\n            LEFT JOIN public.order_signatures os\r\n                ON os.template_signature_id = ots.id\r\n               AND os.entry_order_id = o.id\r\n               AND os.tenant_id = o.tenant_id\r\n               \r\n            WHERE ots.order_template_id = o.plantilla_id\r\n              AND ots.tenant_id = o.tenant_id\r\n              AND ots.deleted_at IS NULL\r\n        ) AS firmas_orden\r\n\r\n    FROM public.entry_orders o\r\n    \r\n    LEFT JOIN public.order_template t \r\n        ON o.plantilla_id = t.id \r\n        AND t.deleted_at IS NULL\r\n        \r\n    WHERE o.id = p_order_id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_order_by_id_SeSimplificaGraciasASnapshots2
20260604202436	{"-- 1. ELIMINAR LA FUNCIÓN EXISTENTE PARA PODER CAMBIAR EL RETURNS TABLE\r\nDROP FUNCTION IF EXISTS public.fetch_entry_order_by_id(UUID, UUID)","-- 2. CREAR LA FUNCIÓN EXACTAMENTE COMO LA TENÍAS\r\nCREATE OR REPLACE FUNCTION public.fetch_entry_order_by_id(\r\n    p_order_id UUID,\r\n    p_tenant_id UUID DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    -- Datos principales de la Orden de Entrada\r\n    id UUID,\r\n    tenant_id UUID,\r\n    consecutivo INTEGER,\r\n    fecha TIMESTAMPTZ,\r\n    kilometraje VARCHAR,\r\n    es_reinspeccion BOOLEAN,\r\n    observaciones TEXT,\r\n    estado_orden order_status_enum,\r\n    soat_vencimiento_snapshot DATE,\r\n    gas_numero_snapshot VARCHAR,\r\n    gas_vencimiento_snapshot DATE,\r\n    \r\n    service_type service_type_enum,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    \r\n    -- Identificadores de relaciones relativas a la orden\r\n    vehiculo_id UUID,\r\n    propietario_id UUID,\r\n    cliente_id UUID,\r\n    funcionario_id UUID,\r\n    plantilla_id UUID,\r\n\r\n    -- Datos de la Plantilla (Control de Calidad / Encabezado PDF)\r\n    plantilla_nombre TEXT,\r\n    plantilla_version INTEGER,\r\n    plantilla_fecha_documento DATE,\r\n    plantilla_codigo_documento TEXT,\r\n    plantilla_logo_url TEXT,\r\n    plantilla_texto_contractual TEXT,\r\n\r\n    -- Atributos Técnicos del Vehículo Asociado (AHORA DESDE EL SNAPSHOT - INMUTABLE)\r\n    vehiculo_placa VARCHAR,\r\n    vehiculo_marca VARCHAR,\r\n    vehiculo_linea VARCHAR,\r\n    vehiculo_modelo INTEGER,\r\n    vehiculo_color VARCHAR,\r\n    vehiculo_tipo_vehiculo public.vehicle_type_enum,\r\n    vehiculo_clase VARCHAR,\r\n    vehiculo_combustible VARCHAR,\r\n    vehiculo_cilindrada INTEGER,\r\n    vehiculo_blindaje BOOLEAN,\r\n    vehiculo_capacidad_pasajeros INTEGER,\r\n    vehiculo_es_ensenanza BOOLEAN,\r\n    vehiculo_tipo_servicio_vehiculo public.vehicle_service_type_enum,\r\n    vehiculo_es_extranjero BOOLEAN,\r\n\r\n    -- Snapshots de Personas (Nuevos campos para eliminar dependencias externas en el PDF)\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,\r\n    funcionario_nombre TEXT,\r\n    funcionario_documento TEXT,\r\n    funcionario_firma TEXT, -- Nueva columna añadida\r\n\r\n    -- Colecciones de Datos Detalle\r\n    presiones_llantas JSONB,\r\n    condiciones_plantilla JSONB,\r\n    firmas_orden JSONB\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        -- Bloque: Orden de Entrada\r\n        o.id,\r\n        o.tenant_id,\r\n        o.consecutivo,\r\n        o.fecha,\r\n        o.kilometraje,\r\n        o.es_reinspeccion,\r\n        o.observaciones,\r\n        o.estado_orden,\r\n        o.soat_vencimiento_snapshot,\r\n        o.gas_numero_snapshot,\r\n        o.gas_vencimiento_snapshot,\r\n        \r\n        o.service_type,\r\n        o.created_at,\r\n        o.updated_at,\r\n        o.vehiculo_id,\r\n        o.propietario_id,\r\n        o.cliente_id,\r\n        o.funcionario_id,\r\n        o.plantilla_id,\r\n        \r\n        -- Bloque: Metadatos de la Plantilla\r\n        t.template_name AS plantilla_nombre,\r\n        t.version AS plantilla_version,\r\n        t.document_date AS plantilla_fecha_documento,\r\n        t.document_code AS plantilla_codigo_documento,\r\n        t.logo_url AS plantilla_logo_url,\r\n        t.base_contract_text AS plantilla_texto_contractual,\r\n\r\n        -- Bloque: Especificaciones del Vehículo EXTRAÍDAS DEL SNAPSHOT (Rendimiento puro)\r\n        o.vehiculo_placa_snapshot AS vehiculo_placa,\r\n        o.vehiculo_marca_snapshot AS vehiculo_marca,\r\n        o.vehiculo_linea_snapshot AS vehiculo_linea,\r\n        o.vehiculo_modelo_snapshot AS vehiculo_modelo,\r\n        o.vehiculo_color_snapshot AS vehiculo_color,\r\n        o.vehiculo_tipo_snapshot AS vehiculo_tipo_vehiculo,\r\n        o.vehiculo_clase_snapshot AS vehiculo_clase,\r\n        o.vehiculo_combustible_snapshot AS vehiculo_combustible,\r\n        o.vehiculo_cilindrada_snapshot AS vehiculo_cilindrada,\r\n        o.vehiculo_blindaje_snapshot AS vehiculo_blindaje,\r\n        o.vehiculo_capacidad_pasajeros_snapshot AS vehiculo_capacidad_pasajeros,\r\n        o.vehiculo_es_ensenanza_snapshot AS vehiculo_es_ensenanza,\r\n        o.vehiculo_tipo_servicio_snapshot AS vehiculo_tipo_servicio_vehiculo,\r\n        o.vehiculo_es_extranjero_snapshot AS vehiculo_es_extranjero,\r\n        \r\n        -- Bloque: Snapshots de Personas (Evita consultar la tabla personas)\r\n        o.propietario_nombre_snapshot AS propietario_nombre,\r\n        o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n        o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,\r\n        o.cliente_nombre_snapshot AS cliente_nombre,\r\n        o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n        o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,\r\n        o.funcionario_nombre_snapshot AS funcionario_nombre,\r\n        o.funcionario_numero_documento_snapshot::TEXT AS funcionario_documento,\r\n        o.funcionario_firma_base64_snapshot AS funcionario_firma,\r\n\r\n        -- Bloque Subconsulta: Mediciones de Presión\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'eje', tp.eje,\r\n                    'posicion', tp.posicion,\r\n                    'encontrada', tp.presion_encontrada,\r\n                    'ajustada', tp.presion_ajustada\r\n                ) \r\n                ORDER BY tp.eje ASC, tp.posicion ASC\r\n            )\r\n            FROM public.entry_order_tire_pressures tp\r\n            WHERE tp.entry_order_id = o.id \r\n              AND tp.tenant_id = o.tenant_id\r\n              AND tp.deleted_at IS NULL\r\n        ) AS presiones_llantas,\r\n\r\n        -- Bloque Subconsulta: Condiciones de Control\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'id', tc.id,\r\n                    'label', tc.label,\r\n                    'is_special', tc.is_special,\r\n                    'special_condition_label', tc.special_condition_label,\r\n                    'value', CASE \r\n                        WHEN ocr.value IS NOT NULL THEN ocr.value\r\n                        WHEN tc.is_special = TRUE THEN tc.default_value\r\n                        ELSE 'cumple'::public.condition_response_enum\r\n                    END\r\n                )\r\n                ORDER BY tc.is_special DESC, tc.created_at ASC\r\n            )\r\n            FROM public.order_template_conditions tc\r\n            LEFT JOIN public.order_condition_results ocr\r\n                ON ocr.template_condition_id = tc.id\r\n               AND ocr.entry_order_id = o.id\r\n               AND ocr.tenant_id = o.tenant_id\r\n            WHERE tc.order_template_id = o.plantilla_id\r\n              AND tc.tenant_id = o.tenant_id\r\n              AND tc.deleted_at IS NULL\r\n        ) AS condiciones_plantilla,\r\n\r\n        -- Bloque Subconsulta 3: Firmas Dinámicas Complementarias (EXCLUSIVO CLIENTE / PROPIETARIO / OTROS)\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'template_signature_id', ots.id,\r\n                    'representative_type', ots.representative_type,\r\n                    'signature_label', ots.signature_label,\r\n                    \r\n                    -- Aquí NUNCA entra el inspector. Es puramente para las firmas dinámicas de la tabla order_signatures\r\n                    'signature_url', COALESCE(os.signature_url, ''),\r\n                    \r\n                    'conditions', COALESCE(\r\n                        (\r\n                            SELECT jsonb_agg(\r\n                                jsonb_build_object(\r\n                                    'condition_id', os_cond.id,\r\n                                    'declaration_text', os_cond.declaration_text\r\n                                )\r\n                                ORDER BY os_cond.created_at ASC\r\n                            )\r\n                            FROM public.order_template_signature_conditions os_cond\r\n                            WHERE os_cond.order_template_signature_id = ots.id\r\n                              AND os_cond.tenant_id = o.tenant_id\r\n                              AND os_cond.deleted_at IS NULL\r\n                        ), \r\n                        '[]'::jsonb\r\n                    )\r\n                )\r\n                ORDER BY ots.created_at ASC\r\n            )\r\n            FROM public.order_template_signatures ots\r\n            \r\n            -- LEFT JOIN puro para traer la firma de la tabla dinámica\r\n            LEFT JOIN public.order_signatures os\r\n                ON os.template_signature_id = ots.id\r\n               AND os.entry_order_id = o.id\r\n               AND os.tenant_id = o.tenant_id\r\n               \r\n            WHERE ots.order_template_id = o.plantilla_id\r\n              AND ots.tenant_id = o.tenant_id\r\n              -- ¡CLAVE! Excluimos cualquier intento de mapear al inspector en este bloque dinámico\r\n              AND LOWER(ots.representative_type) NOT LIKE '%inspector%'\r\n              AND LOWER(ots.representative_type) NOT LIKE '%funcionario%'\r\n              AND ots.deleted_at IS NULL\r\n        ) AS firmas_orden\r\n\r\n    FROM public.entry_orders o\r\n    \r\n    LEFT JOIN public.order_template t \r\n        ON o.plantilla_id = t.id \r\n        AND t.deleted_at IS NULL\r\n        \r\n    WHERE o.id = p_order_id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_order_by_id_Correccion
20260605190300	{"CREATE OR REPLACE FUNCTION public.fetch_entry_order_by_id(\r\n    p_order_id UUID,\r\n    p_tenant_id UUID DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    -- Datos principales de la Orden de Entrada\r\n    id UUID,\r\n    tenant_id UUID,\r\n    consecutivo INTEGER,\r\n    fecha TIMESTAMPTZ,\r\n    kilometraje VARCHAR,\r\n    es_reinspeccion BOOLEAN,\r\n    observaciones TEXT,\r\n    estado_orden order_status_enum,\r\n    soat_vencimiento_snapshot DATE,\r\n    gas_numero_snapshot VARCHAR,\r\n    gas_vencimiento_snapshot DATE,\r\n    \r\n    service_type service_type_enum,\r\n    created_at TIMESTAMPTZ,\r\n    updated_at TIMESTAMPTZ,\r\n    \r\n    -- Identificadores de relaciones relativas a la orden\r\n    vehiculo_id UUID,\r\n    propietario_id UUID,\r\n    cliente_id UUID,\r\n    funcionario_id UUID,\r\n    plantilla_id UUID,\r\n\r\n    -- Datos de la Plantilla (Control de Calidad / Encabezado PDF)\r\n    plantilla_nombre TEXT,\r\n    plantilla_version INTEGER,\r\n    plantilla_fecha_documento DATE,\r\n    plantilla_codigo_documento TEXT,\r\n    plantilla_logo_url TEXT,\r\n    plantilla_texto_contractual TEXT,\r\n\r\n    -- Atributos Técnicos del Vehículo Asociado (AHORA DESDE EL SNAPSHOT - INMUTABLE)\r\n    vehiculo_placa VARCHAR,\r\n    vehiculo_marca VARCHAR,\r\n    vehiculo_linea VARCHAR,\r\n    vehiculo_modelo INTEGER,\r\n    vehiculo_color VARCHAR,\r\n    vehiculo_tipo_vehiculo public.vehicle_type_enum,\r\n    vehiculo_clase VARCHAR,\r\n    vehiculo_combustible VARCHAR,\r\n    vehiculo_cilindrada INTEGER,\r\n    vehiculo_blindaje BOOLEAN,\r\n    vehiculo_capacidad_pasajeros INTEGER,\r\n    vehiculo_es_ensenanza BOOLEAN,\r\n    vehiculo_tipo_servicio_vehiculo public.vehicle_service_type_enum,\r\n    vehiculo_es_extranjero BOOLEAN,\r\n\r\n    -- Snapshots de Personas (Nuevos campos para eliminar dependencias externas en el PDF)\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,\r\n    funcionario_nombre TEXT,\r\n    funcionario_documento TEXT,\r\n    funcionario_firma TEXT, -- Nueva columna añadida\r\n\r\n    -- Colecciones de Datos Detalle\r\n    presiones_llantas JSONB,\r\n    condiciones_plantilla JSONB,\r\n    firmas_orden JSONB\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT \r\n        -- Bloque: Orden de Entrada\r\n        o.id,\r\n        o.tenant_id,\r\n        o.consecutivo,\r\n        o.fecha,\r\n        o.kilometraje,\r\n        o.es_reinspeccion,\r\n        o.observaciones,\r\n        o.estado_orden,\r\n        o.soat_vencimiento_snapshot,\r\n        o.gas_numero_snapshot,\r\n        o.gas_vencimiento_snapshot,\r\n        \r\n        o.service_type,\r\n        o.created_at,\r\n        o.updated_at,\r\n        o.vehiculo_id,\r\n        o.propietario_id,\r\n        o.cliente_id,\r\n        o.funcionario_id,\r\n        o.plantilla_id,\r\n        \r\n        -- Bloque: Metadatos de la Plantilla\r\n        t.template_name AS plantilla_nombre,\r\n        t.version AS plantilla_version,\r\n        t.document_date AS plantilla_fecha_documento,\r\n        t.document_code AS plantilla_codigo_documento,\r\n        t.logo_url AS plantilla_logo_url,\r\n        t.base_contract_text AS plantilla_texto_contractual,\r\n\r\n        -- Bloque: Especificaciones del Vehículo EXTRAÍDAS DEL SNAPSHOT (Rendimiento puro)\r\n        o.vehiculo_placa_snapshot AS vehiculo_placa,\r\n        o.vehiculo_marca_snapshot AS vehiculo_marca,\r\n        o.vehiculo_linea_snapshot AS vehiculo_linea,\r\n        o.vehiculo_modelo_snapshot AS vehiculo_modelo,\r\n        o.vehiculo_color_snapshot AS vehiculo_color,\r\n        o.vehiculo_tipo_snapshot AS vehiculo_tipo_vehiculo,\r\n        o.vehiculo_clase_snapshot AS vehiculo_clase,\r\n        o.vehiculo_combustible_snapshot AS vehiculo_combustible,\r\n        o.vehiculo_cilindrada_snapshot AS vehiculo_cilindrada,\r\n        o.vehiculo_blindaje_snapshot AS vehiculo_blindaje,\r\n        o.vehiculo_capacidad_pasajeros_snapshot AS vehiculo_capacidad_pasajeros,\r\n        o.vehiculo_es_ensenanza_snapshot AS vehiculo_es_ensenanza,\r\n        o.vehiculo_tipo_servicio_snapshot AS vehiculo_tipo_servicio_vehiculo,\r\n        o.vehiculo_es_extranjero_snapshot AS vehiculo_es_extranjero,\r\n        \r\n        -- Bloque: Snapshots de Personas (Evita consultar la tabla personas)\r\n        o.propietario_nombre_snapshot AS propietario_nombre,\r\n        o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n        o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,\r\n        o.cliente_nombre_snapshot AS cliente_nombre,\r\n        o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n        o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,\r\n        o.funcionario_nombre_snapshot AS funcionario_nombre,\r\n        o.funcionario_numero_documento_snapshot::TEXT AS funcionario_documento,\r\n        o.funcionario_firma_base64_snapshot AS funcionario_firma,\r\n\r\n        -- Bloque Subconsulta: Mediciones de Presión\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'eje', tp.eje,\r\n                    'posicion', tp.posicion,\r\n                    'encontrada', tp.presion_encontrada,\r\n                    'ajustada', tp.presion_ajustada\r\n                ) \r\n                ORDER BY tp.eje ASC, tp.posicion ASC\r\n            )\r\n            FROM public.entry_order_tire_pressures tp\r\n            WHERE tp.entry_order_id = o.id \r\n              AND tp.tenant_id = o.tenant_id\r\n              AND tp.deleted_at IS NULL\r\n        ) AS presiones_llantas,\r\n\r\n        -- Bloque Subconsulta: Condiciones de Control\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'id', tc.id,\r\n                    'label', tc.label,\r\n                    'is_special', tc.is_special,\r\n                    'special_condition_label', tc.special_condition_label,\r\n                    'default_value', CASE \r\n                        WHEN ocr.value IS NOT NULL THEN ocr.value\r\n                        WHEN tc.is_special = TRUE THEN tc.default_value\r\n                        ELSE 'cumple'::public.condition_response_enum\r\n                    END\r\n                )\r\n                ORDER BY tc.is_special DESC, tc.created_at ASC\r\n            )\r\n            FROM public.order_template_conditions tc\r\n            LEFT JOIN public.order_condition_results ocr\r\n                ON ocr.template_condition_id = tc.id\r\n               AND ocr.entry_order_id = o.id\r\n               AND ocr.tenant_id = o.tenant_id\r\n            WHERE tc.order_template_id = o.plantilla_id\r\n              AND tc.tenant_id = o.tenant_id\r\n              AND tc.deleted_at IS NULL\r\n        ) AS condiciones_plantilla,\r\n\r\n        -- Bloque Subconsulta 3: Firmas Dinámicas Complementarias (EXCLUSIVO CLIENTE / PROPIETARIO / OTROS)\r\n        (\r\n            SELECT jsonb_agg(\r\n                jsonb_build_object(\r\n                    'template_signature_id', ots.id,\r\n                    'representative_type', ots.representative_type,\r\n                    'signature_label', ots.signature_label,\r\n                    \r\n                    -- Aquí NUNCA entra el inspector. Es puramente para las firmas dinámicas de la tabla order_signatures\r\n                    'signature_url', COALESCE(os.signature_url, ''),\r\n                    \r\n                    'conditions', COALESCE(\r\n                        (\r\n                            SELECT jsonb_agg(\r\n                                jsonb_build_object(\r\n                                    'condition_id', os_cond.id,\r\n                                    'declaration_text', os_cond.declaration_text\r\n                                )\r\n                                ORDER BY os_cond.created_at ASC\r\n                            )\r\n                            FROM public.order_template_signature_conditions os_cond\r\n                            WHERE os_cond.order_template_signature_id = ots.id\r\n                              AND os_cond.tenant_id = o.tenant_id\r\n                              AND os_cond.deleted_at IS NULL\r\n                        ), \r\n                        '[]'::jsonb\r\n                    )\r\n                )\r\n                ORDER BY ots.created_at ASC\r\n            )\r\n            FROM public.order_template_signatures ots\r\n            \r\n            -- LEFT JOIN puro para traer la firma de la tabla dinámica\r\n            LEFT JOIN public.order_signatures os\r\n                ON os.template_signature_id = ots.id\r\n               AND os.entry_order_id = o.id\r\n               AND os.tenant_id = o.tenant_id\r\n               \r\n            WHERE ots.order_template_id = o.plantilla_id\r\n              AND ots.tenant_id = o.tenant_id\r\n              -- ¡CLAVE! Excluimos cualquier intento de mapear al inspector en este bloque dinámico\r\n              AND LOWER(ots.representative_type) NOT LIKE '%inspector%'\r\n              AND LOWER(ots.representative_type) NOT LIKE '%funcionario%'\r\n              AND ots.deleted_at IS NULL\r\n        ) AS firmas_orden\r\n\r\n    FROM public.entry_orders o\r\n    \r\n    LEFT JOIN public.order_template t \r\n        ON o.plantilla_id = t.id \r\n        AND t.deleted_at IS NULL\r\n        \r\n    WHERE o.id = p_order_id\r\n      AND o.tenant_id = p_tenant_id\r\n      AND o.deleted_at IS NULL;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_order_by_id_BetterJsonDefaultValueChange
20260607223425	{"-- ------------------------------------------\r\n-- DELETE: Eliminar plantillas de forma permanente\r\n-- ------------------------------------------\r\nCREATE POLICY \\"delete_order_template_by_tenant\\"\r\nON public.order_template\r\nFOR DELETE\r\nTO authenticated\r\nUSING (\r\n    tenant_id IN (\r\n        SELECT tp.tenant_id \r\n        FROM public.tenant_permissions tp\r\n        JOIN public.service_users su ON su.id = tp.service_user_id\r\n        WHERE su.auth_user_id = (SELECT auth.uid())\r\n    )\r\n)"}	CREATE_rls_table_order_template_rlsForDelete
20260607231109	{"CREATE OR REPLACE FUNCTION public.create_full_order_template(p_data jsonb)\r\nRETURNS uuid\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nDECLARE\r\n    v_template_id uuid;\r\n    v_tenant_id uuid;\r\n    v_signature_record jsonb;\r\n    v_signature_id uuid;\r\n    \r\n    -- Variables para la nueva validación\r\n    v_document_code text;\r\n    v_new_version integer;\r\n    v_max_version integer;\r\nBEGIN\r\n    -- 0. Extraemos los datos de control iniciales\r\n    v_tenant_id := (p_data->>'tenant_id')::uuid;\r\n    v_document_code := (p_data->>'document_code');\r\n    v_new_version := (p_data->>'version')::integer;\r\n\r\n    -- ==============================================================================\r\n    -- VALIDADOR DE CONTROL DE VERSIONES (ISO 17020)\r\n    -- ==============================================================================\r\n    -- Buscamos la versión más alta existente para este código de documento y tenant\r\n    SELECT COALESCE(MAX(version), 0)\r\n    INTO v_max_version\r\n    FROM public.order_template\r\n    WHERE tenant_id = v_tenant_id\r\n      AND document_code = v_document_code;\r\n\r\n    -- Si ya existen versiones y la nueva versión es menor o igual a la máxima, bloqueamos\r\n    IF v_max_version > 0 AND v_new_version <= v_max_version THEN\r\n        RAISE EXCEPTION 'Control de documentos rechazado: El código % ya cuenta con la versión %. La nueva versión debe ser estrictamente mayor (mínimo %).', \r\n            v_document_code, v_max_version, (v_max_version + 1)\r\n            USING ERRCODE = '45000'; -- Código personalizado para excepciones de negocio\r\n    END IF;\r\n    -- ==============================================================================\r\n\r\n\r\n    -- 1. Insertamos en la tabla principal order_template\r\n    INSERT INTO public.order_template (\r\n        tenant_id,\r\n        template_name,\r\n        version,\r\n        is_active,\r\n        document_date,\r\n        document_code,\r\n        logo_url,\r\n        base_contract_text,\r\n        created_by\r\n    )\r\n    VALUES (\r\n        v_tenant_id,\r\n        (p_data->>'template_name'),\r\n        v_new_version,\r\n        (p_data->>'is_active')::boolean,\r\n        (p_data->>'document_date')::date,\r\n        v_document_code,\r\n        (p_data->>'logo_url'),\r\n        (p_data->>'base_contract_text'),\r\n        (p_data->>'created_by')::uuid\r\n    )\r\n    RETURNING id INTO v_template_id;\r\n\r\n    -- 2. Insertamos las condiciones (Hacemos el loop interno con jsonb_to_recordset)\r\n    INSERT INTO public.order_template_conditions (\r\n        tenant_id,\r\n        order_template_id,\r\n        label,\r\n        is_special,\r\n        special_condition_label,\r\n        default_value\r\n    )\r\n    SELECT \r\n        v_tenant_id,\r\n        v_template_id,\r\n        t.label,\r\n        t.is_special,\r\n        t.special_condition_label,\r\n        t.default_value::public.condition_response_enum\r\n    FROM jsonb_to_recordset(p_data->'conditions') AS t(\r\n        label text,\r\n        is_special boolean,\r\n        special_condition_label text,\r\n        default_value text\r\n    );\r\n\r\n    -- 3. PROCESO DE FIRMAS Y DECLARACIONES\r\n    FOR v_signature_record IN SELECT * FROM jsonb_array_elements(p_data->'signatures')\r\n    LOOP\r\n        -- A. Insertamos la Firma actual del loop\r\n        INSERT INTO public.order_template_signatures (\r\n            tenant_id,\r\n            order_template_id,\r\n            representative_type,\r\n            signature_label\r\n        )\r\n        VALUES (\r\n            v_tenant_id,\r\n            v_template_id,\r\n            v_signature_record->>'a_quien_representa',\r\n            v_signature_record->>'label_firma'\r\n        )\r\n        RETURNING id INTO v_signature_id;\r\n\r\n        -- B. Insertamos todas las declaraciones de ESTA firma específica\r\n        INSERT INTO public.order_template_signature_conditions (\r\n            tenant_id,\r\n            order_template_signature_id,\r\n            declaration_text\r\n        )\r\n        SELECT \r\n            v_tenant_id,\r\n            v_signature_id,\r\n            d.texto_declaracion\r\n        FROM jsonb_to_recordset(v_signature_record->'declarations') AS d(\r\n            texto_declaracion text\r\n        );\r\n    END LOOP;\r\n\r\n    -- Devolvemos el ID generado\r\n    RETURN v_template_id;\r\nEND;\r\n$$"}	ALTER_function_create_full_order_template_addversionprotection
20260608224045	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    uuid,      -- p_tenant_id\r\n    integer,   -- p_limit\r\n    integer,   -- p_offset\r\n    text,      -- p_placa\r\n    public.order_status_enum, -- p_estado\r\n    date,      -- p_fecha_desde\r\n    date,      -- p_fecha_hasta\r\n    text,      -- p_cliente_documento\r\n    text       -- p_propietario_documento\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    -- Tenant obligatorio para aislamiento multiempresa\r\n    p_tenant_id UUID,\r\n\r\n    -- Cuántos registros traer\r\n    p_limit INTEGER DEFAULT 20,\r\n\r\n    -- Desde qué posición empezar (paginación)\r\n    p_offset INTEGER DEFAULT 0,\r\n\r\n    -- Filtros opcionales\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL,\r\n\r\n    --filtros para el ordenamiento\r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n\r\n    -- 🌟 NUEVO FILTRO GLOBAL (OPCIONAL)\r\n    p_search_term TEXT DEFAULT NULL\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    RETURN QUERY\r\n    SELECT\r\n        -- =====================================================================\r\n        -- TODO SE SACA DIRECTAMENTE DESDE LA TABLA DE ORDENES (GRACIAS A LOS SNAPSHOTS)\r\n        -- =====================================================================\r\n        o.id,\r\n        o.vehiculo_placa_snapshot::TEXT,\r\n        o.fecha,\r\n        o.vehiculo_marca_snapshot::TEXT,\r\n        o.vehiculo_linea_snapshot::TEXT,\r\n        o.propietario_nombre_snapshot,\r\n        o.propietario_numero_documento_snapshot::TEXT,\r\n        o.cliente_nombre_snapshot,\r\n        o.cliente_numero_documento_snapshot::TEXT,\r\n        o.estado_orden,\r\n        \r\n        -- Conteo total eficiente usando función de ventana\r\n        COUNT(*) OVER() AS total_count\r\n\r\n    FROM public.entry_orders o\r\n    WHERE\r\n        -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n        o.tenant_id = p_tenant_id\r\n        AND o.deleted_at IS NULL\r\n        \r\n        -- FILTRO POR PLACA (Sobre el Snapshot)\r\n        AND (p_placa IS NULL OR o.vehiculo_placa_snapshot ILIKE '%' || TRIM(p_placa) || '%')\r\n        \r\n        -- FILTRO POR ESTADO\r\n        AND (p_estado IS NULL OR o.estado_orden = p_estado)\r\n        \r\n        -- FILTROS DE FECHAS\r\n        AND o.fecha::DATE >= p_fecha_desde\r\n        AND o.fecha::DATE <= p_fecha_hasta\r\n        \r\n        -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n        AND (p_cliente_documento IS NULL OR o.cliente_numero_documento_snapshot ILIKE '%' || TRIM(p_cliente_documento) || '%')\r\n        \r\n        -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n        AND (p_propietario_documento IS NULL OR o.propietario_numero_documento_snapshot ILIKE '%' || TRIM(p_propietario_documento) || '%')\r\n\r\n    -- Más recientes primero\r\n    ORDER BY o.fecha DESC\r\n    LIMIT p_limit\r\n    OFFSET p_offset;\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_ADDsearchterm
20260608225056	{"CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_search_term TEXT DEFAULT NULL -- (Lo conectaremos en el siguiente paso)\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT,\r\n            o.vehiculo_linea_snapshot::TEXT,\r\n            o.propietario_nombre_snapshot,\r\n            o.propietario_numero_documento_snapshot::TEXT,\r\n            o.cliente_nombre_snapshot,\r\n            o.cliente_numero_documento_snapshot::TEXT,\r\n            o.estado_orden,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            o.tenant_id = $1\r\n            AND o.deleted_at IS NULL\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1\r\n        p_placa,                -- $2\r\n        p_estado,               -- $3\r\n        p_fecha_desde,          -- $4\r\n        p_fecha_hasta,          -- $5\r\n        p_cliente_documento,    -- $6\r\n        p_propietario_documento,  -- $7\r\n        p_limit,                -- $8\r\n        p_offset;               -- $9\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_ADDsearchtermCorregida
20260609151033	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID,      -- p_tenant_id\r\n    INTEGER,   -- p_limit\r\n    INTEGER,   -- p_offset\r\n    TEXT,      -- p_placa\r\n    public.order_status_enum, -- p_estado\r\n    DATE,      -- p_fecha_desde\r\n    DATE,      -- p_fecha_hasta\r\n    TEXT,      -- p_cliente_documento\r\n    TEXT,      -- p_propietario_documento \r\n    TEXT,      -- p_order_by_column\r\n    TEXT,      -- p_order_by_direction\r\n    TEXT       -- p_search_term\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_search_term TEXT DEFAULT NULL, -- (Lo conectaremos en el siguiente paso)\r\n    p_show_deleted BOOLEAN DEFAULT FALSE -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT,\r\n            o.vehiculo_linea_snapshot::TEXT,\r\n            o.propietario_nombre_snapshot,\r\n            o.propietario_numero_documento_snapshot::TEXT,\r\n            o.cliente_nombre_snapshot,\r\n            o.cliente_numero_documento_snapshot::TEXT,\r\n            o.estado_orden,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n         -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si $10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n              -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n             -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        --%I (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1\r\n        p_placa,                -- $2\r\n        p_estado,               -- $3\r\n        p_fecha_desde,          -- $4\r\n        p_fecha_hasta,          -- $5\r\n        p_cliente_documento,    -- $6\r\n        p_propietario_documento,  -- $7\r\n        p_limit,                -- $8\r\n        p_offset,               -- $9\r\n        p_show_deleted;         -- $10 🌟 $10 ADICIONADO AL FINAL DEL USING\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_addWatchAnulados
20260619213329	{"-- =========================================================================\r\n-- MIGRACIÓN: CAMPOS DE CONTROL PARA REINSPECCIONES EN ENTRY_ORDERS\r\n-- =========================================================================\r\n\r\n-- 1. Agregar las nuevas columnas de control de flujo\r\nALTER TABLE public.entry_orders \r\n  ADD COLUMN id_reprobado UUID NULL,\r\n  ADD COLUMN id_orden_reinspeccion UUID NULL","-- 2. Crear la restricción de Llave Foránea Autorreferencial (Self-Referencing FK)\r\n-- Vincula 'id_reprobado' hacia la misma tabla para heredar la integridad.\r\nALTER TABLE public.entry_orders\r\n  ADD CONSTRAINT entry_orders_id_reprobado_fkey \r\n  FOREIGN KEY (id_reprobado) \r\n  REFERENCES public.entry_orders(id) \r\n  ON DELETE SET NULL","-- Nota: No añadimos FK estricta a 'id_orden_reinspeccion' para evitar \r\n-- relaciones circulares infinitas durante los inserts concurrentes.\r\n\r\n-- 3. Crear índices optimizados para las búsquedas del RPC y TanStack\r\nCREATE INDEX IF NOT EXISTS entry_orders_id_reprobado_idx \r\n  ON public.entry_orders USING btree (id_reprobado)\r\n  WHERE id_reprobado IS NOT NULL","CREATE INDEX IF NOT EXISTS entry_orders_id_orden_reinspeccion_idx \r\n  ON public.entry_orders USING btree (id_orden_reinspeccion)\r\n  WHERE id_orden_reinspeccion IS NOT NULL","-- 4. Documentación del esquema en Postgres\r\nCOMMENT ON COLUMN public.entry_orders.id_reprobado IS 'Se llena en la REINSPECCIÓN. Guarda el UUID de la orden original que fue rechazada.'","COMMENT ON COLUMN public.entry_orders.id_orden_reinspeccion IS 'Se llena en la ORDEN ORIGINAL (Opcional/Históricos). Guarda el UUID de la orden que actuó como su reinspección.'","-- =========================================================================\r\n-- ANEXO MIGRACIÓN: COLUMNA DE CONTROL DE VENCIMIENTO (15 DÍAS)\r\n-- =========================================================================\r\n\r\n-- 1. Agregar la columna de fecha límite para la reinspección\r\nALTER TABLE public.entry_orders \r\n  ADD COLUMN fecha_limite_reinspeccion DATE NULL","-- 2. Crear un índice para búsquedas rápidas por expiración\r\nCREATE INDEX IF NOT EXISTS entry_orders_fecha_limite_reinspeccion_idx \r\n  ON public.entry_orders USING btree (fecha_limite_reinspeccion)\r\n  WHERE fecha_limite_reinspeccion IS NOT NULL","-- 3. Documentación del campo\r\nCOMMENT ON COLUMN public.entry_orders.fecha_limite_reinspeccion IS 'Fecha máxima (Fecha de la orden original + 15 días calendario) en la que el vehículo puede aplicar a una reinspección.'"}	ALTER_table_entry_orders_addCamposParaManejoDeReprobados
20260609152747	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID,      -- p_tenant_id\r\n    INTEGER,   -- p_limit\r\n    INTEGER,   -- p_offset\r\n    TEXT,      -- p_placa\r\n    public.order_status_enum, -- p_estado\r\n    DATE,      -- p_fecha_desde\r\n    DATE,      -- p_fecha_hasta\r\n    TEXT,      -- p_cliente_documento\r\n    TEXT,      -- p_propietario_documento \r\n    TEXT,      -- p_order_by_column\r\n    TEXT,      -- p_order_by_direction\r\n    TEXT       -- p_search_term\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_search_term TEXT DEFAULT NULL, -- (Lo conectaremos en el siguiente paso)\r\n    p_show_deleted BOOLEAN DEFAULT FALSE -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT,\r\n            o.vehiculo_linea_snapshot::TEXT,\r\n            o.propietario_nombre_snapshot,\r\n            o.propietario_numero_documento_snapshot::TEXT,\r\n            o.cliente_nombre_snapshot,\r\n            o.cliente_numero_documento_snapshot::TEXT,\r\n            o.estado_orden,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n         -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n              -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n             -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        --la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1\r\n        p_placa,                -- $2\r\n        p_estado,               -- $3\r\n        p_fecha_desde,          -- $4\r\n        p_fecha_hasta,          -- $5\r\n        p_cliente_documento,    -- $6\r\n        p_propietario_documento,  -- $7\r\n        p_limit,                -- $8\r\n        p_offset,               -- $9\r\n        p_show_deleted;         -- $10 🌟 $10 ADICIONADO AL FINAL DEL USING\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_addWatchAnuladosCorregido
20260610015758	{"-- 🗑️ BORRAR LA FUNCIÓN ANTERIOR (Obligatorio porque cambiaron los parámetros de entrada)\r\nDROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID,     -- p_tenant_id\r\n    INTEGER,  -- p_limit\r\n    INTEGER,  -- p_offset\r\n    TEXT,     -- p_placa\r\n    public.order_status_enum, -- p_estado\r\n    DATE,     -- p_fecha_desde\r\n    DATE,     -- p_fecha_hasta\r\n    TEXT,     -- p_cliente_documento\r\n    TEXT,     -- p_propietario_documento\r\n    TEXT,     -- p_order_by_column\r\n    TEXT,     -- p_order_by_direction\r\n    TEXT,     -- p_search_term (El parámetro que tenías antes de este cambio)\r\n    BOOLEAN   -- p_show_deleted\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT,\r\n            o.vehiculo_linea_snapshot::TEXT,\r\n            o.propietario_nombre_snapshot,\r\n            o.propietario_numero_documento_snapshot::TEXT,\r\n            o.cliente_nombre_snapshot,\r\n            o.cliente_numero_documento_snapshot::TEXT,\r\n            o.estado_orden,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list
20260611181156	{"CREATE TYPE public.user_role_enum AS ENUM (\r\n            'gerente',\r\n            'recepcionista',\r\n            'aux_administrativo',\r\n            'director_tecnico'\r\n        )","-- Añadimos un comentario a la base de datos para documentar el tipo\r\n        COMMENT ON TYPE public.user_role_enum IS 'Roles asignados a los usuarios dentro del CDA para control de accesos (SGC / ISO 17020).'"}	CREATE_enum_user_roles
20260611181553	{"-- 1. ELIMINAR DEPENDENCIAS VIEJAS\r\n    -- Quitamos el CHECK antiguo porque el ENUM ahora validará los valores por sí solo de forma nativa\r\nALTER TABLE public.tenant_permissions DROP CONSTRAINT IF EXISTS tenant_permissions_role_check","-- Quitamos temporalmente la restricción UNIQUE que involucra la columna role\r\nALTER TABLE public.tenant_permissions  DROP CONSTRAINT IF EXISTS tenant_permissions_unique_triplet","-- 2. TRANSICIÓN DE LA COLUMNA AL NUEVO TIPO ENUM\r\n-- Eliminamos el valor por defecto de texto temporalmente para evitar conflictos de tipo\r\nALTER TABLE public.tenant_permissions  ALTER COLUMN role DROP DEFAULT","-- Cambiamos el tipo de columna usando USING para castear el texto existente al ENUM de forma segura\r\n    ALTER TABLE public.tenant_permissions \r\n        ALTER COLUMN role TYPE public.user_role_enum \r\n        USING role::public.user_role_enum","-- Volvemos a aplicar el valor por defecto, pero ahora mapeado bajo el nuevo tipo ENUM\r\n    ALTER TABLE public.tenant_permissions ALTER COLUMN role SET DEFAULT 'recepcionista'::public.user_role_enum","-- 3. RECONSTRUIR RESTRICCIONES Y CONFIGURACIONES\r\n    -- Volvemos a levantar la restricción UNIQUE (ahora protegiendo con el ENUM acoplado)\r\n    ALTER TABLE public.tenant_permissions\r\n    ADD CONSTRAINT tenant_permissions_unique_triplet \r\n    UNIQUE (tenant_id, service_user_id, role)","-- Actualizamos el comentario explicativo de la columna en la base de datos\r\n    COMMENT ON COLUMN public.tenant_permissions.role IS 'Rol del usuario en el CDA administrado mediante el tipo estructurado public.user_role_enum.'"}	ALTER_table_tenant_permissions_addEnumRoles
20260612203535	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID, \r\n    INTEGER, \r\n    INTEGER, \r\n    TEXT, \r\n    public.order_status_enum, \r\n    DATE, \r\n    DATE, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    BOOLEAN, \r\n    TEXT, \r\n    TEXT\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,     -- 🌟 NUEVO\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,         -- 🌟 NUEVO\r\n    es_reinspeccion BOOLEAN,             -- 🌟 NUEVO\r\n    kilometraje CHARACTER VARYING,       -- 🌟 NUEVO\r\n    soat_vencimiento_snapshot DATE,      -- 🌟 NUEVO\r\n    service_type public.service_type_enum, -- 🌟 NUEVO (RTM, etc.)\r\n    vehiculo_tipo_snapshot public.vehicle_type_enum, -- 🌟 NUEVO (Liviano, pesado, moto)\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT AS placa,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT AS marca,\r\n            o.vehiculo_linea_snapshot::TEXT AS linea,\r\n            o.propietario_nombre_snapshot AS propietario_nombre,\r\n            o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n            o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,   -- 🌟 NUEVO\r\n            o.cliente_nombre_snapshot AS cliente_nombre,\r\n            o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n            o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,           -- 🌟 NUEVO\r\n            o.es_reinspeccion,                                                           -- 🌟 NUEVO\r\n            o.kilometraje,                                                               -- 🌟 NUEVO\r\n            o.soat_vencimiento_snapshot,                                                 -- 🌟 NUEVO\r\n            o.service_type,                                                              -- 🌟 NUEVO\r\n            o.vehiculo_tipo_snapshot,                                                    -- 🌟 NUEVO\r\n            o.estado_orden,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_function_entry_orders_list_fetchMasDatos
20260613012008	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID, \r\n    INTEGER, \r\n    INTEGER, \r\n    TEXT, \r\n    public.order_status_enum, \r\n    DATE, \r\n    DATE, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    BOOLEAN, \r\n    TEXT, \r\n    TEXT\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,     -- 🌟 NUEVO\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,         -- 🌟 NUEVO\r\n    es_reinspeccion BOOLEAN,             -- 🌟 NUEVO\r\n    kilometraje CHARACTER VARYING,       -- 🌟 NUEVO\r\n    soat_vencimiento_snapshot DATE,      -- 🌟 NUEVO\r\n    service_type public.service_type_enum, -- 🌟 NUEVO (RTM, etc.)\r\n    vehiculo_tipo_snapshot public.vehicle_type_enum, -- 🌟 NUEVO (Liviano, pesado, moto)\r\n    vehiculo_tipo_servicio_snapshot public.vehicle_service_type_enum,\r\n    estado_orden public.order_status_enum,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT AS placa,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT AS marca,\r\n            o.vehiculo_linea_snapshot::TEXT AS linea,\r\n            o.propietario_nombre_snapshot AS propietario_nombre,\r\n            o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n            o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,   -- 🌟 NUEVO\r\n            o.cliente_nombre_snapshot AS cliente_nombre,\r\n            o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n            o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,           -- 🌟 NUEVO\r\n            o.es_reinspeccion,                                                           -- 🌟 NUEVO\r\n            o.kilometraje,                                                               -- 🌟 NUEVO\r\n            o.soat_vencimiento_snapshot,                                                 -- 🌟 NUEVO\r\n            o.service_type,                                                              -- 🌟 NUEVO\r\n            o.vehiculo_tipo_snapshot,                                                    -- 🌟 NUEVO\r\n            o.vehiculo_tipo_servicio_snapshot,\r\n            o.estado_orden,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_entry_orders_list_ADDVehiculoTipoServicio
20260613150536	{"-- =========================================================================\r\n-- 1. CREACIÓN DEL ENUM PARA TIPOS DE PAGO EN LA OFICINA\r\n-- =========================================================================\r\nCREATE TYPE public.office_payment_type_enum AS ENUM (\r\n  'efectivo', \r\n  'tarjeta_debito', \r\n  'tarjeta_credito', \r\n  'sistecredito', \r\n  'addi', \r\n  'transferencia', \r\n  'qr'\r\n)","-- =========================================================================\r\n-- 2. ALTERACIÓN DE LA TABLA ENTRY_ORDERS PARA AGREGAR NUEVOS CAMPOS\r\n-- =========================================================================\r\nALTER TABLE public.entry_orders\r\n  -- Datos financieros y de control de la oficina\r\n  ADD COLUMN oficina_pin character varying NULL,\r\n  ADD COLUMN oficina_pago numeric(12,2) NULL DEFAULT 0.00,\r\n  ADD COLUMN oficina_consecutivo_factura character varying NULL,\r\n  ADD COLUMN oficina_tipo_pago public.office_payment_type_enum NULL,\r\n\r\n  -- Datos obligatorios del RUNT y procesos internos del CDA\r\n  ADD COLUMN oficina_fupas character varying NULL,\r\n  ADD COLUMN oficina_certificados_runt character varying NULL,\r\n\r\n  -- Control y adicionales comerciales\r\n  ADD COLUMN se_compro_soat boolean NOT NULL DEFAULT false,\r\n  ADD COLUMN resultado_revision text NULL","-- =========================================================================\r\n-- 3. OPTIMIZACIÓN: ÍNDICES COMPUESTOS PARA MULTI-TENANCY\r\n-- =========================================================================\r\n-- Índice para búsquedas por factura (Cuadres de caja, reportes de ingresos)\r\nCREATE INDEX IF NOT EXISTS entry_orders_oficina_factura_tenant_idx \r\nON public.entry_orders USING btree (tenant_id, oficina_consecutivo_factura) \r\nTABLESPACE pg_default","-- Índice para auditorías u operaciones por número de FUPAS\r\nCREATE INDEX IF NOT EXISTS entry_orders_oficina_fupas_idx \r\nON public.entry_orders USING btree (tenant_id, oficina_fupas) \r\nTABLESPACE pg_default","-- Índice para auditorías de la ONAC o búsquedas por certificado RUNT\r\nCREATE INDEX IF NOT EXISTS entry_orders_oficina_certificados_runt_idx \r\nON public.entry_orders USING btree (tenant_id, oficina_certificados_runt) \r\nTABLESPACE pg_default","-- =========================================================================\r\n-- 4. COMENTARIOS\r\n-- =========================================================================\r\n\r\nCOMMENT ON COLUMN public.entry_orders.oficina_tipo_pago IS \r\n'Registra la modalidad de pago con la que el cliente canceló la Revisión Técnico-Mecánica (RTM) u otros servicios. Vinculado al enum office_payment_type_enum.'","COMMENT ON TYPE public.office_payment_type_enum IS \r\n'Métodos de pago autorizados para la facturación de servicios en la caja de la oficina del CDA.\r\nValores permitidos:\r\n  - efectivo: Pago con moneda corriente física.\r\n  - tarjeta_debito: Tarjeta de débito bancaria (Mister, Visa, etc.).\r\n  - tarjeta_credito: Tarjeta de crédito (Franquicias tradicionales).\r\n  - sistecredito: Línea de crédito y financiamiento por plataforma Sistecrédito.\r\n  - addi: Compra a cuotas mediante la pasarela fintech Addi.\r\n  - transferencia: Transferencias directas verificadas (Bancolombia, Nequi, Daviplata, etc.).\r\n  - qr: Pagos mediante códigos QR de interoperabilidad bancaria.\r\nEste tipo es crítico para los cierres, arqueos de caja diarios y auditorías contables.'"}	ALTER_table_entry_orders_addNewFieldsAndPagoEnum
20260613182531	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID, \r\n    INTEGER, \r\n    INTEGER, \r\n    TEXT, \r\n    public.order_status_enum, \r\n    DATE, \r\n    DATE, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    BOOLEAN, \r\n    TEXT, \r\n    TEXT\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,     -- 🌟 NUEVO\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,         -- 🌟 NUEVO\r\n    es_reinspeccion BOOLEAN,             -- 🌟 NUEVO\r\n    kilometraje CHARACTER VARYING,       -- 🌟 NUEVO\r\n    soat_vencimiento_snapshot DATE,      -- 🌟 NUEVO\r\n    service_type public.service_type_enum, -- 🌟 NUEVO (RTM, etc.)\r\n    vehiculo_tipo_snapshot public.vehicle_type_enum, -- 🌟 NUEVO (Liviano, pesado, moto)\r\n    vehiculo_tipo_servicio_snapshot public.vehicle_service_type_enum,\r\n    estado_orden public.order_status_enum,\r\n    \r\n    -- 🌟 NUEVOS CAMPOS DE OFICINA\r\n    oficina_pin CHARACTER VARYING,\r\n    oficina_pago NUMERIC(12,2),\r\n    oficina_consecutivo_factura CHARACTER VARYING,\r\n    oficina_tipo_pago public.office_payment_type_enum,\r\n    oficina_fupas CHARACTER VARYING,\r\n    oficina_certificados_runt CHARACTER VARYING,\r\n    se_compro_soat BOOLEAN,\r\n    resultado_revision TEXT,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT AS placa,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT AS marca,\r\n            o.vehiculo_linea_snapshot::TEXT AS linea,\r\n            o.propietario_nombre_snapshot AS propietario_nombre,\r\n            o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n            o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,   -- 🌟 NUEVO\r\n            o.cliente_nombre_snapshot AS cliente_nombre,\r\n            o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n            o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,           -- 🌟 NUEVO\r\n            o.es_reinspeccion,                                                           -- 🌟 NUEVO\r\n            o.kilometraje,                                                               -- 🌟 NUEVO\r\n            o.soat_vencimiento_snapshot,                                                 -- 🌟 NUEVO\r\n            o.service_type,                                                              -- 🌟 NUEVO\r\n            o.vehiculo_tipo_snapshot,                                                    -- 🌟 NUEVO\r\n            o.vehiculo_tipo_servicio_snapshot,\r\n            o.estado_orden,\r\n            -- 🌟 MAPEO DE NUEVOS CAMPOS DESDE LA TABLA\r\n            o.oficina_pin,\r\n            o.oficina_pago,\r\n            o.oficina_consecutivo_factura,\r\n            o.oficina_tipo_pago,\r\n            o.oficina_fupas,\r\n            o.oficina_certificados_runt,\r\n            o.se_compro_soat,\r\n            o.resultado_revision,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_ADDoficinaFetchs
20260613194923	{"ALTER TABLE public.entry_orders\r\n  DROP COLUMN IF EXISTS oficina_fupas,\r\n  DROP COLUMN IF EXISTS oficina_certificados_runt","-- 2. Eliminar los índices asociados para no dejar basura en la base de datos\r\nDROP INDEX IF EXISTS public.entry_orders_oficina_fupas_idx","DROP INDEX IF EXISTS public.entry_orders_oficina_certificados_runt_idx"}	ALTER_table_entry_orders_DROPtemporalmentefupasycertificadosrtm
20260613195359	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    UUID, \r\n    INTEGER, \r\n    INTEGER, \r\n    TEXT, \r\n    public.order_status_enum, \r\n    DATE, \r\n    DATE, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    TEXT, \r\n    BOOLEAN, \r\n    TEXT, \r\n    TEXT\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,     -- 🌟 NUEVO\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,         -- 🌟 NUEVO\r\n    es_reinspeccion BOOLEAN,             -- 🌟 NUEVO\r\n    kilometraje CHARACTER VARYING,       -- 🌟 NUEVO\r\n    soat_vencimiento_snapshot DATE,      -- 🌟 NUEVO\r\n    service_type public.service_type_enum, -- 🌟 NUEVO (RTM, etc.)\r\n    vehiculo_tipo_snapshot public.vehicle_type_enum, -- 🌟 NUEVO (Liviano, pesado, moto)\r\n    vehiculo_tipo_servicio_snapshot public.vehicle_service_type_enum,\r\n    estado_orden public.order_status_enum,\r\n    \r\n    -- 🌟 NUEVOS CAMPOS DE OFICINA\r\n    oficina_pin CHARACTER VARYING,\r\n    oficina_pago NUMERIC(12,2),\r\n    oficina_consecutivo_factura CHARACTER VARYING,\r\n    oficina_tipo_pago public.office_payment_type_enum,\r\n    \r\n    se_compro_soat BOOLEAN,\r\n    resultado_revision TEXT,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT AS placa,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT AS marca,\r\n            o.vehiculo_linea_snapshot::TEXT AS linea,\r\n            o.propietario_nombre_snapshot AS propietario_nombre,\r\n            o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n            o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,   -- 🌟 NUEVO\r\n            o.cliente_nombre_snapshot AS cliente_nombre,\r\n            o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n            o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,           -- 🌟 NUEVO\r\n            o.es_reinspeccion,                                                           -- 🌟 NUEVO\r\n            o.kilometraje,                                                               -- 🌟 NUEVO\r\n            o.soat_vencimiento_snapshot,                                                 -- 🌟 NUEVO\r\n            o.service_type,                                                              -- 🌟 NUEVO\r\n            o.vehiculo_tipo_snapshot,                                                    -- 🌟 NUEVO\r\n            o.vehiculo_tipo_servicio_snapshot,\r\n            o.estado_orden,\r\n            -- 🌟 MAPEO DE NUEVOS CAMPOS DESDE LA TABLA\r\n            o.oficina_pin,\r\n            o.oficina_pago,\r\n            o.oficina_consecutivo_factura,\r\n            o.oficina_tipo_pago,\r\n           \r\n            o.se_compro_soat,\r\n            o.resultado_revision,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_funcion_fetch_entry_orders_list_DROPfupasycertificadosrunttemporalmente
20260616000545	{"CREATE OR REPLACE FUNCTION public.update_office_order_data(\r\n    p_order_id uuid,\r\n    p_pin character varying,\r\n    p_pago numeric,\r\n    p_consecutivo_factura character varying,\r\n    p_tipo_pago text,  -- Se recibe como text para castearlo de forma segura al enum de la BD\r\n    p_se_compro_soat boolean\r\n)\r\nRETURNS void\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 1. Verificación defensiva de la existencia de la orden de entrada\r\n    IF NOT EXISTS (SELECT 1 FROM public.entry_orders WHERE id = p_order_id) THEN\r\n        RAISE EXCEPTION 'La orden de entrada con ID % no existe.', p_order_id;\r\n    END IF;\r\n\r\n    -- 2. Ejecución de la actualización de datos de liquidación y oficina\r\n    UPDATE public.entry_orders\r\n    SET\r\n        oficina_pin = NULLIF(TRIM(p_pin), ''),\r\n        oficina_pago = COALESCE(p_pago, 0.00),\r\n        oficina_consecutivo_factura = NULLIF(TRIM(p_consecutivo_factura), ''),\r\n        oficina_tipo_pago = p_tipo_pago::public.office_payment_type_enum, -- Casteo dinámico al ENUM oficial de tu BD\r\n        se_compro_soat = COALESCE(p_se_compro_soat, false),\r\n        updated_at = NOW() -- Forzamos actualización manual aunque el trigger BEFORE UPDATE de tu BD ya lo haga\r\n    WHERE id = p_order_id;\r\n\r\n    -- Nota: Al usar la cláusula WHERE id = p_order_id, garantizamos que si el usuario \r\n    -- reenvía los datos desde la interfaz de la oficina, estos se sobrescriban (actualicen) \r\n    -- de forma transparente sobre el mismo registro.\r\n\r\nEND;\r\n$$"}	CREATE_function_update_order_data
20260616030323	{"DROP FUNCTION IF EXISTS public.update_office_order_data(\r\n    uuid, \r\n    character varying, \r\n    numeric, \r\n    character varying, \r\n    text, \r\n    boolean\r\n)","CREATE OR REPLACE FUNCTION public.update_office_order_data(\r\n    p_order_id uuid,\r\n    p_pin character varying,\r\n    p_pago numeric,\r\n    p_consecutivo_factura character varying,\r\n    p_tipo_pago text,\r\n    p_se_compro_soat boolean\r\n)\r\nRETURNS text -- 🌟 Cambiado de void a text para retornar el mensaje de éxito\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 1. Verificación defensiva de la existencia de la orden\r\n    IF NOT EXISTS (SELECT 1 FROM public.entry_orders WHERE id = p_order_id) THEN\r\n        RAISE EXCEPTION 'La orden de entrada con ID % no existe.', p_order_id;\r\n    END IF;\r\n\r\n    -- 2. Ejecución de la actualización\r\n    UPDATE public.entry_orders\r\n    SET\r\n        oficina_pin = NULLIF(TRIM(p_pin), ''),\r\n        oficina_pago = COALESCE(p_pago, 0.00),\r\n        oficina_consecutivo_factura = NULLIF(TRIM(p_consecutivo_factura), ''),\r\n        oficina_tipo_pago = p_tipo_pago::public.office_payment_type_enum,\r\n        se_compro_soat = COALESCE(p_se_compro_soat, false),\r\n        estado_orden = 'en_prueba'::public.order_status_enum, -- 🌟 Cambia el estado para habilitarla en pista\r\n        updated_at = NOW()\r\n    WHERE id = p_order_id;\r\n\r\n    -- 3. Retornamos el string exacto que necesitas\r\n    RETURN 'Datos guardados con exito';\r\n\r\nEND;\r\n$$"}	ALTER_function_update_order_data_addReturn
20260617002918	{"-- MIGRACIÓN: Agregar campos de control para el Director Técnico (ISO 17020)\r\n\r\n-- 1. Agregar columnas para los consecutivos de RTM y FUR\r\nALTER TABLE public.entry_orders \r\n  ADD COLUMN consecutivo_fur character varying NULL,\r\n  ADD COLUMN consecutivo_rtm character varying NULL","-- 2. Comentarios de documentación en la base de datos (Excelente para auditorías de la ONAC/Supertransporte)\r\nCOMMENT ON COLUMN public.entry_orders.consecutivo_fur IS 'Número del Formato Uniforme de Resultados generado en la inspección'","COMMENT ON COLUMN public.entry_orders.consecutivo_rtm IS 'Número del certificado de Revisión Tecnicomecánica emitido (Satisface RUNT)'","-- 3. Crear índices para optimizar las búsquedas por estos documentos (Muy común al auditar un vehículo específico)\r\nCREATE INDEX IF NOT EXISTS entry_orders_consecutivo_fur_idx \r\n  ON public.entry_orders USING btree (tenant_id, consecutivo_fur) \r\n  TABLESPACE pg_default","CREATE INDEX IF NOT EXISTS entry_orders_consecutivo_rtm_idx \r\n  ON public.entry_orders USING btree (tenant_id, consecutivo_rtm) \r\n  TABLESPACE pg_default"}	ALTER_table_entry_orders_addResultadoFinalyconsecutivo
20260617024421	{"-- DROP de la función existente para permitir el cambio en la estructura de la tabla de retorno (RETURNS TABLE)\r\nDROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER,\r\n    p_offset INTEGER,\r\n    p_placa TEXT,\r\n    p_estado public.order_status_enum,\r\n    p_fecha_desde DATE,\r\n    p_fecha_hasta DATE,\r\n    p_cliente_documento TEXT,\r\n    p_propietario_documento TEXT, \r\n    p_order_by_column TEXT,\r\n    p_order_by_direction TEXT,\r\n    p_show_deleted BOOLEAN,\r\n    p_search_column TEXT,\r\n    p_search_term TEXT\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,     -- 🌟 NUEVO\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,         -- 🌟 NUEVO\r\n    es_reinspeccion BOOLEAN,             -- 🌟 NUEVO\r\n    kilometraje CHARACTER VARYING,       -- 🌟 NUEVO\r\n    soat_vencimiento_snapshot DATE,      -- 🌟 NUEVO\r\n    service_type public.service_type_enum, -- 🌟 NUEVO (RTM, etc.)\r\n    vehiculo_tipo_snapshot public.vehicle_type_enum, -- 🌟 NUEVO (Liviano, pesado, moto)\r\n    vehiculo_tipo_servicio_snapshot public.vehicle_service_type_enum,\r\n    estado_orden public.order_status_enum,\r\n    \r\n    -- 🌟 NUEVOS CAMPOS DE OFICINA\r\n    oficina_pin CHARACTER VARYING,\r\n    oficina_pago NUMERIC(12,2),\r\n    oficina_consecutivo_factura CHARACTER VARYING,\r\n    oficina_tipo_pago public.office_payment_type_enum,\r\n    oficina_fupas CHARACTER VARYING,\r\n    oficina_certificados_runt CHARACTER VARYING,\r\n    se_compro_soat BOOLEAN,\r\n    resultado_revision TEXT,\r\n    consecutivo_fur CHARACTER VARYING,\r\n    consecutivo_rtm CHARACTER VARYING,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT AS placa,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT AS marca,\r\n            o.vehiculo_linea_snapshot::TEXT AS linea,\r\n            o.propietario_nombre_snapshot AS propietario_nombre,\r\n            o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n            o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,   -- 🌟 NUEVO\r\n            o.cliente_nombre_snapshot AS cliente_nombre,\r\n            o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n            o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,           -- 🌟 NUEVO\r\n            o.es_reinspeccion,                                                           -- 🌟 NUEVO\r\n            o.kilometraje,                                                               -- 🌟 NUEVO\r\n            o.soat_vencimiento_snapshot,                                                 -- 🌟 NUEVO\r\n            o.service_type,                                                              -- 🌟 NUEVO\r\n            o.vehiculo_tipo_snapshot,                                                    -- 🌟 NUEVO\r\n            o.vehiculo_tipo_servicio_snapshot,\r\n            o.estado_orden,\r\n            -- 🌟 MAPEO DE NUEVOS CAMPOS DESDE LA TABLA\r\n            o.oficina_pin,\r\n            o.oficina_pago,\r\n            o.oficina_consecutivo_factura,\r\n            o.oficina_tipo_pago,\r\n            o.oficina_fupas,\r\n            o.oficina_certificados_runt,\r\n            o.se_compro_soat,\r\n            o.resultado_revision,\r\n            o.consecutivo_fur,\r\n            o.consecutivo_rtm,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_addDirectorTecnicoFields
20260617025230	{"DROP FUNCTION IF EXISTS public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER,\r\n    p_offset INTEGER,\r\n    p_placa TEXT,\r\n    p_estado public.order_status_enum,\r\n    p_fecha_desde DATE,\r\n    p_fecha_hasta DATE,\r\n    p_cliente_documento TEXT,\r\n    p_propietario_documento TEXT, \r\n    p_order_by_column TEXT,\r\n    p_order_by_direction TEXT,\r\n    p_show_deleted BOOLEAN,\r\n    p_search_column TEXT,\r\n    p_search_term TEXT\r\n)","CREATE OR REPLACE FUNCTION public.fetch_entry_orders_list(\r\n    p_tenant_id UUID,\r\n    p_limit INTEGER DEFAULT 20,\r\n    p_offset INTEGER DEFAULT 0,\r\n    p_placa TEXT DEFAULT NULL,\r\n    p_estado public.order_status_enum DEFAULT NULL,\r\n    p_fecha_desde DATE DEFAULT CURRENT_DATE,\r\n    p_fecha_hasta DATE DEFAULT CURRENT_DATE,\r\n    p_cliente_documento TEXT DEFAULT NULL,\r\n    p_propietario_documento TEXT DEFAULT NULL, \r\n    p_order_by_column TEXT DEFAULT 'fecha',\r\n    p_order_by_direction TEXT DEFAULT 'DESC',\r\n    p_show_deleted BOOLEAN DEFAULT FALSE, -- 🌟 NUEVO PARÁMETRO (Por defecto NO los muestra)\r\n    -- 🌟 PARÁMETROS NUEVOS PARA EL BUSCADOR AVANZADO\r\n    p_search_column TEXT DEFAULT NULL,   -- Recibe la columna del Select: 'placa', 'marca', 'linea', 'doc_cliente', 'doc_propietario'\r\n    p_search_term TEXT DEFAULT NULL      -- Recibe el texto que la recepcionista digita en el Input\r\n)\r\nRETURNS TABLE (\r\n    id UUID,\r\n    placa TEXT,\r\n    fecha TIMESTAMPTZ,\r\n    marca TEXT,\r\n    linea TEXT,\r\n    propietario_nombre TEXT,\r\n    propietario_documento TEXT,\r\n    propietario_tipo_documento TEXT,     -- 🌟 NUEVO\r\n    cliente_nombre TEXT,\r\n    cliente_documento TEXT,\r\n    cliente_tipo_documento TEXT,         -- 🌟 NUEVO\r\n    es_reinspeccion BOOLEAN,             -- 🌟 NUEVO\r\n    kilometraje CHARACTER VARYING,       -- 🌟 NUEVO\r\n    soat_vencimiento_snapshot DATE,      -- 🌟 NUEVO\r\n    service_type public.service_type_enum, -- 🌟 NUEVO (RTM, etc.)\r\n    vehiculo_tipo_snapshot public.vehicle_type_enum, -- 🌟 NUEVO (Liviano, pesado, moto)\r\n    vehiculo_tipo_servicio_snapshot public.vehicle_service_type_enum,\r\n    estado_orden public.order_status_enum,\r\n    \r\n    -- 🌟 NUEVOS CAMPOS DE OFICINA\r\n    oficina_pin CHARACTER VARYING,\r\n    oficina_pago NUMERIC(12,2),\r\n    oficina_consecutivo_factura CHARACTER VARYING,\r\n    oficina_tipo_pago public.office_payment_type_enum,\r\n   \r\n    se_compro_soat BOOLEAN,\r\n    resultado_revision TEXT,\r\n    consecutivo_fur CHARACTER VARYING,\r\n    consecutivo_rtm CHARACTER VARYING,\r\n    total_count BIGINT\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 💡 SOLO UN RETURN: Todo el query se vuelve un string dentro de format()\r\n    RETURN QUERY EXECUTE format('\r\n        SELECT\r\n            o.id,\r\n            o.vehiculo_placa_snapshot::TEXT AS placa,\r\n            o.fecha,\r\n            o.vehiculo_marca_snapshot::TEXT AS marca,\r\n            o.vehiculo_linea_snapshot::TEXT AS linea,\r\n            o.propietario_nombre_snapshot AS propietario_nombre,\r\n            o.propietario_numero_documento_snapshot::TEXT AS propietario_documento,\r\n            o.propietario_tipo_documento_snapshot::TEXT AS propietario_tipo_documento,   -- 🌟 NUEVO\r\n            o.cliente_nombre_snapshot AS cliente_nombre,\r\n            o.cliente_numero_documento_snapshot::TEXT AS cliente_documento,\r\n            o.cliente_tipo_documento_snapshot::TEXT AS cliente_tipo_documento,           -- 🌟 NUEVO\r\n            o.es_reinspeccion,                                                           -- 🌟 NUEVO\r\n            o.kilometraje,                                                               -- 🌟 NUEVO\r\n            o.soat_vencimiento_snapshot,                                                 -- 🌟 NUEVO\r\n            o.service_type,                                                              -- 🌟 NUEVO\r\n            o.vehiculo_tipo_snapshot,                                                    -- 🌟 NUEVO\r\n            o.vehiculo_tipo_servicio_snapshot,\r\n            o.estado_orden,\r\n            -- 🌟 MAPEO DE NUEVOS CAMPOS DESDE LA TABLA\r\n            o.oficina_pin,\r\n            o.oficina_pago,\r\n            o.oficina_consecutivo_factura,\r\n            o.oficina_tipo_pago,\r\n            \r\n            o.se_compro_soat,\r\n            o.resultado_revision,\r\n            o.consecutivo_fur,\r\n            o.consecutivo_rtm,\r\n            COUNT(*) OVER() AS total_count\r\n        FROM public.entry_orders o\r\n        WHERE\r\n            -- AISLAMIENTO MULTI-TENANT (Solo validamos el soft delete de la orden)\r\n            o.tenant_id = $1\r\n            \r\n            -- 🌟 NUEVO: Si porcentaje con el 10 es TRUE muestra todo, si es FALSE exige que deleted_at sea NULL\r\n            AND ($10 = TRUE OR o.deleted_at IS NULL)\r\n\r\n            -- FILTRO POR PLACA (Sobre el Snapshot)\r\n            AND ($2 IS NULL OR o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($2) || ''%%'')\r\n\r\n            -- FILTRO POR ESTADO\r\n            AND ($3 IS NULL OR o.estado_orden = $3)\r\n\r\n            -- FILTROS DE FECHAS\r\n            AND o.fecha::DATE >= $4\r\n            AND o.fecha::DATE <= $5\r\n\r\n            -- FILTRO DOCUMENTO CLIENTE (Sobre el Snapshot)\r\n            AND ($6 IS NULL OR o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($6) || ''%%'')\r\n\r\n            -- FILTRO DOCUMENTO PROPIETARIO (Sobre el Snapshot)\r\n            AND ($7 IS NULL OR o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($7) || ''%%'')\r\n            \r\n            -- 🌟 NUEVO BLOQUE: BÚSQUEDA EXCLUSIVA POR COLUMNA SELECCIONADA ($11 y $12)\r\n            -- Evaluamos dinámicamente según el valor que venga del componente Select de la UI\r\n            AND (\r\n                $12 IS NULL OR TRIM($12) = '''' -- Si la barra de búsqueda está vacía, ignora todo este bloque e imprime los datos normales\r\n                OR (\r\n                    CASE $11\r\n                        -- Si seleccionó \\"Placa\\", busca coincidencias parciales ignorando mayúsculas/minúsculas\r\n                        WHEN ''placa'' THEN \r\n                            o.vehiculo_placa_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Marca\\", busca en el snapshot del vehículo (ej: Chevrolet, Renault)\r\n                        WHEN ''marca'' THEN \r\n                            o.vehiculo_marca_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 NUEVO: Si seleccionó \\"Línea\\", busca en la línea/modelo del vehículo (ej: Spark, Logan)\r\n                        WHEN ''linea'' THEN \r\n                            o.vehiculo_linea_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del CLIENTE\r\n                        WHEN ''doc_cliente'' THEN \r\n                            o.cliente_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- 🌟 AJUSTADO: Busca estrictamente por el documento del PROPIETARIO\r\n                        WHEN ''doc_propietario'' THEN \r\n                            o.propietario_numero_documento_snapshot ILIKE ''%%'' || TRIM($12) || ''%%''\r\n                        \r\n                        -- Si mandan una columna inválida por error, no retorna filas por seguridad\r\n                        ELSE FALSE\r\n                    END\r\n                )\r\n            )\r\n            \r\n        -- 🌟 El ordenamiento se inyecta dinámicamente aquí antes de paginar\r\n        ORDER BY %I %s\r\n        \r\n        LIMIT $8 OFFSET $9\r\n\r\n        -- la I con el simbolo de porcentaje (Identificador): Le dice a la función: \\"Toma el string que te pasé (p_order_by_column) y escríbelo aquí como una columna real de la tabla, poniéndole comillas dobles si es necesario\\".\r\n    ', p_order_by_column, p_order_by_direction)\r\n    USING \r\n        p_tenant_id,            -- $1  (ID del CDA / Organización activa)\r\n        p_placa,                -- $2  (Filtro directo de placa)\r\n        p_estado,               -- $3  (Filtro directo por estado)\r\n        p_fecha_desde,          -- $4  (Rango de calendario inicial)\r\n        p_fecha_hasta,          -- $5  (Rango de calendario final)\r\n        p_cliente_documento,    -- $6  (Filtro de documento cliente)\r\n        p_propietario_documento,  -- $7  (Filtro de documento propietario)\r\n        p_limit,                -- $8  (Cantidad de filas a traer)\r\n        p_offset,               -- $9  (Paginación de las filas)\r\n        p_show_deleted,         -- $10 (Booleano para incluir órdenes anuladas)\r\n        p_search_column,        -- $11 🌟 (Columna activa del Select de búsqueda)\r\n        p_search_term;          -- $12 🌟 (Texto escrito en la barra de búsqueda)\r\nEND;\r\n$$"}	ALTER_function_fetch_entry_orders_list_dropfupasfetch
20260617035909	{"CREATE OR REPLACE FUNCTION public.update_director_tecnico_order(\r\n    p_order_id uuid,\r\n    p_resultado_revision text,\r\n    p_consecutivo_fur character varying,\r\n    p_consecutivo_rtm character varying\r\n)\r\nRETURNS text\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER -- Mantiene el estándar de seguridad de tu función de oficina\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 1. Verificación defensiva de la existencia de la orden\r\n    IF NOT EXISTS (SELECT 1 FROM public.entry_orders WHERE id = p_order_id) THEN\r\n        RAISE EXCEPTION 'La orden de entrada con ID % no existe.', p_order_id;\r\n    END IF;\r\n\r\n    -- 2. Ejecución de la actualización del Cierre Técnico (ISO 17020)\r\n    UPDATE public.entry_orders\r\n    SET\r\n        resultado_revision = NULLIF(TRIM(p_resultado_revision), ''),\r\n        consecutivo_fur = NULLIF(TRIM(p_consecutivo_fur), ''),\r\n        -- Si viene vacío o nulo desde el server action (ej: por rechazo), se guarda como NULL\r\n        consecutivo_rtm = NULLIF(TRIM(p_consecutivo_rtm), ''),\r\n        \r\n        -- Transición de estado: La orden culmina su ciclo operativo en el CDA\r\n        estado_orden = 'finalizada'::public.order_status_enum, \r\n        \r\n        updated_at = NOW()\r\n    WHERE id = p_order_id;\r\n\r\n    -- 3. Retorno de confirmación para el cliente/Server Action\r\n    RETURN 'Cierre técnico registrado con éxito';\r\n\r\nEND;\r\n$$"}	CREATE_function_update_director_tecnico_order
20260617040337	{"CREATE OR REPLACE FUNCTION public.update_director_tecnico_order(\r\n    p_order_id uuid,\r\n    p_resultado_revision text,\r\n    p_consecutivo_fur character varying,\r\n    p_consecutivo_rtm character varying\r\n)\r\nRETURNS text\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER -- Mantiene el estándar de seguridad de tu función de oficina\r\nSET search_path = public\r\nAS $$\r\nBEGIN\r\n    -- 1. Verificación defensiva de la existencia de la orden\r\n    IF NOT EXISTS (SELECT 1 FROM public.entry_orders WHERE id = p_order_id) THEN\r\n        RAISE EXCEPTION 'La orden de entrada con ID % no existe.', p_order_id;\r\n    END IF;\r\n\r\n    -- 2. Ejecución de la actualización del Cierre Técnico (ISO 17020)\r\n    UPDATE public.entry_orders\r\n    SET\r\n        resultado_revision = NULLIF(TRIM(p_resultado_revision), ''),\r\n        consecutivo_fur = NULLIF(TRIM(p_consecutivo_fur), ''),\r\n        -- Si viene vacío o nulo desde el server action (ej: por rechazo), se guarda como NULL\r\n        consecutivo_rtm = NULLIF(TRIM(p_consecutivo_rtm), ''),\r\n        \r\n        -- Transición de estado: La orden culmina su ciclo operativo en el CDA\r\n        estado_orden = 'finalizada'::public.order_status_enum \r\n        \r\n        \r\n    WHERE id = p_order_id;\r\n\r\n    -- 3. Retorno de confirmación para el cliente/Server Action\r\n    RETURN 'Cierre técnico registrado con éxito';\r\n\r\nEND;\r\n$$"}	CREATE_function_update_director_tecnico_order_dropUpdateDate
20260619223124	{"CREATE OR REPLACE FUNCTION public.check_preventiva_reinspection_eligibility(\r\n    p_placa CHARACTER VARYING,\r\n    p_tenant_id UUID\r\n)\r\nRETURNS JSONB\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER \r\nAS $$\r\nDECLARE\r\n    v_orden_original RECORD;\r\n    v_conteo_originales INT;\r\n    v_ya_reinspeccionada BOOLEAN;\r\nBEGIN\r\n\r\n\r\n\r\n    -- 1. Contar cuántas órdenes originales vigentes (sin vencer) existen para esa placa\r\n    -- Usamos: CURRENT_DATE <= fecha_limite_reinspeccion\r\n    SELECT COUNT(*)\r\n    INTO v_conteo_originales\r\n    FROM public.entry_orders\r\n    WHERE vehiculo_placa_snapshot = p_placa\r\n      AND tenant_id = p_tenant_id\r\n      AND es_reinspeccion = false\r\n      AND service_type = 'preventiva'\r\n      AND estado_orden = 'finalizada'\r\n      AND resultado_revision = 'rechazado'\r\n      AND CURRENT_DATE <= fecha_limite_reinspeccion -- 🌟 Validación directa con tu campo\r\n      AND deleted_at IS NULL;\r\n\r\n    IF v_conteo_originales > 1 THEN\r\n        RETURN jsonb_build_object(\r\n            'merece_reinspeccion', false,\r\n            'motivo', 'Error crítico: Existe más de una orden original rechazada vigente en el sistema para esta placa.'\r\n        );\r\n    END IF;\r\n\r\n\r\n\r\n    -- 2. Seleccionar la orden original vigente\r\n    SELECT id, fecha, fecha_limite_reinspeccion\r\n    INTO v_orden_original\r\n    FROM public.entry_orders\r\n    WHERE vehiculo_placa_snapshot = p_placa\r\n      AND tenant_id = p_tenant_id\r\n      AND es_reinspeccion = false\r\n      AND service_type = 'preventiva'\r\n      AND estado_orden = 'finalizada'\r\n      AND resultado_revision = 'rechazado'\r\n      AND CURRENT_DATE <= fecha_limite_reinspeccion -- 🌟 Validación directa con tu campo\r\n      AND deleted_at IS NULL\r\n    ORDER BY fecha DESC\r\n    LIMIT 1;\r\n\r\n    -- Si no hay ninguna orden que cumpla las condiciones o ya expiró la fecha límite\r\n    IF v_orden_original.id IS NULL THEN\r\n        RETURN jsonb_build_object(\r\n            'merece_reinspeccion', false,\r\n            'motivo', 'No se encontró ninguna revisión preventiva rechazada que esté vigente. El plazo legal ya expiró o no existe el registro.'\r\n        );\r\n    END IF;\r\n\r\n\r\n\r\n\r\n    -- 3. Comprobar que no se haya usado ya este derecho en otra orden de reinspección\r\n    SELECT EXISTS (\r\n        SELECT 1 \r\n        FROM public.entry_orders \r\n        WHERE id_reprobado = v_orden_original.id\r\n          AND es_reinspeccion = true\r\n          AND deleted_at IS NULL\r\n    ) INTO v_ya_reinspeccionada;\r\n\r\n    IF v_ya_reinspeccionada THEN\r\n        RETURN jsonb_build_object(\r\n            'merece_reinspeccion', false,\r\n            'motivo', 'El derecho a reinspección para esta orden ya fue utilizado.'\r\n        );\r\n    END IF;\r\n\r\n\r\n\r\n\r\n\r\n\r\n    -- 4. Todo correcto: Retornamos éxito y el ID del reprobado para el formulario\r\n    RETURN jsonb_build_object(\r\n        'merece_reinspeccion', true,\r\n        'motivo', 'Vehículo apto. Aplica para reinspección (Plazo límite: ' || to_char(v_orden_original.fecha_limite_reinspeccion, 'DD/MM/YYYY') || ')',\r\n        'id_reprobado', v_orden_original.id\r\n    );\r\n\r\nEND;\r\n$$"}	CREATE_function_check_preventiva_reinspection_eligibility
20260620153659	{"DROP FUNCTION IF EXISTS public.check_preventiva_reinspection_eligibility(p_placa CHARACTER VARYING, p_tenant_id UUID)","CREATE OR REPLACE FUNCTION public.check_preventiva_reinspection_eligibility(\r\n    p_placa CHARACTER VARYING,\r\n    p_tenant_id UUID\r\n)\r\nRETURNS TABLE (\r\n    merece_reinspeccion BOOLEAN,\r\n    motivo TEXT,\r\n    id_reprobado UUID\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY DEFINER\r\nAS $$\r\nDECLARE\r\n    v_orden_id UUID;\r\n    v_fecha_limite DATE;\r\n    v_conteo_originales INT;\r\n    v_ya_reinspeccionada BOOLEAN;\r\nBEGIN\r\n\r\n\r\n\r\n    -- 1. Contar cuántas órdenes originales vigentes existen\r\n    SELECT COUNT(*)\r\n    INTO v_conteo_originales\r\n    FROM public.entry_orders\r\n    WHERE vehiculo_placa_snapshot = p_placa\r\n      AND tenant_id = p_tenant_id\r\n      AND es_reinspeccion = false\r\n      AND service_type = 'preventiva'\r\n      AND estado_orden = 'finalizada'\r\n      AND resultado_revision = 'rechazado'\r\n      AND CURRENT_DATE <= fecha_limite_reinspeccion\r\n      AND deleted_at IS NULL;\r\n\r\n    IF v_conteo_originales > 1 THEN\r\n        merece_reinspeccion := false;\r\n        motivo := 'Error crítico: Existe más de una orden original rechazada vigente en el sistema para esta placa.';\r\n        id_reprobado := NULL;\r\n        RETURN NEXT;\r\n        RETURN;\r\n    END IF;\r\n\r\n\r\n\r\n\r\n    -- 2. Seleccionar la orden original vigente\r\n    SELECT id, fecha_limite_reinspeccion\r\n    INTO v_orden_id, v_fecha_limite\r\n    FROM public.entry_orders\r\n    WHERE vehiculo_placa_snapshot = p_placa\r\n      AND tenant_id = p_tenant_id\r\n      AND es_reinspeccion = false\r\n      AND service_type = 'preventiva'\r\n      AND estado_orden = 'finalizada'\r\n      AND resultado_revision = 'rechazado'\r\n      AND CURRENT_DATE <= fecha_limite_reinspeccion\r\n      AND deleted_at IS NULL\r\n    ORDER BY fecha DESC\r\n    LIMIT 1;\r\n\r\n    -- Si no hay ninguna orden que cumpla las condiciones o ya expiró\r\n    IF v_orden_id IS NULL THEN\r\n        merece_reinspeccion := false;\r\n        motivo := 'No se encontró ninguna revisión preventiva rechazada que esté vigente. El plazo legal ya expiró o no existe el registro.';\r\n        id_reprobado := NULL;\r\n        RETURN NEXT;\r\n        RETURN;\r\n    END IF;\r\n\r\n\r\n\r\n\r\n\r\n\r\n    -- 3. Comprobar que no se haya usado ya este derecho en otra orden de reinspección\r\n    SELECT EXISTS (\r\n        SELECT 1 \r\n        FROM public.entry_orders \r\n        WHERE public.entry_orders.id_reprobado = v_orden_id\r\n          AND es_reinspeccion = true\r\n          AND deleted_at IS NULL\r\n    ) INTO v_ya_reinspeccionada;\r\n\r\n    IF v_ya_reinspeccionada THEN\r\n        merece_reinspeccion := false;\r\n        motivo := 'El derecho a reinspección para esta orden ya fue utilizado.';\r\n        id_reprobado := NULL;\r\n        RETURN NEXT;\r\n        RETURN;\r\n    END IF;\r\n\r\n\r\n\r\n\r\n\r\n    -- 4. Todo correcto: Retornamos los datos asignando valores a las columnas de la tabla de salida\r\n    merece_reinspeccion := true;\r\n    motivo := 'Vehículo apto. Aplica para reinspección (Plazo límite: ' || to_char(v_fecha_limite, 'DD/MM/YYYY') || ')';\r\n    id_reprobado := v_orden_id;\r\n    \r\n    RETURN NEXT; -- Empuja la fila armada al resultado\r\nEND;\r\n$$"}	ALTER_function_check_preventiva_reinspection_eligibility_changejsonportable
20260620170947	{"DROP FUNCTION IF EXISTS public.check_preventiva_reinspection_eligibility(p_placa CHARACTER VARYING, p_tenant_id UUID)","CREATE OR REPLACE FUNCTION public.check_reinspection_eligibility_table(\r\n    p_placa CHARACTER VARYING,\r\n    p_tenant_id UUID\r\n)\r\nRETURNS TABLE (\r\n    merece_reinspeccion BOOLEAN,\r\n    motivo TEXT,\r\n    id_reprobado UUID\r\n)\r\nLANGUAGE plpgsql\r\nSECURITY INVOKER\r\nAS $$\r\nDECLARE\r\n    v_orden_id UUID;\r\n    v_fecha_limite DATE;\r\n    v_conteo_originales INT;\r\n    v_ya_reinspeccionada BOOLEAN;\r\nBEGIN\r\n\r\n\r\n\r\n    -- 1. Contar cuántas órdenes originales vigentes existen\r\n    SELECT COUNT(*)\r\n    INTO v_conteo_originales\r\n    FROM public.entry_orders\r\n    WHERE vehiculo_placa_snapshot = p_placa\r\n      AND tenant_id = p_tenant_id\r\n      AND es_reinspeccion = false\r\n      AND service_type = 'preventiva'\r\n      AND estado_orden = 'finalizada'\r\n      AND resultado_revision = 'rechazado'\r\n      AND CURRENT_DATE <= fecha_limite_reinspeccion\r\n      AND deleted_at IS NULL;\r\n\r\n    IF v_conteo_originales > 1 THEN\r\n        merece_reinspeccion := false;\r\n        motivo := 'Error crítico: Existe más de una orden original rechazada vigente en el sistema para esta placa.';\r\n        id_reprobado := NULL;\r\n        RETURN NEXT;\r\n        RETURN;\r\n    END IF;\r\n\r\n\r\n\r\n\r\n    -- 2. Seleccionar la orden original vigente\r\n    SELECT id, fecha_limite_reinspeccion\r\n    INTO v_orden_id, v_fecha_limite\r\n    FROM public.entry_orders\r\n    WHERE vehiculo_placa_snapshot = p_placa\r\n      AND tenant_id = p_tenant_id\r\n      AND es_reinspeccion = false\r\n      AND service_type = 'preventiva'\r\n      AND estado_orden = 'finalizada'\r\n      AND resultado_revision = 'rechazado'\r\n      AND CURRENT_DATE <= fecha_limite_reinspeccion\r\n      AND deleted_at IS NULL\r\n    ORDER BY fecha DESC\r\n    LIMIT 1;\r\n\r\n    -- Si no hay ninguna orden que cumpla las condiciones o ya expiró\r\n    IF v_orden_id IS NULL THEN\r\n        merece_reinspeccion := false;\r\n        motivo := 'No se encontró ninguna revisión preventiva rechazada que esté vigente. El plazo legal ya expiró o no existe el registro.';\r\n        id_reprobado := NULL;\r\n        RETURN NEXT;\r\n        RETURN;\r\n    END IF;\r\n\r\n\r\n\r\n\r\n\r\n\r\n    -- 3. Comprobar que no se haya usado ya este derecho en otra orden de reinspección\r\n    SELECT EXISTS (\r\n        SELECT 1 \r\n        FROM public.entry_orders \r\n        WHERE public.entry_orders.id_reprobado = v_orden_id\r\n          AND es_reinspeccion = true\r\n          AND deleted_at IS NULL\r\n    ) INTO v_ya_reinspeccionada;\r\n\r\n    IF v_ya_reinspeccionada THEN\r\n        merece_reinspeccion := false;\r\n        motivo := 'El derecho a reinspección para esta orden ya fue utilizado.';\r\n        id_reprobado := NULL;\r\n        RETURN NEXT;\r\n        RETURN;\r\n    END IF;\r\n\r\n\r\n\r\n\r\n\r\n    -- 4. Todo correcto: Retornamos los datos asignando valores a las columnas de la tabla de salida\r\n    merece_reinspeccion := true;\r\n    motivo := 'Vehículo apto. Aplica para reinspección (Plazo límite: ' || to_char(v_fecha_limite, 'DD/MM/YYYY') || ')';\r\n    id_reprobado := v_orden_id;\r\n    \r\n    RETURN NEXT; -- Empuja la fila armada al resultado\r\nEND;\r\n$$"}	ALTER_function_check_preventiva_reinspection_eligibility_cambiadedefinerainvoker
